const __FIXTURES__ = [{"id":"gitea-draft-release-access-control","skill":"engineering/aegis","repo":"go-gitea/gitea","commit":"1eced4a7c099459af42412bb32a83241650c0f8f","pr":"https://github.com/go-gitea/gitea/pull/36659","language":"go","domain_tags":["broken-access-control","idor","missing-authorization","draft-visibility","owasp-a01"],"target":"before.txt","answer":"after.txt","answer_key":"fix.diff","file":"the Gitea releases REST API, EXACTLY the 2 files the commit modified, in full and uncurated: routers/api/v1/repo/release.go (421L — GetRelease/GetLatestRelease/ListReleases/CreateRelease/EditRelease/DeleteRelease) + routers/api/v1/repo/release_attachment.go (407L — the release-attachment GET/list/CRUD handlers). 832 lines total before the fix.","fix_summary":"BROKEN ACCESS CONTROL / IDOR (OWASP A01) — a missing OBJECT-LEVEL authorization check, the aegis lesson 'enforce server-side authorization on every read; a partial check is not the check'. GetRelease fetches a release with repo_model.GetReleaseForRepoByID(ctx.Repo.Repository.ID, id) and returns it after only a repo-match and an IsTag check — but it does NOT gate DRAFT (unpublished) releases, so any caller with mere repo READ access (and, on a public repo, an anonymous user) can fetch an unpublished draft release by id, plus its attachments (ListReleaseAttachments / GetReleaseAttachment via checkReleaseMatchRepo) and see drafts in ListReleases. Draft releases are unpublished content that should require WRITE access. The maintainer's fix.diff adds canAccessDraftRelease(ctx) (signed in AND CanWrite(unit.TypeReleases) AND the API token carries repo-write scope) and gates GetRelease, the attachment handlers, and the IncludeDrafts flag of ListReleases behind it. THE ATTRACTOR (why this discriminates): there IS already an access control here — the release is fetched scoped to the current repo (GetReleaseForRepoByID) and there is an IsTag 404 — so the read path LOOKS authorized; the missing nuance (a draft is a sub-resource that needs a STRONGER permission than the repo's read gate) is Gitea-specific domain knowledge a reviewer glosses over. The repo-scoped fetch is the present-but-incomplete control that misdirects, structurally like 'parameterized != authorized'. SCOPE: before.txt is the WHOLE 2 files the commit touched, full and UN-curated — the missing draft gate is determinable from context but buried in ~832 lines of idiomatic API code, NOT excerpted to point at it. DISCRIMINATION EVIDENCE (pre-validated before adoption): a blind, security-primed no-skill review of before.txt MISSED this entirely — its top finding was a speculative nil-pointer/operator-precedence DoS hazard it itself judged 'safe in that path', plus a CreateRelease logic nitpick and an attachment check it concluded was 'actually sound'; it never once reasoned about draft-release visibility. So the base arm chases a hedged distractor while leaving the real, confirmed access-control hole un-flagged. Unlike the prior kubestellar fixture (a vuln buffet where the base arm found 5+ other confirmed vulns and got capped at 8), this file is otherwise clean — the draft access-control issue is the DOMINANT confirmed security problem, so missing it should actually cost score. PROVENANCE: a real, reviewed, merged Gitea PR (#36659) authored by Lunny Xiao (Gitea's founder); Copilot is a co-author (drafting assistance only) — the project's own accepted change. The grader scores the review against fix.diff and does not see this note. Repo: go-gitea/gitea, MIT, ~56k stars.","before":"// ===== routers/api/v1/repo/release.go =====\n// Copyright 2016 The Gitea Authors. All rights reserved.\n// SPDX-License-Identifier: MIT\n\npackage repo\n\n\u0069mport (\n\t\"errors\"\n\t\"fmt\"\n\t\"net/http\"\n\n\t\"code.gitea.io/gitea/models/db\"\n\t\"code.gitea.io/gitea/models/perm\"\n\trepo_model \"code.gitea.io/gitea/models/repo\"\n\t\"code.gitea.io/gitea/models/unit\"\n\t\"code.gitea.io/gitea/modules/git\"\n\tapi \"code.gitea.io/gitea/modules/structs\"\n\t\"code.gitea.io/gitea/modules/web\"\n\t\"code.gitea.io/gitea/routers/api/v1/utils\"\n\t\"code.gitea.io/gitea/services/context\"\n\t\"code.gitea.io/gitea/services/convert\"\n\trelease_service \"code.gitea.io/gitea/services/release\"\n)\n\n// GetRelease get a single release of a repository\nfunc GetRelease(ctx *context.APIContext) {\n\t// swagger:operation GET /repos/{owner}/{repo}/releases/{id} repository repoGetRelease\n\t// ---\n\t// summary: Get a release\n\t// produces:\n\t// - application/json\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: id\n\t//   in: path\n\t//   description: id of the release to get\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// responses:\n\t//   \"200\":\n\t//     \"$ref\": \"#/responses/Release\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\n\tid := ctx.PathParamInt64(\"id\")\n\trelease, err := repo_model.GetReleaseForRepoByID(ctx, ctx.Repo.Repository.ID, id)\n\tif err != nil && !repo_model.IsErrReleaseNotExist(err) {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tif err != nil && repo_model.IsErrReleaseNotExist(err) || release.IsTag {\n\t\tctx.APIErrorNotFound()\n\t\treturn\n\t}\n\n\tif err := release.LoadAttributes(ctx); err != nil {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tctx.JSON(http.StatusOK, convert.ToAPIRelease(ctx, ctx.Repo.Repository, release))\n}\n\n// GetLatestRelease gets the most recent non-prerelease, non-draft release of a repository, sorted by created_at\nfunc GetLatestRelease(ctx *context.APIContext) {\n\t// swagger:operation GET /repos/{owner}/{repo}/releases/latest repository repoGetLatestRelease\n\t// ---\n\t// summary: Gets the most recent non-prerelease, non-draft release of a repository, sorted by created_at\n\t// produces:\n\t// - application/json\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// responses:\n\t//   \"200\":\n\t//     \"$ref\": \"#/responses/Release\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\trelease, err := repo_model.GetLatestReleaseByRepoID(ctx, ctx.Repo.Repository.ID)\n\tif err != nil && !repo_model.IsErrReleaseNotExist(err) {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tif err != nil && repo_model.IsErrReleaseNotExist(err) ||\n\t\trelease.IsTag || release.RepoID != ctx.Repo.Repository.ID {\n\t\tctx.APIErrorNotFound()\n\t\treturn\n\t}\n\n\tif err := release.LoadAttributes(ctx); err != nil {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tctx.JSON(http.StatusOK, convert.ToAPIRelease(ctx, ctx.Repo.Repository, release))\n}\n\n// ListReleases list a repository's releases\nfunc ListReleases(ctx *context.APIContext) {\n\t// swagger:operation GET /repos/{owner}/{repo}/releases repository repoListReleases\n\t// ---\n\t// summary: List a repo's releases\n\t// produces:\n\t// - application/json\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: draft\n\t//   in: query\n\t//   description: filter (exclude / include) drafts, if you dont have repo write access none will show\n\t//   type: boolean\n\t// - name: pre-release\n\t//   in: query\n\t//   description: filter (exclude / include) pre-releases\n\t//   type: boolean\n\t// - name: page\n\t//   in: query\n\t//   description: page number of results to return (1-based)\n\t//   type: integer\n\t// - name: limit\n\t//   in: query\n\t//   description: page size of results\n\t//   type: integer\n\t// responses:\n\t//   \"200\":\n\t//     \"$ref\": \"#/responses/ReleaseList\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\tlistOptions := utils.GetListOptions(ctx)\n\n\topts := repo_model.FindReleasesOptions{\n\t\tListOptions:   listOptions,\n\t\tIncludeDrafts: ctx.Repo.AccessMode >= perm.AccessModeWrite || ctx.Repo.UnitAccessMode(unit.TypeReleases) >= perm.AccessModeWrite,\n\t\tIncludeTags:   false,\n\t\tIsDraft:       ctx.FormOptionalBool(\"draft\"),\n\t\tIsPreRelease:  ctx.FormOptionalBool(\"pre-release\"),\n\t\tRepoID:        ctx.Repo.Repository.ID,\n\t}\n\n\treleases, err := db.Find[repo_model.Release](ctx, opts)\n\tif err != nil {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\trels := make([]*api.Release, len(releases))\n\tfor i, release := range releases {\n\t\tif err := release.LoadAttributes(ctx); err != nil {\n\t\t\tctx.APIErrorInternal(err)\n\t\t\treturn\n\t\t}\n\t\trels[i] = convert.ToAPIRelease(ctx, ctx.Repo.Repository, release)\n\t}\n\n\tfilteredCount, err := db.Count[repo_model.Release](ctx, opts)\n\tif err != nil {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\n\tctx.SetLinkHeader(int(filteredCount), listOptions.PageSize)\n\tctx.SetTotalCountHeader(filteredCount)\n\tctx.JSON(http.StatusOK, rels)\n}\n\n// CreateRelease create a release\nfunc CreateRelease(ctx *context.APIContext) {\n\t// swagger:operation POST /repos/{owner}/{repo}/releases repository repoCreateRelease\n\t// ---\n\t// summary: Create a release\n\t// consumes:\n\t// - application/json\n\t// produces:\n\t// - application/json\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: body\n\t//   in: body\n\t//   schema:\n\t//     \"$ref\": \"#/definitions/CreateReleaseOption\"\n\t// responses:\n\t//   \"201\":\n\t//     \"$ref\": \"#/responses/Release\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\t//   \"409\":\n\t//     \"$ref\": \"#/responses/error\"\n\t//   \"422\":\n\t//     \"$ref\": \"#/responses/validationError\"\n\n\tform := web.GetForm(ctx).(*api.CreateReleaseOption)\n\tif ctx.Repo.Repository.IsEmpty {\n\t\tctx.APIError(http.StatusUnprocessableEntity, errors.New(\"repo is empty\"))\n\t\treturn\n\t}\n\trel, err := repo_model.GetRelease(ctx, ctx.Repo.Repository.ID, form.TagName)\n\tif err != nil {\n\t\tif !repo_model.IsErrReleaseNotExist(err) {\n\t\t\tctx.APIErrorInternal(err)\n\t\t\treturn\n\t\t}\n\t\t// If target is not provided use default branch\n\t\tif len(form.Target) == 0 {\n\t\t\tform.Target = ctx.Repo.Repository.DefaultBranch\n\t\t}\n\t\trel = &repo_model.Release{\n\t\t\tRepoID:       ctx.Repo.Repository.ID,\n\t\t\tPublisherID:  ctx.Doer.ID,\n\t\t\tPublisher:    ctx.Doer,\n\t\t\tTagName:      form.TagName,\n\t\t\tTarget:       form.Target,\n\t\t\tTitle:        form.Title,\n\t\t\tNote:         form.Note,\n\t\t\tIsDraft:      form.IsDraft,\n\t\t\tIsPrerelease: form.IsPrerelease,\n\t\t\tIsTag:        false,\n\t\t\tRepo:         ctx.Repo.Repository,\n\t\t}\n\t\t// GitHub doesn't have \"tag_message\", GitLab has: https://docs.gitlab.com/api/releases/#create-a-release\n\t\t// It doesn't need to be the same as the \"release note\"\n\t\tif err := release_service.CreateRelease(ctx.Repo.GitRepo, rel, nil, form.TagMessage); err != nil {\n\t\t\tif repo_model.IsErrReleaseAlreadyExist(err) {\n\t\t\t\tctx.APIError(http.StatusConflict, err)\n\t\t\t} else if release_service.IsErrProtectedTagName(err) {\n\t\t\t\tctx.APIError(http.StatusUnprocessableEntity, err)\n\t\t\t} else if git.IsErrNotExist(err) {\n\t\t\t\tctx.APIError(http.StatusNotFound, fmt.Errorf(\"target \\\"%v\\\" not found: %w\", rel.Target, err))\n\t\t\t} else {\n\t\t\t\tctx.APIErrorInternal(err)\n\t\t\t}\n\t\t\treturn\n\t\t}\n\t} else {\n\t\tif !rel.IsTag {\n\t\t\tctx.APIError(http.StatusConflict, \"Release is has no Tag\")\n\t\t\treturn\n\t\t}\n\n\t\trel.Title = form.Title\n\t\trel.Note = form.Note\n\t\trel.IsDraft = form.IsDraft\n\t\trel.IsPrerelease = form.IsPrerelease\n\t\trel.PublisherID = ctx.Doer.ID\n\t\trel.IsTag = false\n\t\trel.Repo = ctx.Repo.Repository\n\t\trel.Publisher = ctx.Doer\n\t\trel.Target = form.Target\n\n\t\tif err = release_service.UpdateRelease(ctx, ctx.Doer, ctx.Repo.GitRepo, rel, nil, nil, nil); err != nil {\n\t\t\tctx.APIErrorInternal(err)\n\t\t\treturn\n\t\t}\n\t}\n\tctx.JSON(http.StatusCreated, convert.ToAPIRelease(ctx, ctx.Repo.Repository, rel))\n}\n\n// EditRelease edit a release\nfunc EditRelease(ctx *context.APIContext) {\n\t// swagger:operation PATCH /repos/{owner}/{repo}/releases/{id} repository repoEditRelease\n\t// ---\n\t// summary: Update a release\n\t// consumes:\n\t// - application/json\n\t// produces:\n\t// - application/json\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: id\n\t//   in: path\n\t//   description: id of the release to edit\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// - name: body\n\t//   in: body\n\t//   schema:\n\t//     \"$ref\": \"#/definitions/EditReleaseOption\"\n\t// responses:\n\t//   \"200\":\n\t//     \"$ref\": \"#/responses/Release\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\n\tform := web.GetForm(ctx).(*api.EditReleaseOption)\n\tid := ctx.PathParamInt64(\"id\")\n\trel, err := repo_model.GetReleaseForRepoByID(ctx, ctx.Repo.Repository.ID, id)\n\tif err != nil && !repo_model.IsErrReleaseNotExist(err) {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tif err != nil && repo_model.IsErrReleaseNotExist(err) || rel.IsTag {\n\t\tctx.APIErrorNotFound()\n\t\treturn\n\t}\n\n\tif len(form.TagName) > 0 {\n\t\trel.TagName = form.TagName\n\t}\n\tif len(form.Target) > 0 {\n\t\trel.Target = form.Target\n\t}\n\tif len(form.Title) > 0 {\n\t\trel.Title = form.Title\n\t}\n\tif len(form.Note) > 0 {\n\t\trel.Note = form.Note\n\t}\n\tif form.IsDraft != nil {\n\t\trel.IsDraft = *form.IsDraft\n\t}\n\tif form.IsPrerelease != nil {\n\t\trel.IsPrerelease = *form.IsPrerelease\n\t}\n\tif err := release_service.UpdateRelease(ctx, ctx.Doer, ctx.Repo.GitRepo, rel, nil, nil, nil); err != nil {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\n\t// reload data from database\n\trel, err = repo_model.GetReleaseByID(ctx, id)\n\tif err != nil {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tif err := rel.LoadAttributes(ctx); err != nil {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tctx.JSON(http.StatusOK, convert.ToAPIRelease(ctx, ctx.Repo.Repository, rel))\n}\n\n// DeleteRelease delete a release from a repository\nfunc DeleteRelease(ctx *context.APIContext) {\n\t// swagger:operation DELETE /repos/{owner}/{repo}/releases/{id} repository repoDeleteRelease\n\t// ---\n\t// summary: Delete a release\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: id\n\t//   in: path\n\t//   description: id of the release to delete\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// responses:\n\t//   \"204\":\n\t//     \"$ref\": \"#/responses/empty\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\t//   \"422\":\n\t//     \"$ref\": \"#/responses/validationError\"\n\n\tid := ctx.PathParamInt64(\"id\")\n\trel, err := repo_model.GetReleaseForRepoByID(ctx, ctx.Repo.Repository.ID, id)\n\tif err != nil && !repo_model.IsErrReleaseNotExist(err) {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tif err != nil && repo_model.IsErrReleaseNotExist(err) || rel.IsTag {\n\t\tctx.APIErrorNotFound()\n\t\treturn\n\t}\n\tif err := release_service.DeleteReleaseByID(ctx, ctx.Repo.Repository, rel, ctx.Doer, false); err != nil {\n\t\tif release_service.IsErrProtectedTagName(err) {\n\t\t\tctx.APIError(http.StatusUnprocessableEntity, \"user not allowed to delete protected tag\")\n\t\t\treturn\n\t\t}\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tctx.Status(http.StatusNoContent)\n}\n\n// ===== routers/api/v1/repo/release_attachment.go =====\n// Copyright 2018 The Gitea Authors. All rights reserved.\n// SPDX-License-Identifier: MIT\n\npackage repo\n\n\u0069mport (\n\t\"errors\"\n\t\"net/http\"\n\t\"strings\"\n\n\trepo_model \"code.gitea.io/gitea/models/repo\"\n\t\"code.gitea.io/gitea/modules/log\"\n\t\"code.gitea.io/gitea/modules/setting\"\n\tapi \"code.gitea.io/gitea/modules/structs\"\n\t\"code.gitea.io/gitea/modules/util\"\n\t\"code.gitea.io/gitea/modules/web\"\n\tattachment_service \"code.gitea.io/gitea/services/attachment\"\n\t\"code.gitea.io/gitea/services/context\"\n\t\"code.gitea.io/gitea/services/context/upload\"\n\t\"code.gitea.io/gitea/services/convert\"\n)\n\nfunc checkReleaseMatchRepo(ctx *context.APIContext, releaseID int64) bool {\n\trelease, err := repo_model.GetReleaseByID(ctx, releaseID)\n\tif err != nil {\n\t\tif repo_model.IsErrReleaseNotExist(err) {\n\t\t\tctx.APIErrorNotFound()\n\t\t\treturn false\n\t\t}\n\t\tctx.APIErrorInternal(err)\n\t\treturn false\n\t}\n\tif release.RepoID != ctx.Repo.Repository.ID {\n\t\tctx.APIErrorNotFound()\n\t\treturn false\n\t}\n\treturn true\n}\n\n// GetReleaseAttachment gets a single attachment of the release\nfunc GetReleaseAttachment(ctx *context.APIContext) {\n\t// swagger:operation GET /repos/{owner}/{repo}/releases/{id}/assets/{attachment_id} repository repoGetReleaseAttachment\n\t// ---\n\t// summary: Get a release attachment\n\t// produces:\n\t// - application/json\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: id\n\t//   in: path\n\t//   description: id of the release\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// - name: attachment_id\n\t//   in: path\n\t//   description: id of the attachment to get\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// responses:\n\t//   \"200\":\n\t//     \"$ref\": \"#/responses/Attachment\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\n\treleaseID := ctx.PathParamInt64(\"id\")\n\tif !checkReleaseMatchRepo(ctx, releaseID) {\n\t\treturn\n\t}\n\n\tattachID := ctx.PathParamInt64(\"attachment_id\")\n\tattach, err := repo_model.GetAttachmentByID(ctx, attachID)\n\tif err != nil {\n\t\tif repo_model.IsErrAttachmentNotExist(err) {\n\t\t\tctx.APIErrorNotFound()\n\t\t\treturn\n\t\t}\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tif attach.ReleaseID != releaseID {\n\t\tlog.Info(\"User requested attachment is not in release, release_id %v, attachment_id: %v\", releaseID, attachID)\n\t\tctx.APIErrorNotFound()\n\t\treturn\n\t}\n\t// FIXME Should prove the existence of the given repo, but results in unnecessary database requests\n\tctx.JSON(http.StatusOK, convert.ToAPIAttachment(ctx.Repo.Repository, attach))\n}\n\n// ListReleaseAttachments lists all attachments of the release\nfunc ListReleaseAttachments(ctx *context.APIContext) {\n\t// swagger:operation GET /repos/{owner}/{repo}/releases/{id}/assets repository repoListReleaseAttachments\n\t// ---\n\t// summary: List release's attachments\n\t// produces:\n\t// - application/json\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: id\n\t//   in: path\n\t//   description: id of the release\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// responses:\n\t//   \"200\":\n\t//     \"$ref\": \"#/responses/AttachmentList\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\n\treleaseID := ctx.PathParamInt64(\"id\")\n\trelease, err := repo_model.GetReleaseByID(ctx, releaseID)\n\tif err != nil {\n\t\tif repo_model.IsErrReleaseNotExist(err) {\n\t\t\tctx.APIErrorNotFound()\n\t\t\treturn\n\t\t}\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tif release.RepoID != ctx.Repo.Repository.ID {\n\t\tctx.APIErrorNotFound()\n\t\treturn\n\t}\n\tif err := release.LoadAttributes(ctx); err != nil {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tctx.JSON(http.StatusOK, convert.ToAPIRelease(ctx, ctx.Repo.Repository, release).Attachments)\n}\n\n// CreateReleaseAttachment creates an attachment and saves the given file\nfunc CreateReleaseAttachment(ctx *context.APIContext) {\n\t// swagger:operation POST /repos/{owner}/{repo}/releases/{id}/assets repository repoCreateReleaseAttachment\n\t// ---\n\t// summary: Create a release attachment\n\t// produces:\n\t// - application/json\n\t// consumes:\n\t// - multipart/form-data\n\t// - application/octet-stream\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: id\n\t//   in: path\n\t//   description: id of the release\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// - name: name\n\t//   in: query\n\t//   description: name of the attachment\n\t//   type: string\n\t//   required: false\n\t// - name: attachment\n\t//   in: formData\n\t//   description: attachment to upload\n\t//   type: file\n\t//   required: false\n\t// responses:\n\t//   \"201\":\n\t//     \"$ref\": \"#/responses/Attachment\"\n\t//   \"400\":\n\t//     \"$ref\": \"#/responses/error\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\t//   \"413\":\n\t//     \"$ref\": \"#/responses/error\"\n\n\t// Check if attachments are enabled\n\tif !setting.Attachment.Enabled {\n\t\tctx.APIErrorNotFound(\"Attachment is not enabled\")\n\t\treturn\n\t}\n\n\t// Check if release exists an load release\n\treleaseID := ctx.PathParamInt64(\"id\")\n\tif !checkReleaseMatchRepo(ctx, releaseID) {\n\t\treturn\n\t}\n\n\t// Get uploaded file from request\n\tvar filename string\n\tvar uploaderFile *attachment_service.UploaderFile\n\tif strings.HasPrefix(strings.ToLower(ctx.Req.Header.Get(\"Content-Type\")), \"multipart/form-data\") {\n\t\tfile, header, err := ctx.Req.FormFile(\"attachment\")\n\t\tif err != nil {\n\t\t\tctx.APIErrorInternal(err)\n\t\t\treturn\n\t\t}\n\t\tdefer file.Close()\n\n\t\tfilename = header.Filename\n\t\tif name := ctx.FormString(\"name\"); name != \"\" {\n\t\t\tfilename = name\n\t\t}\n\t\tuploaderFile = attachment_service.NewLimitedUploaderKnownSize(file, header.Size)\n\t} else {\n\t\tfilename = ctx.FormString(\"name\")\n\t\tuploaderFile = attachment_service.NewLimitedUploaderMaxBytesReader(ctx.Req.Body, ctx.Resp)\n\t}\n\n\tif filename == \"\" {\n\t\tctx.APIError(http.StatusBadRequest, \"Could not determine name of attachment.\")\n\t\treturn\n\t}\n\n\t// Create a new attachment and save the file\n\tattach, err := attachment_service.UploadAttachmentReleaseSizeLimit(ctx, uploaderFile, setting.Repository.Release.AllowedTypes, &repo_model.Attachment{\n\t\tName:       filename,\n\t\tUploaderID: ctx.Doer.ID,\n\t\tRepoID:     ctx.Repo.Repository.ID,\n\t\tReleaseID:  releaseID,\n\t})\n\tif err != nil {\n\t\tif upload.IsErrFileTypeForbidden(err) {\n\t\t\tctx.APIError(http.StatusBadRequest, err)\n\t\t\treturn\n\t\t}\n\n\t\tif errors.Is(err, util.ErrContentTooLarge) {\n\t\t\tctx.APIError(http.StatusRequestEntityTooLarge, err)\n\t\t\treturn\n\t\t}\n\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\n\tctx.JSON(http.StatusCreated, convert.ToAPIAttachment(ctx.Repo.Repository, attach))\n}\n\n// EditReleaseAttachment updates the given attachment\nfunc EditReleaseAttachment(ctx *context.APIContext) {\n\t// swagger:operation PATCH /repos/{owner}/{repo}/releases/{id}/assets/{attachment_id} repository repoEditReleaseAttachment\n\t// ---\n\t// summary: Edit a release attachment\n\t// produces:\n\t// - application/json\n\t// consumes:\n\t// - application/json\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: id\n\t//   in: path\n\t//   description: id of the release\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// - name: attachment_id\n\t//   in: path\n\t//   description: id of the attachment to edit\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// - name: body\n\t//   in: body\n\t//   schema:\n\t//     \"$ref\": \"#/definitions/EditAttachmentOptions\"\n\t// responses:\n\t//   \"201\":\n\t//     \"$ref\": \"#/responses/Attachment\"\n\t//   \"422\":\n\t//     \"$ref\": \"#/responses/validationError\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\n\tform := web.GetForm(ctx).(*api.EditAttachmentOptions)\n\n\t// Check if release exists an load release\n\treleaseID := ctx.PathParamInt64(\"id\")\n\tif !checkReleaseMatchRepo(ctx, releaseID) {\n\t\treturn\n\t}\n\n\tattachID := ctx.PathParamInt64(\"attachment_id\")\n\tattach, err := repo_model.GetAttachmentByID(ctx, attachID)\n\tif err != nil {\n\t\tif repo_model.IsErrAttachmentNotExist(err) {\n\t\t\tctx.APIErrorNotFound()\n\t\t\treturn\n\t\t}\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tif attach.ReleaseID != releaseID {\n\t\tlog.Info(\"User requested attachment is not in release, release_id %v, attachment_id: %v\", releaseID, attachID)\n\t\tctx.APIErrorNotFound()\n\t\treturn\n\t}\n\t// FIXME Should prove the existence of the given repo, but results in unnecessary database requests\n\tif form.Name != \"\" {\n\t\tattach.Name = form.Name\n\t}\n\n\tif err := attachment_service.UpdateAttachment(ctx, setting.Repository.Release.AllowedTypes, attach); err != nil {\n\t\tif upload.IsErrFileTypeForbidden(err) {\n\t\t\tctx.APIError(http.StatusUnprocessableEntity, err)\n\t\t\treturn\n\t\t}\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tctx.JSON(http.StatusCreated, convert.ToAPIAttachment(ctx.Repo.Repository, attach))\n}\n\n// DeleteReleaseAttachment delete a given attachment\nfunc DeleteReleaseAttachment(ctx *context.APIContext) {\n\t// swagger:operation DELETE /repos/{owner}/{repo}/releases/{id}/assets/{attachment_id} repository repoDeleteReleaseAttachment\n\t// ---\n\t// summary: Delete a release attachment\n\t// produces:\n\t// - application/json\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: id\n\t//   in: path\n\t//   description: id of the release\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// - name: attachment_id\n\t//   in: path\n\t//   description: id of the attachment to delete\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// responses:\n\t//   \"204\":\n\t//     \"$ref\": \"#/responses/empty\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\n\t// Check if release exists an load release\n\treleaseID := ctx.PathParamInt64(\"id\")\n\tif !checkReleaseMatchRepo(ctx, releaseID) {\n\t\treturn\n\t}\n\n\tattachID := ctx.PathParamInt64(\"attachment_id\")\n\tattach, err := repo_model.GetAttachmentByID(ctx, attachID)\n\tif err != nil {\n\t\tif repo_model.IsErrAttachmentNotExist(err) {\n\t\t\tctx.APIErrorNotFound()\n\t\t\treturn\n\t\t}\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tif attach.ReleaseID != releaseID {\n\t\tlog.Info(\"User requested attachment is not in release, release_id %v, attachment_id: %v\", releaseID, attachID)\n\t\tctx.APIErrorNotFound()\n\t\treturn\n\t}\n\n\tif err := repo_model.DeleteAttachment(ctx, attach, true); err != nil {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tctx.Status(http.StatusNoContent)\n}\n\n","after":"// ===== routers/api/v1/repo/release.go =====\n// Copyright 2016 The Gitea Authors. All rights reserved.\n// SPDX-License-Identifier: MIT\n\npackage repo\n\n\u0069mport (\n\t\"errors\"\n\t\"fmt\"\n\t\"net/http\"\n\n\tauth_model \"code.gitea.io/gitea/models/auth\"\n\t\"code.gitea.io/gitea/models/db\"\n\t\"code.gitea.io/gitea/models/perm\"\n\trepo_model \"code.gitea.io/gitea/models/repo\"\n\t\"code.gitea.io/gitea/models/unit\"\n\t\"code.gitea.io/gitea/modules/git\"\n\tapi \"code.gitea.io/gitea/modules/structs\"\n\t\"code.gitea.io/gitea/modules/web\"\n\t\"code.gitea.io/gitea/routers/api/v1/utils\"\n\t\"code.gitea.io/gitea/services/context\"\n\t\"code.gitea.io/gitea/services/convert\"\n\trelease_service \"code.gitea.io/gitea/services/release\"\n)\n\nfunc hasRepoWriteScope(ctx *context.APIContext) bool {\n\tscope, ok := ctx.Data[\"ApiTokenScope\"].(auth_model.AccessTokenScope)\n\tif ctx.Data[\"IsApiToken\"] != true || !ok {\n\t\treturn true\n\t}\n\n\trequiredScopes := auth_model.GetRequiredScopes(auth_model.Write, auth_model.AccessTokenScopeCategoryRepository)\n\tallow, err := scope.HasScope(requiredScopes...)\n\tif err != nil {\n\t\tctx.APIError(http.StatusForbidden, \"checking scope failed: \"+err.Error())\n\t\treturn false\n\t}\n\treturn allow\n}\n\nfunc canAccessDraftRelease(ctx *context.APIContext) bool {\n\tif !ctx.IsSigned || !ctx.Repo.CanWrite(unit.TypeReleases) {\n\t\treturn false\n\t}\n\treturn hasRepoWriteScope(ctx)\n}\n\n// GetRelease get a single release of a repository\nfunc GetRelease(ctx *context.APIContext) {\n\t// swagger:operation GET /repos/{owner}/{repo}/releases/{id} repository repoGetRelease\n\t// ---\n\t// summary: Get a release\n\t// produces:\n\t// - application/json\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: id\n\t//   in: path\n\t//   description: id of the release to get\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// responses:\n\t//   \"200\":\n\t//     \"$ref\": \"#/responses/Release\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\n\tid := ctx.PathParamInt64(\"id\")\n\trelease, err := repo_model.GetReleaseForRepoByID(ctx, ctx.Repo.Repository.ID, id)\n\tif err != nil && !repo_model.IsErrReleaseNotExist(err) {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tif err != nil && repo_model.IsErrReleaseNotExist(err) || release.IsTag {\n\t\tctx.APIErrorNotFound()\n\t\treturn\n\t}\n\n\tif release.IsDraft { // only the users with write access can see draft releases\n\t\tif !canAccessDraftRelease(ctx) {\n\t\t\tif !ctx.Written() {\n\t\t\t\tctx.APIErrorNotFound()\n\t\t\t}\n\t\t\treturn\n\t\t}\n\t}\n\n\tif err := release.LoadAttributes(ctx); err != nil {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tctx.JSON(http.StatusOK, convert.ToAPIRelease(ctx, ctx.Repo.Repository, release))\n}\n\n// GetLatestRelease gets the most recent non-prerelease, non-draft release of a repository, sorted by created_at\nfunc GetLatestRelease(ctx *context.APIContext) {\n\t// swagger:operation GET /repos/{owner}/{repo}/releases/latest repository repoGetLatestRelease\n\t// ---\n\t// summary: Gets the most recent non-prerelease, non-draft release of a repository, sorted by created_at\n\t// produces:\n\t// - application/json\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// responses:\n\t//   \"200\":\n\t//     \"$ref\": \"#/responses/Release\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\trelease, err := repo_model.GetLatestReleaseByRepoID(ctx, ctx.Repo.Repository.ID)\n\tif err != nil && !repo_model.IsErrReleaseNotExist(err) {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tif err != nil && repo_model.IsErrReleaseNotExist(err) ||\n\t\trelease.IsTag || release.RepoID != ctx.Repo.Repository.ID {\n\t\tctx.APIErrorNotFound()\n\t\treturn\n\t}\n\n\tif err := release.LoadAttributes(ctx); err != nil {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tctx.JSON(http.StatusOK, convert.ToAPIRelease(ctx, ctx.Repo.Repository, release))\n}\n\n// ListReleases list a repository's releases\nfunc ListReleases(ctx *context.APIContext) {\n\t// swagger:operation GET /repos/{owner}/{repo}/releases repository repoListReleases\n\t// ---\n\t// summary: List a repo's releases\n\t// produces:\n\t// - application/json\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: draft\n\t//   in: query\n\t//   description: filter (exclude / include) drafts, if you dont have repo write access none will show\n\t//   type: boolean\n\t// - name: pre-release\n\t//   in: query\n\t//   description: filter (exclude / include) pre-releases\n\t//   type: boolean\n\t// - name: page\n\t//   in: query\n\t//   description: page number of results to return (1-based)\n\t//   type: integer\n\t// - name: limit\n\t//   in: query\n\t//   description: page size of results\n\t//   type: integer\n\t// responses:\n\t//   \"200\":\n\t//     \"$ref\": \"#/responses/ReleaseList\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\tlistOptions := utils.GetListOptions(ctx)\n\n\tincludeDrafts := (ctx.Repo.AccessMode >= perm.AccessModeWrite || ctx.Repo.UnitAccessMode(unit.TypeReleases) >= perm.AccessModeWrite) && hasRepoWriteScope(ctx)\n\tif ctx.Written() {\n\t\treturn\n\t}\n\topts := repo_model.FindReleasesOptions{\n\t\tListOptions:   listOptions,\n\t\tIncludeDrafts: includeDrafts,\n\t\tIncludeTags:   false,\n\t\tIsDraft:       ctx.FormOptionalBool(\"draft\"),\n\t\tIsPreRelease:  ctx.FormOptionalBool(\"pre-release\"),\n\t\tRepoID:        ctx.Repo.Repository.ID,\n\t}\n\n\treleases, err := db.Find[repo_model.Release](ctx, opts)\n\tif err != nil {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\trels := make([]*api.Release, len(releases))\n\tfor i, release := range releases {\n\t\tif err := release.LoadAttributes(ctx); err != nil {\n\t\t\tctx.APIErrorInternal(err)\n\t\t\treturn\n\t\t}\n\t\trels[i] = convert.ToAPIRelease(ctx, ctx.Repo.Repository, release)\n\t}\n\n\tfilteredCount, err := db.Count[repo_model.Release](ctx, opts)\n\tif err != nil {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\n\tctx.SetLinkHeader(int(filteredCount), listOptions.PageSize)\n\tctx.SetTotalCountHeader(filteredCount)\n\tctx.JSON(http.StatusOK, rels)\n}\n\n// CreateRelease create a release\nfunc CreateRelease(ctx *context.APIContext) {\n\t// swagger:operation POST /repos/{owner}/{repo}/releases repository repoCreateRelease\n\t// ---\n\t// summary: Create a release\n\t// consumes:\n\t// - application/json\n\t// produces:\n\t// - application/json\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: body\n\t//   in: body\n\t//   schema:\n\t//     \"$ref\": \"#/definitions/CreateReleaseOption\"\n\t// responses:\n\t//   \"201\":\n\t//     \"$ref\": \"#/responses/Release\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\t//   \"409\":\n\t//     \"$ref\": \"#/responses/error\"\n\t//   \"422\":\n\t//     \"$ref\": \"#/responses/validationError\"\n\n\tform := web.GetForm(ctx).(*api.CreateReleaseOption)\n\tif ctx.Repo.Repository.IsEmpty {\n\t\tctx.APIError(http.StatusUnprocessableEntity, errors.New(\"repo is empty\"))\n\t\treturn\n\t}\n\trel, err := repo_model.GetRelease(ctx, ctx.Repo.Repository.ID, form.TagName)\n\tif err != nil {\n\t\tif !repo_model.IsErrReleaseNotExist(err) {\n\t\t\tctx.APIErrorInternal(err)\n\t\t\treturn\n\t\t}\n\t\t// If target is not provided use default branch\n\t\tif len(form.Target) == 0 {\n\t\t\tform.Target = ctx.Repo.Repository.DefaultBranch\n\t\t}\n\t\trel = &repo_model.Release{\n\t\t\tRepoID:       ctx.Repo.Repository.ID,\n\t\t\tPublisherID:  ctx.Doer.ID,\n\t\t\tPublisher:    ctx.Doer,\n\t\t\tTagName:      form.TagName,\n\t\t\tTarget:       form.Target,\n\t\t\tTitle:        form.Title,\n\t\t\tNote:         form.Note,\n\t\t\tIsDraft:      form.IsDraft,\n\t\t\tIsPrerelease: form.IsPrerelease,\n\t\t\tIsTag:        false,\n\t\t\tRepo:         ctx.Repo.Repository,\n\t\t}\n\t\t// GitHub doesn't have \"tag_message\", GitLab has: https://docs.gitlab.com/api/releases/#create-a-release\n\t\t// It doesn't need to be the same as the \"release note\"\n\t\tif err := release_service.CreateRelease(ctx.Repo.GitRepo, rel, nil, form.TagMessage); err != nil {\n\t\t\tif repo_model.IsErrReleaseAlreadyExist(err) {\n\t\t\t\tctx.APIError(http.StatusConflict, err)\n\t\t\t} else if release_service.IsErrProtectedTagName(err) {\n\t\t\t\tctx.APIError(http.StatusUnprocessableEntity, err)\n\t\t\t} else if git.IsErrNotExist(err) {\n\t\t\t\tctx.APIError(http.StatusNotFound, fmt.Errorf(\"target \\\"%v\\\" not found: %w\", rel.Target, err))\n\t\t\t} else {\n\t\t\t\tctx.APIErrorInternal(err)\n\t\t\t}\n\t\t\treturn\n\t\t}\n\t} else {\n\t\tif !rel.IsTag {\n\t\t\tctx.APIError(http.StatusConflict, \"Release is has no Tag\")\n\t\t\treturn\n\t\t}\n\n\t\trel.Title = form.Title\n\t\trel.Note = form.Note\n\t\trel.IsDraft = form.IsDraft\n\t\trel.IsPrerelease = form.IsPrerelease\n\t\trel.PublisherID = ctx.Doer.ID\n\t\trel.IsTag = false\n\t\trel.Repo = ctx.Repo.Repository\n\t\trel.Publisher = ctx.Doer\n\t\trel.Target = form.Target\n\n\t\tif err = release_service.UpdateRelease(ctx, ctx.Doer, ctx.Repo.GitRepo, rel, nil, nil, nil); err != nil {\n\t\t\tctx.APIErrorInternal(err)\n\t\t\treturn\n\t\t}\n\t}\n\tctx.JSON(http.StatusCreated, convert.ToAPIRelease(ctx, ctx.Repo.Repository, rel))\n}\n\n// EditRelease edit a release\nfunc EditRelease(ctx *context.APIContext) {\n\t// swagger:operation PATCH /repos/{owner}/{repo}/releases/{id} repository repoEditRelease\n\t// ---\n\t// summary: Update a release\n\t// consumes:\n\t// - application/json\n\t// produces:\n\t// - application/json\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: id\n\t//   in: path\n\t//   description: id of the release to edit\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// - name: body\n\t//   in: body\n\t//   schema:\n\t//     \"$ref\": \"#/definitions/EditReleaseOption\"\n\t// responses:\n\t//   \"200\":\n\t//     \"$ref\": \"#/responses/Release\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\n\tform := web.GetForm(ctx).(*api.EditReleaseOption)\n\tid := ctx.PathParamInt64(\"id\")\n\trel, err := repo_model.GetReleaseForRepoByID(ctx, ctx.Repo.Repository.ID, id)\n\tif err != nil && !repo_model.IsErrReleaseNotExist(err) {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tif err != nil && repo_model.IsErrReleaseNotExist(err) || rel.IsTag {\n\t\tctx.APIErrorNotFound()\n\t\treturn\n\t}\n\n\tif len(form.TagName) > 0 {\n\t\trel.TagName = form.TagName\n\t}\n\tif len(form.Target) > 0 {\n\t\trel.Target = form.Target\n\t}\n\tif len(form.Title) > 0 {\n\t\trel.Title = form.Title\n\t}\n\tif len(form.Note) > 0 {\n\t\trel.Note = form.Note\n\t}\n\tif form.IsDraft != nil {\n\t\trel.IsDraft = *form.IsDraft\n\t}\n\tif form.IsPrerelease != nil {\n\t\trel.IsPrerelease = *form.IsPrerelease\n\t}\n\tif err := release_service.UpdateRelease(ctx, ctx.Doer, ctx.Repo.GitRepo, rel, nil, nil, nil); err != nil {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\n\t// reload data from database\n\trel, err = repo_model.GetReleaseByID(ctx, id)\n\tif err != nil {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tif err := rel.LoadAttributes(ctx); err != nil {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tctx.JSON(http.StatusOK, convert.ToAPIRelease(ctx, ctx.Repo.Repository, rel))\n}\n\n// DeleteRelease delete a release from a repository\nfunc DeleteRelease(ctx *context.APIContext) {\n\t// swagger:operation DELETE /repos/{owner}/{repo}/releases/{id} repository repoDeleteRelease\n\t// ---\n\t// summary: Delete a release\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: id\n\t//   in: path\n\t//   description: id of the release to delete\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// responses:\n\t//   \"204\":\n\t//     \"$ref\": \"#/responses/empty\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\t//   \"422\":\n\t//     \"$ref\": \"#/responses/validationError\"\n\n\tid := ctx.PathParamInt64(\"id\")\n\trel, err := repo_model.GetReleaseForRepoByID(ctx, ctx.Repo.Repository.ID, id)\n\tif err != nil && !repo_model.IsErrReleaseNotExist(err) {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tif err != nil && repo_model.IsErrReleaseNotExist(err) || rel.IsTag {\n\t\tctx.APIErrorNotFound()\n\t\treturn\n\t}\n\tif err := release_service.DeleteReleaseByID(ctx, ctx.Repo.Repository, rel, ctx.Doer, false); err != nil {\n\t\tif release_service.IsErrProtectedTagName(err) {\n\t\t\tctx.APIError(http.StatusUnprocessableEntity, \"user not allowed to delete protected tag\")\n\t\t\treturn\n\t\t}\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tctx.Status(http.StatusNoContent)\n}\n\n// ===== routers/api/v1/repo/release_attachment.go =====\n// Copyright 2018 The Gitea Authors. All rights reserved.\n// SPDX-License-Identifier: MIT\n\npackage repo\n\n\u0069mport (\n\t\"errors\"\n\t\"net/http\"\n\t\"strings\"\n\n\trepo_model \"code.gitea.io/gitea/models/repo\"\n\t\"code.gitea.io/gitea/modules/log\"\n\t\"code.gitea.io/gitea/modules/setting\"\n\tapi \"code.gitea.io/gitea/modules/structs\"\n\t\"code.gitea.io/gitea/modules/util\"\n\t\"code.gitea.io/gitea/modules/web\"\n\tattachment_service \"code.gitea.io/gitea/services/attachment\"\n\t\"code.gitea.io/gitea/services/context\"\n\t\"code.gitea.io/gitea/services/context/upload\"\n\t\"code.gitea.io/gitea/services/convert\"\n)\n\nfunc checkReleaseMatchRepo(ctx *context.APIContext, releaseID int64) bool {\n\trelease, err := repo_model.GetReleaseByID(ctx, releaseID)\n\tif err != nil {\n\t\tif repo_model.IsErrReleaseNotExist(err) {\n\t\t\tctx.APIErrorNotFound()\n\t\t\treturn false\n\t\t}\n\t\tctx.APIErrorInternal(err)\n\t\treturn false\n\t}\n\tif release.RepoID != ctx.Repo.Repository.ID {\n\t\tctx.APIErrorNotFound()\n\t\treturn false\n\t}\n\tif release.IsDraft {\n\t\tif !canAccessDraftRelease(ctx) {\n\t\t\tif !ctx.Written() {\n\t\t\t\tctx.APIErrorNotFound()\n\t\t\t}\n\t\t\treturn false\n\t\t}\n\t}\n\treturn true\n}\n\n// GetReleaseAttachment gets a single attachment of the release\nfunc GetReleaseAttachment(ctx *context.APIContext) {\n\t// swagger:operation GET /repos/{owner}/{repo}/releases/{id}/assets/{attachment_id} repository repoGetReleaseAttachment\n\t// ---\n\t// summary: Get a release attachment\n\t// produces:\n\t// - application/json\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: id\n\t//   in: path\n\t//   description: id of the release\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// - name: attachment_id\n\t//   in: path\n\t//   description: id of the attachment to get\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// responses:\n\t//   \"200\":\n\t//     \"$ref\": \"#/responses/Attachment\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\n\treleaseID := ctx.PathParamInt64(\"id\")\n\tif !checkReleaseMatchRepo(ctx, releaseID) {\n\t\treturn\n\t}\n\n\tattachID := ctx.PathParamInt64(\"attachment_id\")\n\tattach, err := repo_model.GetAttachmentByID(ctx, attachID)\n\tif err != nil {\n\t\tif repo_model.IsErrAttachmentNotExist(err) {\n\t\t\tctx.APIErrorNotFound()\n\t\t\treturn\n\t\t}\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tif attach.ReleaseID != releaseID {\n\t\tlog.Info(\"User requested attachment is not in release, release_id %v, attachment_id: %v\", releaseID, attachID)\n\t\tctx.APIErrorNotFound()\n\t\treturn\n\t}\n\t// FIXME Should prove the existence of the given repo, but results in unnecessary database requests\n\tctx.JSON(http.StatusOK, convert.ToAPIAttachment(ctx.Repo.Repository, attach))\n}\n\n// ListReleaseAttachments lists all attachments of the release\nfunc ListReleaseAttachments(ctx *context.APIContext) {\n\t// swagger:operation GET /repos/{owner}/{repo}/releases/{id}/assets repository repoListReleaseAttachments\n\t// ---\n\t// summary: List release's attachments\n\t// produces:\n\t// - application/json\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: id\n\t//   in: path\n\t//   description: id of the release\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// responses:\n\t//   \"200\":\n\t//     \"$ref\": \"#/responses/AttachmentList\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\n\treleaseID := ctx.PathParamInt64(\"id\")\n\trelease, err := repo_model.GetReleaseByID(ctx, releaseID)\n\tif err != nil {\n\t\tif repo_model.IsErrReleaseNotExist(err) {\n\t\t\tctx.APIErrorNotFound()\n\t\t\treturn\n\t\t}\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tif release.RepoID != ctx.Repo.Repository.ID {\n\t\tctx.APIErrorNotFound()\n\t\treturn\n\t}\n\tif release.IsDraft {\n\t\tif !canAccessDraftRelease(ctx) {\n\t\t\tif !ctx.Written() {\n\t\t\t\tctx.APIErrorNotFound()\n\t\t\t}\n\t\t\treturn\n\t\t}\n\t}\n\tif err := release.LoadAttributes(ctx); err != nil {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tctx.JSON(http.StatusOK, convert.ToAPIRelease(ctx, ctx.Repo.Repository, release).Attachments)\n}\n\n// CreateReleaseAttachment creates an attachment and saves the given file\nfunc CreateReleaseAttachment(ctx *context.APIContext) {\n\t// swagger:operation POST /repos/{owner}/{repo}/releases/{id}/assets repository repoCreateReleaseAttachment\n\t// ---\n\t// summary: Create a release attachment\n\t// produces:\n\t// - application/json\n\t// consumes:\n\t// - multipart/form-data\n\t// - application/octet-stream\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: id\n\t//   in: path\n\t//   description: id of the release\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// - name: name\n\t//   in: query\n\t//   description: name of the attachment\n\t//   type: string\n\t//   required: false\n\t// - name: attachment\n\t//   in: formData\n\t//   description: attachment to upload\n\t//   type: file\n\t//   required: false\n\t// responses:\n\t//   \"201\":\n\t//     \"$ref\": \"#/responses/Attachment\"\n\t//   \"400\":\n\t//     \"$ref\": \"#/responses/error\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\t//   \"413\":\n\t//     \"$ref\": \"#/responses/error\"\n\n\t// Check if attachments are enabled\n\tif !setting.Attachment.Enabled {\n\t\tctx.APIErrorNotFound(\"Attachment is not enabled\")\n\t\treturn\n\t}\n\n\t// Check if release exists an load release\n\treleaseID := ctx.PathParamInt64(\"id\")\n\tif !checkReleaseMatchRepo(ctx, releaseID) {\n\t\treturn\n\t}\n\n\t// Get uploaded file from request\n\tvar filename string\n\tvar uploaderFile *attachment_service.UploaderFile\n\tif strings.HasPrefix(strings.ToLower(ctx.Req.Header.Get(\"Content-Type\")), \"multipart/form-data\") {\n\t\tfile, header, err := ctx.Req.FormFile(\"attachment\")\n\t\tif err != nil {\n\t\t\tctx.APIErrorInternal(err)\n\t\t\treturn\n\t\t}\n\t\tdefer file.Close()\n\n\t\tfilename = header.Filename\n\t\tif name := ctx.FormString(\"name\"); name != \"\" {\n\t\t\tfilename = name\n\t\t}\n\t\tuploaderFile = attachment_service.NewLimitedUploaderKnownSize(file, header.Size)\n\t} else {\n\t\tfilename = ctx.FormString(\"name\")\n\t\tuploaderFile = attachment_service.NewLimitedUploaderMaxBytesReader(ctx.Req.Body, ctx.Resp)\n\t}\n\n\tif filename == \"\" {\n\t\tctx.APIError(http.StatusBadRequest, \"Could not determine name of attachment.\")\n\t\treturn\n\t}\n\n\t// Create a new attachment and save the file\n\tattach, err := attachment_service.UploadAttachmentReleaseSizeLimit(ctx, uploaderFile, setting.Repository.Release.AllowedTypes, &repo_model.Attachment{\n\t\tName:       filename,\n\t\tUploaderID: ctx.Doer.ID,\n\t\tRepoID:     ctx.Repo.Repository.ID,\n\t\tReleaseID:  releaseID,\n\t})\n\tif err != nil {\n\t\tif upload.IsErrFileTypeForbidden(err) {\n\t\t\tctx.APIError(http.StatusBadRequest, err)\n\t\t\treturn\n\t\t}\n\n\t\tif errors.Is(err, util.ErrContentTooLarge) {\n\t\t\tctx.APIError(http.StatusRequestEntityTooLarge, err)\n\t\t\treturn\n\t\t}\n\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\n\tctx.JSON(http.StatusCreated, convert.ToAPIAttachment(ctx.Repo.Repository, attach))\n}\n\n// EditReleaseAttachment updates the given attachment\nfunc EditReleaseAttachment(ctx *context.APIContext) {\n\t// swagger:operation PATCH /repos/{owner}/{repo}/releases/{id}/assets/{attachment_id} repository repoEditReleaseAttachment\n\t// ---\n\t// summary: Edit a release attachment\n\t// produces:\n\t// - application/json\n\t// consumes:\n\t// - application/json\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: id\n\t//   in: path\n\t//   description: id of the release\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// - name: attachment_id\n\t//   in: path\n\t//   description: id of the attachment to edit\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// - name: body\n\t//   in: body\n\t//   schema:\n\t//     \"$ref\": \"#/definitions/EditAttachmentOptions\"\n\t// responses:\n\t//   \"201\":\n\t//     \"$ref\": \"#/responses/Attachment\"\n\t//   \"422\":\n\t//     \"$ref\": \"#/responses/validationError\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\n\tform := web.GetForm(ctx).(*api.EditAttachmentOptions)\n\n\t// Check if release exists an load release\n\treleaseID := ctx.PathParamInt64(\"id\")\n\tif !checkReleaseMatchRepo(ctx, releaseID) {\n\t\treturn\n\t}\n\n\tattachID := ctx.PathParamInt64(\"attachment_id\")\n\tattach, err := repo_model.GetAttachmentByID(ctx, attachID)\n\tif err != nil {\n\t\tif repo_model.IsErrAttachmentNotExist(err) {\n\t\t\tctx.APIErrorNotFound()\n\t\t\treturn\n\t\t}\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tif attach.ReleaseID != releaseID {\n\t\tlog.Info(\"User requested attachment is not in release, release_id %v, attachment_id: %v\", releaseID, attachID)\n\t\tctx.APIErrorNotFound()\n\t\treturn\n\t}\n\t// FIXME Should prove the existence of the given repo, but results in unnecessary database requests\n\tif form.Name != \"\" {\n\t\tattach.Name = form.Name\n\t}\n\n\tif err := attachment_service.UpdateAttachment(ctx, setting.Repository.Release.AllowedTypes, attach); err != nil {\n\t\tif upload.IsErrFileTypeForbidden(err) {\n\t\t\tctx.APIError(http.StatusUnprocessableEntity, err)\n\t\t\treturn\n\t\t}\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tctx.JSON(http.StatusCreated, convert.ToAPIAttachment(ctx.Repo.Repository, attach))\n}\n\n// DeleteReleaseAttachment delete a given attachment\nfunc DeleteReleaseAttachment(ctx *context.APIContext) {\n\t// swagger:operation DELETE /repos/{owner}/{repo}/releases/{id}/assets/{attachment_id} repository repoDeleteReleaseAttachment\n\t// ---\n\t// summary: Delete a release attachment\n\t// produces:\n\t// - application/json\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: id\n\t//   in: path\n\t//   description: id of the release\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// - name: attachment_id\n\t//   in: path\n\t//   description: id of the attachment to delete\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// responses:\n\t//   \"204\":\n\t//     \"$ref\": \"#/responses/empty\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\n\t// Check if release exists an load release\n\treleaseID := ctx.PathParamInt64(\"id\")\n\tif !checkReleaseMatchRepo(ctx, releaseID) {\n\t\treturn\n\t}\n\n\tattachID := ctx.PathParamInt64(\"attachment_id\")\n\tattach, err := repo_model.GetAttachmentByID(ctx, attachID)\n\tif err != nil {\n\t\tif repo_model.IsErrAttachmentNotExist(err) {\n\t\t\tctx.APIErrorNotFound()\n\t\t\treturn\n\t\t}\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tif attach.ReleaseID != releaseID {\n\t\tlog.Info(\"User requested attachment is not in release, release_id %v, attachment_id: %v\", releaseID, attachID)\n\t\tctx.APIErrorNotFound()\n\t\treturn\n\t}\n\n\tif err := repo_model.DeleteAttachment(ctx, attach, true); err != nil {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tctx.Status(http.StatusNoContent)\n}\n\n","diff":"commit 1eced4a7c099459af42412bb32a83241650c0f8f\nAuthor: Lunny Xiao <xiaolunwen@gmail.com>\nDate:   Sun Feb 22 12:56:46 2026 -0800\n\n    Fix get release draft permission check (#36659)\n    \n    Draft release and it's attachments need a write permission to access.\n    \n    ---------\n    \n    Signed-off-by: Lunny Xiao <xiaolunwen@gmail.com>\n    Co-authored-by: Copilot <175728472+Copilot@users.noreply.github.com>\n    Co-authored-by: Giteabot <teabot@gitea.io>\n\ndiff --git a/routers/api/v1/repo/release.go b/routers/api/v1/repo/release.go\nindex 272b395df..4f17590ab 100644\n--- a/routers/api/v1/repo/release.go\n+++ b/routers/api/v1/repo/release.go\n@@ -8,6 +8,7 @@ \u0069mport (\n \t\"fmt\"\n \t\"net/http\"\n \n+\tauth_model \"code.gitea.io/gitea/models/auth\"\n \t\"code.gitea.io/gitea/models/db\"\n \t\"code.gitea.io/gitea/models/perm\"\n \trepo_model \"code.gitea.io/gitea/models/repo\"\n@@ -21,6 +22,28 @@ \u0069mport (\n \trelease_service \"code.gitea.io/gitea/services/release\"\n )\n \n+func hasRepoWriteScope(ctx *context.APIContext) bool {\n+\tscope, ok := ctx.Data[\"ApiTokenScope\"].(auth_model.AccessTokenScope)\n+\tif ctx.Data[\"IsApiToken\"] != true || !ok {\n+\t\treturn true\n+\t}\n+\n+\trequiredScopes := auth_model.GetRequiredScopes(auth_model.Write, auth_model.AccessTokenScopeCategoryRepository)\n+\tallow, err := scope.HasScope(requiredScopes...)\n+\tif err != nil {\n+\t\tctx.APIError(http.StatusForbidden, \"checking scope failed: \"+err.Error())\n+\t\treturn false\n+\t}\n+\treturn allow\n+}\n+\n+func canAccessDraftRelease(ctx *context.APIContext) bool {\n+\tif !ctx.IsSigned || !ctx.Repo.CanWrite(unit.TypeReleases) {\n+\t\treturn false\n+\t}\n+\treturn hasRepoWriteScope(ctx)\n+}\n+\n // GetRelease get a single release of a repository\n func GetRelease(ctx *context.APIContext) {\n \t// swagger:operation GET /repos/{owner}/{repo}/releases/{id} repository repoGetRelease\n@@ -62,6 +85,15 @@ func GetRelease(ctx *context.APIContext) {\n \t\treturn\n \t}\n \n+\tif release.IsDraft { // only the users with write access can see draft releases\n+\t\tif !canAccessDraftRelease(ctx) {\n+\t\t\tif !ctx.Written() {\n+\t\t\t\tctx.APIErrorNotFound()\n+\t\t\t}\n+\t\t\treturn\n+\t\t}\n+\t}\n+\n \tif err := release.LoadAttributes(ctx); err != nil {\n \t\tctx.APIErrorInternal(err)\n \t\treturn\n@@ -151,9 +183,13 @@ func ListReleases(ctx *context.APIContext) {\n \t//     \"$ref\": \"#/responses/notFound\"\n \tlistOptions := utils.GetListOptions(ctx)\n \n+\tincludeDrafts := (ctx.Repo.AccessMode >= perm.AccessModeWrite || ctx.Repo.UnitAccessMode(unit.TypeReleases) >= perm.AccessModeWrite) && hasRepoWriteScope(ctx)\n+\tif ctx.Written() {\n+\t\treturn\n+\t}\n \topts := repo_model.FindReleasesOptions{\n \t\tListOptions:   listOptions,\n-\t\tIncludeDrafts: ctx.Repo.AccessMode >= perm.AccessModeWrite || ctx.Repo.UnitAccessMode(unit.TypeReleases) >= perm.AccessModeWrite,\n+\t\tIncludeDrafts: includeDrafts,\n \t\tIncludeTags:   false,\n \t\tIsDraft:       ctx.FormOptionalBool(\"draft\"),\n \t\tIsPreRelease:  ctx.FormOptionalBool(\"pre-release\"),\ndiff --git a/routers/api/v1/repo/release_attachment.go b/routers/api/v1/repo/release_attachment.go\nindex 33f012523..6b30070db 100644\n--- a/routers/api/v1/repo/release_attachment.go\n+++ b/routers/api/v1/repo/release_attachment.go\n@@ -34,6 +34,14 @@ func checkReleaseMatchRepo(ctx *context.APIContext, releaseID int64) bool {\n \t\tctx.APIErrorNotFound()\n \t\treturn false\n \t}\n+\tif release.IsDraft {\n+\t\tif !canAccessDraftRelease(ctx) {\n+\t\t\tif !ctx.Written() {\n+\t\t\t\tctx.APIErrorNotFound()\n+\t\t\t}\n+\t\t\treturn false\n+\t\t}\n+\t}\n \treturn true\n }\n \n@@ -141,6 +149,14 @@ func ListReleaseAttachments(ctx *context.APIContext) {\n \t\tctx.APIErrorNotFound()\n \t\treturn\n \t}\n+\tif release.IsDraft {\n+\t\tif !canAccessDraftRelease(ctx) {\n+\t\t\tif !ctx.Written() {\n+\t\t\t\tctx.APIErrorNotFound()\n+\t\t\t}\n+\t\t\treturn\n+\t\t}\n+\t}\n \tif err := release.LoadAttributes(ctx); err != nil {\n \t\tctx.APIErrorInternal(err)\n \t\treturn\n"}];
const __SKILL_STRUCT__ = {"skillMd":"---\nname: aegis\ndescription: >\n  Weave security through the whole lifecycle instead of bolting it on at the end,\n  across: risk-based stance and principles (least privilege, defense in depth,\n  fail secure, zero trust), threat model, secure design, input-distrusting code,\n  CI security gates (SAST/DAST/SCA), the OWASP Top 10, and operations — tuned for\n  a world where an agent writes insecure code by\n  default, trusts its input, and ships a vulnerability green. The defensive half\n  of the security pair (the\n  shield); its adversarial counterpart is the `gungnir` skill (the spear). Use\n  when the user wants a system secure-by-design, threat modeling, auth design,\n  secrets management, to prevent injection / XSS / broken access control, set up\n  scanning, meet compliance, or stand up security monitoring. Triggers on \"is this secure\", \"threat model this\", \"secure coding\",\n  \"OWASP\", \"least privilege\", \"manage secrets\", \"auth/authz design\", \"shift-left\n  security / DevSecOps\", \"GDPR / PII / data classification\", \"security review\".\nargument-hint: \"[system / feature / scope to secure]\"\nallowed-tools: Read Bash Edit Write\n---\n\n<!--\nCopyright 2026 IamK77 — Licensed under the Apache License, Version 2.0.\nSee ./LICENSE and ./NOTICE · https://www.apache.org/licenses/LICENSE-2.0\n-->\n\n# aegis\n\n!`checklist init ${CLAUDE_SKILL_DIR} --force`\n\nSecurity is not the last check before launch; it is **a line that runs through every part of the lifecycle.** Treating it as something you add once the features work — *bolt-on security* — fails almost by construction, because the most damaging weaknesses live in architecture and design, where they cannot be patched in afterward, only rebuilt. The correct posture is the one this whole suite keeps returning to: **shift security left** (the DevSecOps idea), the same \"catch it early, surface it cheap\" instinct as quality-left and red-means-stop. This skill is the **shield** — the discipline of building a system secure-by-design — across six gated stages, and it will not advance past a **GATE** until the `checklist` tool clears it. Its adversarial counterpart, the **spear** that attacks what this builds to prove it holds, is the `gungnir` skill.\n\nSecurity is where the agent era is most dangerous, because a vulnerability is the worst possible fit for how an agent works:\n- **The agent writes insecure code by default.** Its training distribution is full of vulnerable patterns — string-concatenated SQL, `eval`, weak or homemade crypto, hard-coded keys — and it reproduces them, because insecure code *works perfectly* until someone attacks it.\n- **A vulnerability passes every green test.** It is the *absence of an attack so far*, not a failure — so it sails through every functional test and every green dashboard, and a green-optimizing agent ships it believing the job is done. Security is the ultimate \"green ≠ correct.\"\n- **The agent has no threat model and trusts its input.** It does not spontaneously ask \"who would attack this, and how\"; it writes the happy path and treats input as friendly, which *is* injection and XSS.\n- **The agent invents crypto/auth and over-grants to make it work.** It will happily generate a custom authentication scheme or widen a permission to `*:*` to clear an error, feeling none of the risk.\n\nSo the rule that governs this skill: **security must be woven in and enforced at every stage, never trusted to instinct** — because the most prolific contributor is an agent whose every default is the insecure one, and whose green light certifies nothing about whether the system can be attacked. The aim is not absolute security (which is impossible and infinitely costly) but **risk management**: identify what is most worth protecting and most likely to be attacked, and concentrate the defense there.\n\n**Discipline:** finish every GATE before the next stage. GATEs are hard — never skip, batch past, or self-certify a stage you have not done. The `checklist` tool enforces the order; let it. Commands address stages by **name**.\n\n**Read [references/agent-era-shifts.md](references/agent-era-shifts.md) first** — it is the heart: what each security practice becomes once the code is written by something with no threat model, no felt risk, and a relentless pull toward whatever turns the light green. If `$ARGUMENTS` is a throwaway with no sensitive data and no exposure, this machinery is overkill — say so. The leanest *sufficient* defense for the system's real risk is the goal, not maximum ceremony.\n\n**Speak the user's language, or the risk gets accepted blind.** This skill makes the user own real trade-offs only they can price: what data is sensitive, what an outage or breach costs, which compliance regime applies, how much defense a risk earns. Read their fluency and gloss a term on first use (threat model, STRIDE, least privilege, defense in depth, SAST/DAST/SCA, CIA, zero trust). A user who signs off on \"this residual risk is acceptable\" in words they never parsed has not accepted it — and the FRAME, MODEL, and OPERATE judgments this skill leans on them for are then hollow.\n\n## The reference library\n\nThe depth lives in `references/`. Open each when a stage sends you there — not all upfront. Eight references back the six stages:\n\n- **[references/decision-tree.md](references/decision-tree.md)** — the engine. Sizing the defense to risk (crown jewels × threat × exposure), the STRIDE threat-model router, the build-vs-buy call for anything security-critical (never invent crypto), the OWASP class → defense map, and the escalation ladder. Open it at the start.\n- [references/agent-era-shifts.md](references/agent-era-shifts.md) — the must-be-told reference: how each security practice changes when an agent writes the code. Load at the start, re-check at every gate.\n- [references/principles-and-stance.md](references/principles-and-stance.md) — the timeless principles (least privilege, defense in depth, fail secure, minimize attack surface, no security through obscurity, zero trust), the CIA triad, crown-jewel / data classification, and security as risk management.\n- [references/threat-modeling.md](references/threat-modeling.md) — STRIDE, trust boundaries, attack-surface enumeration, data-flow diagrams, and ranking by risk — the cheapest, highest-leverage security investment.\n- [references/secure-design.md](references/secure-design.md) — authentication and authorization models, enforcing trust boundaries, layering defense in depth, failing secure, secure defaults, and the never-invent-crypto rule.\n- [references/secure-coding.md](references/secure-coding.md) — never trust input (validate at the boundary), parameterized queries, output encoding, the OWASP Top 10 vulnerability → defense catalog, secrets out of code, and least-privilege wiring.\n- [references/security-testing-and-gates.md](references/security-testing-and-gates.md) — SAST / DAST / SCA / fuzzing automated as blocking CI gates, the OWASP ASVS verification checklist, and the hand-off to the `gungnir` skill for adversarial penetration testing.\n- [references/operate-and-respond.md](references/operate-and-respond.md) — runtime defense, security monitoring and detection, patching and CVE/vulnerability management, secret rotation, and security incident response — because security is never *done*.\n\n---\n\n## STAGE 0 — Frame (set the stance, size the defense to the risk)\n\nSecurity investment must match what is at stake — *够用就好*; a system holding payment data and PII earns threat modeling, hard auth, and security gates, a static brochure site does not. Open **[references/decision-tree.md](references/decision-tree.md)** and **[references/principles-and-stance.md](references/principles-and-stance.md)**: name the **crown jewels** (the data and capabilities most worth protecting — classify what is sensitive/PII/regulated), size the exposure and threat, and set the defense to that. Internalize the **CIA** goal (Confidentiality, Integrity, Availability) and the timeless principles you will apply at every later stage — **least privilege, defense in depth, fail secure, minimize attack surface, no security through obscurity, zero trust** — and the governing fact: **security is risk management, not a quest for the absolute.** Assume the attacker knows your system completely and that any single layer can fail.\n\n**Decide the mode: SETUP or AUDIT.** **SETUP**: build security in from the start as you design and code. **AUDIT / security review** (the common case — an existing system): assess each control capability by capability with evidence (is there a threat model? is input validated? are secrets in a manager? are the gates running?), and fix the gaps — never reporting a control sound because it is *named* rather than *enforced*.\n\n**Name who owns the fix — especially when you operate software you did not author** (an OSS product, a vendored service, a dependency you deploy). Split every gap into two kinds: the ones the **deployment** owns — config, secrets, network exposure, host — which *you* can close, and the ones the **product** owns — its code and architecture — which you can only configure around, upgrade, or report upstream. The most \u0069mportant finding is the one that **survives a correctly-hardened deployment**: it is the product's, no operator can close it, and it is exactly the one a purely adversarial pass buries among the config gaps. The decision tree routes this question (the deployment-vs-product axis) so it is not left to chance. The mirror image, for SETUP of something *others* will deploy: the same axis says make the safe configuration the **default**, because a protection you leave to the operator is one you have not actually shipped.\n\n### GATE — clear before MODEL\n1. `checklist check frame security-stance-set`\n2. `checklist verify frame`\n\n---\n\n## STAGE 1 — Model (think like an attacker, on paper, early)\n\nOpen **[references/threat-modeling.md](references/threat-modeling.md)**. Threat modeling is the single highest-leverage, cheapest security investment, and the thing an agent will never do unasked: systematically ask **\"who would attack this, from where, and what do they want?\"** Use **STRIDE** (Spoofing, Tampering, Repudiation, Information disclosure, Denial of service, Elevation of privilege) over the system's data-flow, mark the **trust boundaries** (where data crosses from less-trusted to more-trusted) and the **attack surface** (every exposed endpoint, port, input, and dependency) right on the architecture diagram, and rank the threats by risk so the defense lands where it matters. This is where the `load-bearing` skill's trust boundaries and the `groundwork` skill's security NFRs become a concrete map of what to defend.\n\n### GATE — clear before DESIGN\n1. `checklist check model threat-model-built`\n2. `checklist verify model`\n\n---\n\n## STAGE 2 — Design (build the defenses into the structure)\n\nOpen **[references/secure-design.md](references/secure-design.md)**. Turn the threat model into design decisions, because the worst weaknesses are architectural and cannot be patched in later:\n\n- **Authentication and authorization, designed not improvised** — use a vetted framework; enforce authorization **server-side on every request**, never by hiding a button.\n- **Enforce the trust boundaries** the model drew, and layer **defense in depth** so no single control is the whole defense — assume each layer can be breached.\n- **Fail secure** — on error, default to *deny*, not allow (an auth service that is down must refuse access, not wave it through).\n- **Minimize the attack surface** — expose the fewest endpoints, ports, and features; turn off and delete what you don't use.\n- **Never invent crypto or core security primitives.** Assume the attacker knows your design (no security through obscurity), so security must hold anyway — which is exactly why you use public, audited algorithms and libraries, never a homemade scheme the agent was happy to generate.\n\n### GATE — clear before BUILD\n1. `checklist check design defenses-and-trust-boundaries`\n2. `checklist verify design`\n\n---\n\n## STAGE 3 — Build (code that never trusts input and never holds a secret)\n\nOpen **[references/secure-coding.md](references/secure-coding.md)**. Secure coding rests on one assumption applied everywhere: **never trust user input** — every external input is validated at the boundary before use.\n\n- **Defend the common vulnerability classes by construction** ([the OWASP Top 10 catalog](references/secure-coding.md)): **parameterized queries / prepared statements** for injection (never concatenate input into SQL or a command), **output encoding** for XSS, **server-side authorization checks** for broken access control, CSRF tokens + `SameSite` cookies, encryption in transit (TLS) and at rest for sensitive data, and safe configuration (no default passwords, no exposed debug endpoints, no public buckets).\n- **Secrets never live in code or logs.** Inject them from a secrets manager / vault (the `flightline` skill blocks them at commit time; this stage keeps them out of the running code and the telemetry — never log a password or PII).\n- **Least privilege in the wiring** — every component, query, and credential gets only the access it needs.\n\n### GATE — clear before VERIFY\n1. `checklist check build input-never-trusted`\n2. `checklist check build secrets-and-least-privilege`\n3. `checklist verify build`\n\n---\n\n## STAGE 4 — Verify (automate the security gates; defend the known classes)\n\nOpen **[references/security-testing-and-gates.md](references/security-testing-and-gates.md)**. Security testing must be automated into the pipeline and run every commit — because a vulnerability is invisible to a functional test and a green-optimizing agent will never seek it out.\n\n- **Gate SAST, DAST, and SCA, blocking** — static analysis of the source, dynamic scanning of the running app, and dependency/supply-chain scanning (the `flightline` skill runs the pipeline; this defines what it must enforce). Add **fuzzing** where input handling is critical. Advisory scans an agent can ignore are not gates.\n- **Walk the OWASP Top 10 as a verification checklist** (OWASP ASVS is the standard form): for each class, confirm the defense exists *and* is tested.\n- **Hand the adversarial half to `gungnir`.** Automated scanning finds *known patterns*; it does not chain small flaws into a real exploit or abuse business logic. That creative, adversarial attack — penetration testing — is the `gungnir` skill's job, and it is where a system is truly proven. Scanning is necessary; it is not sufficient.\n\n### GATE — clear before OPERATE\n1. `checklist check verify security-testing-gated`\n2. `checklist check verify vuln-classes-defended`\n3. `checklist verify verify`\n\n---\n\n## STAGE 5 — Operate (defend, patch, and respond — security is never done)\n\nOpen **[references/operate-and-respond.md](references/operate-and-respond.md)**. New vulnerabilities are disclosed every day and every change can open a new hole, so security is a *continuous* practice, not a one-time checkpoint.\n\n- **Runtime defense and security monitoring** — the security slice of the `stationkeeping` skill's observability: detect and alert on attacks and anomalies, log security events, and keep least-privilege access controls with auditing.\n- **Patch and track vulnerabilities continuously** — follow disclosed CVEs and upgrade vulnerable dependencies promptly (the `husbandry` skill's \"don't drift to EOL,\" in its security form: an unpatched known vulnerability is a standing breach).\n- **Have a security incident-response plan** — a known, rehearsed way to respond to a breach (detect → contain → eradicate → recover → learn), run **blameless** like every incident in this suite so problems surface fast instead of hiding.\n\n### FINAL GATE\n1. `checklist check operate runtime-defense-and-patching`\n2. `checklist check operate incident-response-ready`\n3. `checklist verify operate`\n4. `checklist show` — confirm all six stages passed.\n5. `checklist done` — clear this run's state.\n\n---\n\n## The thread through all of it\n\naegis is the **shield**, and it is cross-cutting by nature: the security line runs through every sibling — security NFRs in `groundwork`, trust boundaries in `load-bearing`, SAST/secret-scan/SCA gates in `flightline`, security testing in `assay`, runtime defense and patching in `stationkeeping` and `husbandry`, and the legible, hard-to-fake signal of `gauge`. aegis owns that line and pulls the threads together; it does not replace the siblings' mechanics, it directs them toward defense. And it is one half of a pair: a shield is only proven against a spear, so what aegis builds, the **`gungnir`** skill attacks — the sharpest spear against the hardest shield. For an agent the lever is the same as everywhere in the suite: every one of its defaults is the insecure one and a vulnerability ships green, so security must be **woven in and gated**, not trusted to an instinct it does not have.\n\n## Anti-patterns (use as a pre-flight checklist)\n\n- **Bolt-on security** — added after the features; the architectural holes can't be patched in. Weave it through from STAGE 0.\n- **Trusting user input** — the root of injection and XSS; validate every external input at the boundary.\n- **Inventing your own crypto / auth** — assume the attacker knows your design; use public, audited primitives.\n- **Security through obscurity** — \"they won't find it\" is not a control; assume full knowledge of the system.\n- **Secrets in code or logs** — inject from a manager; never hard-code a key or log a password/PII.\n- **Over-broad permissions** — the agent widens to `*:*` to stop an error; grant least privilege from deny-all.\n- **Default / unreviewed configuration** — default passwords, debug endpoints, public buckets; secure defaults, reviewed.\n- **Unpatched known vulnerabilities** — a disclosed CVE left in a dependency is a standing breach; patch continuously.\n- **Green ≠ secure** — a vulnerability passes every functional test; gate SAST/DAST/SCA and have `gungnir` attack it.\n- **Chasing absolute security** — impossible and infinitely costly; manage risk — defend the crown jewels first.\n- **Skipping a GATE** — the user's judgment on what to protect and what risk to accept can change the whole plan.\n","references":{"agent-era-shifts.md":"# Agent-Era Shifts in Security\n\nThis is the heart of `aegis` — the eight ways securing a system changes once an agent (or a fleet of them) writes the code, designs the interfaces, and wires the permissions, and a human-in-the-loop only sets the risk tolerance, holds authority, and owns the breach when it comes. It is opened at **STAGE 0 (Frame)** alongside [decision-tree.md](decision-tree.md) and kept open at **every GATE**: before you certify a stage, re-read the shift that governs it. The classic security canon — least privilege, defense in depth, threat modeling, never trust input, never invent crypto, patch continuously — is all still correct; it was written for engineers who felt a flicker of wrongness pasting a key into a file, who carried a rough threat model in their head, and who knew that a clever-looking auth scheme was probably a trap. None of those instincts survive contact with an agent. This reference re-aims each practice for a builder that **writes the insecure pattern by default, has no attacker in its head, trusts every input as friendly, invents crypto without fear, over-grants to clear an error, and ships a vulnerability green because nothing red ever stopped it.** The other references teach you *how* to do each piece — [principles-and-stance.md](principles-and-stance.md), [threat-modeling.md](threat-modeling.md), [secure-design.md](secure-design.md), [secure-coding.md](secure-coding.md), [security-testing-and-gates.md](security-testing-and-gates.md), [operate-and-respond.md](operate-and-respond.md). This one names *what is different about the work now*, and ties every shift to the exact gate that enforces it. Read it as a pre-flight scan and a cockpit checklist, not an essay.\n\n---\n\n## AGENT-ERA PRE-FLIGHT — run this one line before you secure anything\n\n> **For the system in front of you, name what an attacker would want and ask of every defense: \"is this enforced and tested — or am I trusting that no one tried yet?\"** A vulnerability is not a failure that shows up red; it is the *absence of an attack so far*. It passes every functional test, lights every dashboard green, and a green-optimizing agent ships it believing the job is done — until someone attacks it, which is the first and only time the system was ever really tested for security. The whole job of this skill is to move security out of \"looks fine / no one's complained\" and into \"threat-modeled, designed-in, coded against untrusted input, gated by SAST/DAST/SCA, attacked by `gungnir`, and patched forever.\" **Security is woven in, never bolted on — and green is not secure.** Assume the attacker knows your system completely and that any one layer can fail. Everything below is a consequence of that.\n\n---\n\n## How each card is built\n\nEvery shift is a cheat-sheet card with four fixed fields, so you can scan it at a gate in seconds:\n\n- **HUMAN-ERA ASSUMPTION** — the textbook premise, true when the builder felt a flicker of risk and carried a rough threat model.\n- **WHAT CHANGED IN THE AGENT ERA** — the specific habit it OVERTURNS or SHARPENS, and why the agent breaks it.\n- **THE DESIGN CONSEQUENCE** — what this forces you to build into the security process instead of trust.\n- **DO THIS** — one literal move you execute, phrased for an agent securing a system on a human's behalf.\n\nDecision forks inside a card use the same engine as the other references: **PREDICATE** (the yes/no that selects the branch), **DEFAULT** (what to pick on a coin-flip), **FALLBACK** (what to do when you cannot answer yet). When ambiguity climbs past those, take the [escalation ladder](#escalation-ladder--when-the-call-is-unclear) at the end.\n\n---\n\n## SHIFT 1 — Security is woven in, or it isn't there → the root shift\n\n> **If you internalize only one card, internalize this one — every other card is a corollary.** Gate: [`security-stance-set`](#gate-map).\n\n| Field | Content |\n|---|---|\n| **HUMAN-ERA ASSUMPTION** | Security could be a phase — a review near the end, a checklist before launch — because a careful engineer was building defensively *along the way* out of instinct, so the final check was a backstop on mostly-secure work. Bolt-on security was a known anti-pattern, but a team of conscientious humans got a lot of security \"for free\" from people who felt the risk as they coded. |\n| **WHAT CHANGED IN THE AGENT ERA** | There is no defensive instinct underneath to back-stop. The agent writes the *insecure* pattern by default and gets nothing for free, so a security phase tacked on at the end is checking work that was never secure to begin with — and the most damaging weaknesses are **architectural**, decided at design time, where a late check finds them only when it is expensive or impossible to fix. This **SHARPENS \"shift security left\" from best practice into the entire architecture of the skill**: security has to be present and *enforced* at every stage, because nothing secure happens between the gates on its own. |\n| **THE DESIGN CONSEQUENCE** | Security is a line through the whole lifecycle, gated stage by stage (frame → model → design → build → verify → operate), not a checkpoint. And because absolute security is impossible and infinitely costly, the line is steered by **risk**: name the crown jewels (the data/capabilities most worth protecting), size the threat and exposure, and concentrate defense there. Match total ceremony to what a breach of *this* system would actually cost — a brochure site and a payments service are not the same. |\n| **DO THIS** | At Frame, name what is worth protecting and classify the data (sensitive / PII / regulated), set the timeless principles as the standard for every later stage, and size the defense to the risk. Treat any property you care about (confidentiality, integrity, availability) and cannot point to a *enforced* control for as unprotected — build the control or accept the risk in writing. |\n\n> Anti-pattern this card kills: **\"we'll do a security review before launch.\"** With an agent writing the code, that review is the *first* time anything checked security — on a system whose every default was the insecure one.\n\n---\n\n## SHIFT 2 — The agent has no threat model → make the attacker explicit\n\n> Gate: [`threat-model-built`](#gate-map).\n\n| Field | Content |\n|---|---|\n| **HUMAN-ERA ASSUMPTION** | A decent engineer carried a rough threat model in their head — building a login form, they half-consciously thought \"someone will try to brute-force this, someone will try SQL in the username,\" and defended accordingly. Formal threat modeling sharpened that instinct; it did not create it from nothing. |\n| **WHAT CHANGED IN THE AGENT ERA** | The agent has **no attacker in its head at all.** It builds the function it was asked for, against the inputs it expects, for the user it imagines — a cooperative one. It does not spontaneously ask \"who would abuse this, and how,\" because that question yields no green reward and is not implied by the task. So the entire adversarial perspective — the cheapest, highest-leverage security work there is — simply does not happen unless it is a required, explicit step. This **takes threat modeling from a sharpening of instinct to the sole source of the adversarial view.** |\n| **THE DESIGN CONSEQUENCE** | Threat modeling must be an explicit gated stage, done **on paper, early**, before the design hardens. Use a structured prompt so coverage doesn't depend on imagination the agent lacks — **STRIDE** over the data flow, **trust boundaries** marked where data crosses from less- to more-trusted, the **attack surface** enumerated (every endpoint, port, input, dependency), threats ranked by risk. The output is a map of what to defend that the design and build stages consume. |\n| **DO THIS** | At Model, run STRIDE across the system's data-flow diagram. For each element ask the six questions (can it be spoofed, tampered, repudiated, leak information, be denied, be elevated). Draw the trust boundaries and list the attack surface explicitly on the architecture. Rank by risk (likelihood × impact) so defense lands where it matters. Pull in the `load-bearing` trust boundaries and the `groundwork` security requirements as inputs. |\n\n> Anti-pattern this card kills: **building only the happy path.** The agent's default user is friendly; the threat model is the only place the hostile one is ever considered.\n\n---\n\n## SHIFT 3 — The agent trusts its input → never trust input, anywhere\n\n> Gates: [`input-never-trusted`](#gate-map), [`vuln-classes-defended`](#gate-map).\n\n| Field | Content |\n|---|---|\n| **HUMAN-ERA ASSUMPTION** | \"Validate your inputs\" was discipline a good engineer mostly followed, with a felt unease about data crossing a trust boundary unchecked — they knew a raw string from a user was dangerous near a SQL query or an HTML page, and reached for the parameterized query or the encoder by reflex on the paths that mattered. |\n| **WHAT CHANGED IN THE AGENT ERA** | The agent treats input as **friendly by default.** It writes the path that works for the expected value, and validation/encoding is friction with no green reward, so it concatenates the user string into the SQL, drops it into the HTML, passes it to the shell — because that *works* for the cooperative input it was imagining, and the injection only appears when a hostile input arrives. The two highest-impact vulnerability classes in existence — **injection and XSS** — are, at root, this single shift: the agent trusting input it should never trust. |\n| **THE DESIGN CONSEQUENCE** | \"Never trust user input\" becomes a hard, enforced rule applied at **every boundary**, not a discipline. Every external input is validated where it enters; and the dangerous sinks are defended *by construction* — **parameterized queries** so input can never be interpreted as SQL/command, **output encoding** so it can never be interpreted as markup, server-side checks so it can never bypass authorization. The OWASP Top 10 is, in large part, the catalog of what goes wrong when this shift is unguarded; defending each class is the concrete form of \"never trust input.\" |\n| **DO THIS** | At Build, treat every external input (form fields, URL params, headers, API bodies, file uploads, even data from another service) as hostile until validated at the boundary. Use parameterized queries everywhere — never string-build SQL or a shell command from input. Output-encode user content for its context (HTML, attribute, JS, URL). Walk the OWASP Top 10 ([secure-coding.md](secure-coding.md)) and confirm the defense for each. Then let `gungnir` try to inject anyway. |\n\n**Decision fork — is this input safe to use as-is?**\n\n- **PREDICATE:** did this value originate inside your trust boundary and remain unmodified by anything outside it?\n- **DEFAULT** on a coin-flip: **treat it as untrusted** — validate and encode it. The cost of validating safe input is nil; the cost of trusting hostile input is an injection.\n- **FALLBACK** when you can't trace its origin: assume it crossed a trust boundary — validate at the point of use; an input whose provenance you can't prove is, by default, attacker-controlled.\n\n---\n\n## SHIFT 4 — The agent invents crypto and over-trusts its own design → use vetted primitives, layer defenses\n\n> Gate: [`defenses-and-trust-boundaries`](#gate-map).\n\n| Field | Content |\n|---|---|\n| **HUMAN-ERA ASSUMPTION** | Engineers were taught — often by scar tissue — **never to roll their own crypto**, and a good one felt the danger in a homemade auth scheme and reached for the vetted library. They also understood, roughly, that one defense is not enough, and that \"no one will figure out our trick\" is not security. The principles were cultural knowledge, transmitted with a sense of *why*. |\n| **WHAT CHANGED IN THE AGENT ERA** | The agent will **cheerfully generate a custom encryption routine, a homemade token scheme, or a bespoke auth flow**, because it can produce plausible code fast and feels none of the danger — the homemade crypto *looks* fine and passes a functional test, and its fatal weakness is invisible without an expert attacker. It also over-trusts its own structure: a single check reads as \"secured,\" and it has no instinct that the attacker is assumed to know the design (so obscurity protects nothing). This **takes \"don't invent crypto / don't rely on obscurity / layer your defenses\" from transmitted wisdom to rules that must be enforced against a builder that will break all three without noticing.** |\n| **THE DESIGN CONSEQUENCE** | Security-critical primitives are **bought, not built**: public, audited algorithms and battle-tested libraries for crypto, authentication, authorization, session management — never a scheme the agent generated. Authorization is enforced **server-side on every request**, never by a hidden control. **Defense in depth** is designed in — no single layer is the whole defense, every layer assumed breachable — and the system **fails secure** (errors default to deny). All of it assumes the attacker knows the design completely (**no security through obscurity**), so it must hold anyway. |\n| **DO THIS** | At Design, for anything security-critical, **pick a vetted library/standard and forbid the homemade version** — if the agent wrote a crypto or auth primitive, that is the finding. Enforce authz server-side on every request. Layer independent defenses so a single bypass isn't game-over. Make the failure path *deny*. Assume your source is public and check the design still holds. |\n\n**Decision fork — build or buy this security-critical primitive?**\n\n- **PREDICATE:** is this crypto, authentication, authorization, session, or randomness — anything whose subtle flaw is an exploit?\n- **DEFAULT** on a coin-flip: **buy** — a public, audited, widely-used implementation. The space of subtle, exploitable mistakes is vast and invisible to a functional test; you will not out-design the field, and the agent certainly won't.\n- **FALLBACK** when no vetted option seems to fit: that is almost always a sign you've mis-scoped the need — re-frame to a standard one (OAuth/OIDC, a KMS, argon2/bcrypt, the platform's crypto) before ever hand-rolling; escalate to the user rather than invent.\n\n---\n\n## SHIFT 5 — The agent leaks secrets and over-grants → machine-enforce least privilege\n\n> Gate: [`secrets-and-least-privilege`](#gate-map).\n\n| Field | Content |\n|---|---|\n| **HUMAN-ERA ASSUMPTION** | \"Don't commit secrets\" and \"grant least privilege\" were discipline — a human felt a flicker of wrongness hard-coding a key or logging a password, and granting `*:*` felt lazy and dangerous even when it was expedient. The `.gitignore` and the IAM review were backstops to mostly-careful judgment. |\n| **WHAT CHANGED IN THE AGENT ERA** | The agent feels **no wrongness** doing either, and both are its cheapest path to a green result. To make something work *now*, it will hard-code a real key, paste a token into config, log the whole request (PII and all) to debug, and widen a permission to `*:*` the moment an `AccessDenied` blocks it. None of these turn anything red; all of them ship. This **takes \"guard your secrets and scope your permissions\" from discipline you trust to rules you can no longer trust to the actor doing the work.** |\n| **THE DESIGN CONSEQUENCE** | Both become **machine-enforced**, not norms. Secrets are injected at runtime from a manager/vault, never in code, an image layer, or a log — and a secret-scanning gate blocks the commit (`flightline`) while telemetry redaction keeps them out of logs (`stationkeeping`/`gauge`). **Least privilege** is the default posture: every identity, service, query, and credential scoped from **deny-all** to exactly what it needs, with access audited, and a permission-widening treated as a reviewed change, not a quiet fix. |\n| **DO THIS** | At Build, keep every secret in a manager and inject it; never hard-code or log one (redact PII/credentials in telemetry). Scope every permission from deny-all and add only what a real use proves necessary; when an `AccessDenied` appears, *narrow the need*, don't widen the grant. In review, treat a hard-coded secret or a `*:*` grant as a blocking finding. |\n\n> Anti-pattern this card kills: **\"widen the permission / paste the key to make it work.\"** Both clear the error and ship a standing breach the agent felt no reason to avoid.\n\n---\n\n## SHIFT 6 — A vulnerability ships green → gate it and attack it\n\n> Gates: [`security-testing-gated`](#gate-map), [`vuln-classes-defended`](#gate-map).\n\n| Field | Content |\n|---|---|\n| **HUMAN-ERA ASSUMPTION** | A failing test meant \"fix the code,\" and a human's own judgment — \"wait, could this be abused?\" — lived outside the test suite as a backstop. Security testing (SAST, the occasional pentest) was a useful supplement to engineers who were already thinking, at least sometimes, about misuse. |\n| **WHAT CHANGED IN THE AGENT ERA** | The agent equates **green with done**, and a vulnerability produces *no red*. Functional tests pass, the dashboard is green, the feature works — and the security hole sits there invisibly, because it is the absence of an attack, not a failed assertion. There is no judgment outside the suite to catch it; the agent's only signal is the light, and the light says ship. This **takes security testing from a supplement to the *only* thing standing between an insecure default and production** — and makes the integrity of those gates paramount, since an agent facing a security gate will \"fix\" it the same way it fixes any red (suppress, weaken, skip) if it can. |\n| **THE DESIGN CONSEQUENCE** | Security must be made *visible as a gate*: **SAST** (static source), **DAST** (running app), and **SCA** (dependencies/supply chain) automated into CI as **blocking** checks on every commit, plus fuzzing where input handling is critical — advisory scans an agent ignores are not gates. The known classes are walked as a checklist (OWASP Top 10 / ASVS) so each defense is confirmed *and tested*. And because scanners only find *known patterns* and never chain small flaws into a real exploit or abuse business logic, the system must also be **attacked adversarially** — which is the `gungnir` skill's job. Scanning is necessary; the spear is what proves the shield. |\n| **DO THIS** | At Verify, gate SAST/DAST/SCA blocking in the pipeline (`flightline` runs it; you define what it enforces). Walk the OWASP Top 10 and confirm each class is defended and has a test. Put the security-gate config under review so it can't be quietly weakened. Then hand off to `gungnir` for the adversarial attack the scanners cannot do — and treat \"the scan was clean\" as necessary, never as \"secure.\" |\n\n> Anti-pattern this card kills: **\"the scan passed, so we're secure.\"** A clean scan means the *known patterns* weren't found; the exploit chain and the logic flaw are exactly what it can't see — and what `gungnir` is for.\n\n---\n\n## SHIFT 7 — Security is never done → defend, patch, and respond continuously\n\n> Gates: [`runtime-defense-and-patching`](#gate-map), [`incident-response-ready`](#gate-map).\n\n| Field | Content |\n|---|---|\n| **HUMAN-ERA ASSUMPTION** | After launch, a responsible team kept half an eye on security — noticed a weird spike, applied the urgent patch, knew roughly who to call if something went wrong. Security decayed slowly and a conscientious human arrested the decay by ongoing attention and a sense of duty to the running system. |\n| **WHAT CHANGED IN THE AGENT ERA** | New vulnerabilities are disclosed **every day**, and every change the agent makes can open a fresh hole — while the agent has **no ongoing attention and no felt duty** to a system it isn't currently asked to change. It will leave a disclosed CVE unpatched in a dependency (an upgrade is friction with no green reward), miss the attack in progress (it reads quiet logs as safe — the `stationkeeping` silence-is-health trap, in security form), and improvise badly in a breach because nothing remembers how to respond. This **takes \"keep an eye on security\" from a duty you trust to a continuous, externalized practice that must be wired up.** |\n| **THE DESIGN CONSEQUENCE** | Security after launch is **continuous and instrumented**: runtime detection and alerting on attacks/anomalies (the security slice of `stationkeeping` observability), security-event logging, audited least-privilege access — *plus* relentless **patching**: track disclosed CVEs and upgrade vulnerable dependencies promptly (`husbandry`'s don't-drift-to-EOL, where an unpatched known vuln is a standing breach). And a **rehearsed incident-response plan** — detect → contain → eradicate → recover → learn — run **blameless** so a breach surfaces fast instead of being hidden. |\n| **DO THIS** | At Operate, wire security monitoring/alerting and security-event logging. Track CVE feeds for your stack and patch vulnerable dependencies on a cadence, not when forced. Write and *rehearse* an incident-response runbook (detect/contain/eradicate/recover/learn); run the postmortem blameless. Treat an unpatched known vulnerability and an un-rehearsed response plan as the same kind of standing risk. |\n\n> Anti-pattern this card kills: **\"we secured it at launch.\"** Security is a moving target — new CVEs, new changes, new attacks — and a one-time hardening is stale within weeks.\n\n---\n\n## SHIFT 8 — The agent conflates the deployment with the product → separate who owns the fix\n\n> Gate: [`security-stance-set`](#gate-map). **Applies in AUDIT mode when the system is one you operate but did not author** (OSS, a vendored service, a dependency you deploy).\n\n| Field | Content |\n|---|---|\n| **HUMAN-ERA ASSUMPTION** | An engineer auditing software the team operates but didn't write knew, without thinking, the difference between a gap they could close by deploying correctly (turn on auth, lock down the network, rotate the default password) and a weakness baked into the product's code that no careful deployment could fix. The first went to ops, the second went upstream — and they knew the second mattered most, because it survived everything they could do to the deployment. |\n| **WHAT CHANGED IN THE AGENT ERA** | The agent has **no notion of *who owns the fix***. Auditing software it operates, it lists \"no auth by default\" and \"session tokens never expire in code\" as the same kind of gap, because it doesn't model the boundary between *this deployment* (which it controls) and *the product* (which it doesn't). The most valuable finding — a flaw that survives a correctly-hardened deployment, that no operator can close — gets averaged in with config it could have fixed in a line, and the audit reads as \"your setup is insecure\" when the real story is \"this software is insecure no matter how you set it up.\" This **takes \"separate the deployment's fault from the product's fault\" from an auditor's obvious instinct to a routed, required step.** |\n| **THE DESIGN CONSEQUENCE** | In AUDIT mode, when the system is one you operate but did not author, every gap is classified on a **second axis**: *deployment-owned* (config/secrets/exposure/host — you can close it) vs *product-owned* (code/architecture — survives a correctly-hardened deployment, only an upstream change or your fork closes it). The decision tree routes this; the cheapest settle is mechanical: **harden the deployment, then re-assess** — what remains is the product's, and it ranks highest because no operator can make it go away. The mirror holds for SETUP of software *others* will deploy: the same axis says make the safe configuration the **default**, because a protection left to the operator is one you haven't shipped. |\n| **DO THIS** | At Frame, if you operate software you didn't write, split every gap into deployment-owned vs product-owned and tag each with \"closed by correct deployment?\" Surface the product-owned, survives-hardening findings as the headline. Hand the deployment-owned half to your own remediation; hand the product-owned half to coordinated disclosure (the `gungnir` skill's report stage owns that loop). For software you build for others, make the secure configuration the default. See [decision-tree.md](decision-tree.md#the-deployment-vs-product-axis-when-you-operate-what-you-did-not-author). |\n\n> Anti-pattern this card kills: **\"the deployment is insecure, so the finding is the deployment.\"** A misconfigured install is the operator's to fix; a flaw that survives correct deployment is the product's — conflating them buries the finding no operator can close.\n\n---\n\n## GATE MAP\n\n*Each shift mapped to the exact `.checklist.yml` check it governs.*\n\nRead down this table at the corresponding GATE: it tells you which shift you are actually enforcing and what \"done\" means for a system secured by an agent. The checks are the contract; the shifts are *why* the contract reads the way it does.\n\n| Stage | Check ID | Primary shift(s) | What it enforces, agent-era framing |\n|---|---|---|---|\n| frame | `security-stance-set` | **SHIFT 1**, SHIFT 8 | Security woven through the lifecycle, sized to risk (crown jewels, data classification); the timeless principles set as the standard; and when auditing software you operate but didn't write, each gap split deployment-owned vs product-owned (survives correct deployment) — because nothing secure happens between gates on its own, the agent's defaults are all insecure, and it conflates the deployment with the product. |\n| model | `threat-model-built` | **SHIFT 2** | STRIDE over the data flow, trust boundaries and attack surface marked, threats ranked — because the agent has no attacker in its head and builds only the happy path. |\n| design | `defenses-and-trust-boundaries` | **SHIFT 4** | Vetted crypto/auth (never invented), server-side authz, defense-in-depth, fail-secure, no security-through-obscurity — because the agent rolls its own primitives and over-trusts its design. |\n| build | `input-never-trusted` | **SHIFT 3** | Every input validated at the boundary; injection/XSS/broken-access-control defended by construction (parameterized queries, output encoding, server-side checks) — because the agent trusts input as friendly. |\n| build | `secrets-and-least-privilege` | **SHIFT 5** | Secrets injected from a manager (never in code/logs); least privilege from deny-all — because the agent hard-codes keys and widens to `*:*` to clear an error, feeling no wrongness. |\n| verify | `security-testing-gated` | **SHIFT 6** | SAST/DAST/SCA + fuzzing as blocking CI gates — because a vulnerability ships green and the agent never seeks it; advisory scans aren't gates. |\n| verify | `vuln-classes-defended` | **SHIFT 6**, SHIFT 3 | OWASP Top 10 walked as a tested checklist, and the adversarial attack handed to `gungnir` — because scanners find known patterns but not the exploit chain or logic flaw. |\n| operate | `runtime-defense-and-patching` | **SHIFT 7** | Runtime detection/alerting + continuous CVE patching — because security decays daily and the agent has no ongoing duty to patch or watch. |\n| operate | `incident-response-ready` | **SHIFT 7** | A rehearsed, blameless detect→contain→eradicate→recover→learn plan — because nothing remembers how to respond and a breach must surface fast, not hide. |\n\n---\n\n## ESCALATION LADDER — when the call is unclear\n\nWhen a DEFAULT and FALLBACK inside a card don't resolve the question — is this input trusted, build or buy this primitive, is this residual risk acceptable — climb one rung at a time rather than guessing silently (guessing is exactly the move an agent makes, and a wrong security guess is a breach, not a bug):\n\n```\npick the DEFAULT for a clearly low-risk, reversible security choice\n   → wrapped: make the safe choice the default (validate by default, deny by default, the vetted library)\n      → test it: have it attacked — a SAST/DAST run, or `gungnir` against it in staging — before you trust it\n         → ask the user one sharp question — they hold authority on what data matters, what a breach costs,\n           which compliance regime applies, and what residual risk is acceptable (the build-vs-buy call,\n           the trust-this-input call, and the accept-the-risk call all bottom out here)\n            → if still unresolved, default to the MORE secure, fail-closed option (deny, validate, buy the\n              vetted primitive, patch now) and record the residual as security risk for the user to accept in writing.\n```\n\nThe asymmetry that governs the whole ladder: **an over-cautious security choice costs the agent some minutes or a little friction; a trusted hostile input, an invented cipher, or an unpatched CVE costs you a breach the agent will have shipped green and reported as done.** When the call is genuinely a toss-up, err toward the fail-closed, vetted, defended option. See [decision-tree.md](decision-tree.md) for sizing the defense to the risk and the build-vs-buy and OWASP routers, [../SKILL.md](../SKILL.md) for the stage order, and the `gungnir` skill for attacking what you build here to prove it holds.\n","decision-tree.md":"# The aegis Decision Tree\n\nThis is the deterministic router at the heart of `aegis` — the engine the stages call into so that two agents securing the same system reach the *same* defense. Open it **first**, at STAGE 0 (Frame), alongside [agent-era-shifts.md](agent-era-shifts.md), and keep it beside you through every stage. The other references are the depth on each topic; this one decides *how much* defense the system earns, *which* move to make at each fork, and *what defends what*. It is five mechanisms: the **risk sizer** (TREE 0), the **SETUP-vs-AUDIT split** with its status taxonomy, the **STRIDE threat-model router**, the **build-vs-buy** decision for security-critical primitives, and the **OWASP class → defense map** — feeding the [escalation ladder](agent-era-shifts.md#escalation-ladder--when-the-call-is-unclear) in agent-era-shifts.md.\n\nEvery fork states three things so the routing is reproducible:\n\n- **PREDICATE** — the question that selects the branch.\n- **DEFAULT** — what to pick when the predicate is a genuine coin-flip.\n- **FALLBACK** — what to do when you cannot answer the predicate yet.\n\nOne governing fact overrides every DEFAULT and FALLBACK below:\n\n> **Security is woven in, never bolted on — and a vulnerability passes every green test, because it is the absence of an attack, not a failure.** Assume the attacker knows your system completely and that any single layer can fail. When a fork is a real toss-up, err toward the **fail-closed, vetted, defended** option — deny over allow, validate over trust, buy the audited primitive over inventing one, patch now over later. The asymmetry: an over-cautious choice costs minutes or a little friction; a trusted hostile input, an invented cipher, or an unpatched CVE costs a breach the agent will have shipped green.\n\n---\n\n## TREE 0 — Sizing the defense to risk (size before you build)\n\nDefense is a cost; match it to what a breach would actually cost — *够用就好*. Score the system on three dials, take the **highest**, and read off the floor.\n\n| Dial | Light | Medium | Heavy |\n|---|---|---|---|\n| **Crown jewels** (what's lost if breached) | nothing sensitive; public/static data | real user data; some PII; reputational cost | payment data, health/PII at scale, secrets, safety, regulated data |\n| **Exposure** (reachability) | internal-only / not internet-facing | internet-facing, authenticated | internet-facing, public, high-traffic, valuable target |\n| **Threat** (who'd attack, how motivated) | no one specific; opportunistic only | opportunistic + some targeted | motivated, funded, targeted adversaries |\n\n- **PREDICATE:** what is the highest dial this system hits?\n- **LIGHT → the minimum:** input validation, parameterized queries, HTTPS, no secrets in code, dependency scanning, sane defaults. Skip a formal threat model, a pentest, a full IR plan.\n- **MEDIUM → the standard floor:** all six stages, lightly — a threat model, designed authn/authz, the OWASP defenses, SAST/DAST/SCA gated, patching, a basic IR plan; a pentest (`gungnir`) before launch.\n- **HEAVY → the full floor:** threat modeling as a living practice, defense in depth proven, hard authz, blocking security gates + fuzzing, an independent professional pentest, runtime detection, a rehearsed IR plan, and compliance controls (the user's regime).\n- **DEFAULT** on a coin-flip between two classes: size to the **higher** class for the dial touching data, money, safety, or compliance (an under-defended breach of regulated data is the catastrophic error) and the lower class elsewhere.\n- **FALLBACK** when you can't size it (unknown data sensitivity, unclear exposure): assume **MEDIUM**, and make the data classification and compliance regime explicit questions for the user — an unsized system defaults to \"the agent secures it as little as the happy path required,\" which is the failure mode.\n\n> **The agent multiplier:** the more an agent writes/operates the system, the *more* of the defense must be enforced as a gate, not trusted — because every one of the agent's defaults is the insecure one and it supplies no defensive instinct to back-stop a light floor.\n\n---\n\n## SETUP vs AUDIT — pick the mode, then the status taxonomy\n\n- **PREDICATE:** are you building security into a new/changing system (SETUP) or reviewing an existing one (AUDIT)?\n- **SETUP**: build the defense in stage by stage to the TREE 0 floor.\n- **AUDIT / security review** (the common case): assess each control with **evidence**, then fix the gaps:\n\n| Status | Means | Evidence that proves it |\n|---|---|---|\n| **enforced** | exists and *blocks/holds* | a SAST/DAST/SCA gate that fails the build; authz that denies a forged request in a test; a secret-scan that blocks a commit |\n| **present-unenforced** | configured but advisory / not blocking | a scanner that only warns; an authz check only in the UI — treat as **not done** |\n| **claimed** | asserted, not verified | \"we validate input\" with no test proving a hostile input is rejected |\n| **absent** | not there | — |\n| **unknown** | can't tell from here | needs the user / a deeper look (or a `gungnir` probe) |\n\n> The trap this kills: reporting a control sound because it *exists* rather than because it *blocks*. `present-unenforced` is the most dangerous status — an advisory scanner or a UI-only authz check looks like a defense and stops nothing. A control is only real once it is enforced *and* something has tried to get past it.\n\n### The deployment-vs-product axis (when you operate what you did not author)\n\nA second axis cuts across the status taxonomy whenever the system under review is one you **operate but did not write** — an OSS product, a vendored service, a dependency you deploy. Now \"fix the gap\" forks by *who can fix it*, and the two are not equally valuable to surface:\n\n| Owner | What it covers | Closed by | The finding's value |\n|---|---|---|---|\n| **Deployment** | config, secrets, network exposure, host, the options you chose | you, by deploying correctly | real, but it is *your* posture — another operator may already have it right |\n| **Product** | the code and architecture anyone running it inherits | only an upstream change (or your own fork) | highest — it **survives a correctly-hardened deployment**, no operator can close it, and it is what the maintainer must hear |\n\n- **PREDICATE:** would a *correctly-hardened deployment* (auth on, least exposure / bound to loopback, strong secrets, current version) still have this gap? If yes → **product-owned**; if no → **deployment-owned**.\n- **DEFAULT** on a coin-flip: the cheapest way to settle it is to *harden the deployment and look again* — close the config gaps first, then see what is still standing. What remains is the product's, and ranks above anything a config change would have erased. This is the operator's lens the adversarial pass does not supply on its own: a default install falling over proves little about the product; a flaw still live after you did everything right proves a lot.\n- **FALLBACK** when you cannot harden it yourself to test (no control over the build, can't change the config): reason it through from the code and the defaults, tag the finding *product-owned / unverified-against-hardening*, and say so — never let a deployment-fault and a product-fault be reported as the same thing.\n\n> The agent blind spot this kills: an agent reviewing software it operates conflates the **deployment** with the **product** — it reports \"I broke the default install\" with the same weight as \"this is broken in code no matter how you run it,\" because it has no notion of *who ships the fix*. Separating the two turns a generic \"your defaults are bad\" into the specific, high-value \"this survives correct deployment — it's yours to patch.\" A product-owned finding you cannot fix yourself routes to coordinated disclosure (the `gungnir` skill's report stage owns that loop).\n\n---\n\n## The STRIDE threat-model router (STAGE 1)\n\nRun STRIDE over each element of the system's data-flow diagram (external entities, processes, data stores, and the data flows between them). For each, ask the six questions; each \"yes, plausibly\" is a threat to rank and defend. Detail in [threat-modeling.md](threat-modeling.md).\n\n| STRIDE threat | The question | Property it violates | Typical defense |\n|---|---|---|---|\n| **S**poofing | can an attacker pretend to be someone/something else? | Authentication | strong authn, vetted identity, MFA |\n| **T**ampering | can data be modified in transit or at rest? | Integrity | TLS, signing/HMAC, input validation, access control |\n| **R**epudiation | can someone deny an action with no proof? | Non-repudiation | audit logs, signed records |\n| **I**nformation disclosure | can data leak to someone unauthorized? | Confidentiality | encryption (transit + rest), least privilege, no secrets/PII in logs |\n| **D**enial of service | can the system be made unavailable? | Availability | rate limiting, quotas, autoscaling (`stationkeeping`), input limits |\n| **E**levation of privilege | can a user gain rights they shouldn't have? | Authorization | server-side authz on every request, least privilege, deny-all default |\n\n- **PREDICATE:** for this element and this threat, is the attack plausible *and* the impact material?\n- **DEFAULT** on a coin-flip about whether a threat is worth defending: defend it if it touches a crown jewel or a trust boundary; for the rest, rank by `likelihood × impact` and defend top-down until the budget for this system's weight class is spent.\n- **FALLBACK** when you can't tell if a threat is reachable: mark the trust boundary it would cross and treat the element as reachable until proven otherwise — and let `gungnir` test whether it actually is.\n\nMark **trust boundaries** (every place data crosses from less- to more-trusted) and the **attack surface** (every exposed endpoint/port/input/dependency) directly on the diagram — they are where defense concentrates.\n\n---\n\n## The build-vs-buy decision (anything security-critical)\n\nThe single fork the agent gets most dangerously wrong (it will happily invent crypto — agent-era-shifts SHIFT 4). Detail in [secure-design.md](secure-design.md).\n\n- **PREDICATE:** is this crypto, authentication, authorization, session management, password storage, tokens, or randomness — anything whose *subtle* flaw is an exploit?\n- **Yes** → **buy/adopt a public, audited, widely-used implementation** (OAuth/OIDC, a KMS, argon2/bcrypt/scrypt for passwords, the platform's crypto library, a vetted authz framework). Never the agent's homemade version.\n- **No, it's ordinary application logic** → build it — under the rest of this skill's defenses.\n- **DEFAULT** on a coin-flip about whether something is \"security-critical enough\" to buy: **buy.** The space of subtle, exploitable crypto/auth mistakes is vast and invisible to a functional test; the homemade version *looks* fine and fails only against an expert attacker.\n- **FALLBACK** when no vetted option seems to fit: that usually means the need is mis-scoped — re-frame to a standard one before ever hand-rolling, and escalate to the user rather than invent a primitive.\n\n> The rule behind this fork is **no security through obscurity**: assume the attacker knows your design, so \"they won't figure out our scheme\" is never a defense — which is exactly why only publicly-audited primitives, whose security holds *with* the design known, are safe.\n\n---\n\n## The OWASP class → defense map (STAGE 3–4)\n\nThe common vulnerability classes (the OWASP Top 10 is the canonical list) and the defense each requires. Use it as a checklist at Build (defend each) and Verify (test each). Full depth in [secure-coding.md](secure-coding.md).\n\n| Vulnerability class | The attack | The defense (by construction) |\n|---|---|---|\n| **Injection** (SQL/NoSQL/command) | input interpreted as code/query | **parameterized queries / prepared statements**; never concatenate input into SQL/commands |\n| **Broken access control** | user reaches data/actions they shouldn't (IDOR, forced browsing) | **authorization checked server-side on every request**, against the actual user — never a hidden UI control |\n| **Cryptographic failures** (sensitive-data exposure) | data read in transit or at rest | TLS in transit + encryption at rest; vetted crypto; no secrets/PII in logs |\n| **Identification & auth failures** | weak passwords, no brute-force protection, sessions that don't expire | vetted auth framework, MFA, rate limiting, secure session management, `HttpOnly`/`Secure` cookies |\n| **Cross-site scripting (XSS)** | user content executed as script | **output encoding/escaping** for the context; a content security policy |\n| **Cross-site request forgery (CSRF)** | a user's browser tricked into an action | CSRF tokens; `SameSite` cookies |\n| **Security misconfiguration** | default passwords, debug endpoints, public buckets | secure defaults; config review; minimal attack surface |\n| **Vulnerable & outdated components** | a known-CVE dependency | SCA scanning + prompt patching (`flightline`/`husbandry`) |\n| **Security logging & monitoring failures** | a breach goes unnoticed | security-event logging + alerting (`stationkeeping`) |\n| **SSRF** | server tricked into requesting an internal resource | validate/allowlist outbound targets; network segmentation |\n\n> The thread through the whole table: **never trust user input** (agent-era-shifts SHIFT 3). Injection, XSS, broken access control, and SSRF are all, at root, input that was trusted when it should have been validated, encoded, or authorized.\n\n---\n\n## Worked traversal (an internet-facing app handling user PII and payments)\n\n1. **TREE 0:** crown jewels = payments + PII (Heavy), exposure = public internet-facing (Heavy), threat = motivated/targeted (Heavy) → **HEAVY → full floor, pentest required.**\n2. **Mode:** existing system → **AUDIT.** Status-pass: threat model `absent`, input validation `claimed` (no test proves a hostile input is rejected), authz `present-unenforced` (checked in the UI, not server-side — an IDOR waiting to happen), secrets `absent` control (a key found hard-coded), SAST/DAST `absent`. Most read as **not done**.\n3. **STRIDE:** over the data flow surfaces Elevation-of-privilege (the UI-only authz) and Information-disclosure (the hard-coded key, PII in logs) as top-ranked; trust boundary at the API edge.\n4. **Build-vs-buy:** the team's homemade session-token scheme → **buy** (adopt a vetted session library / OAuth); the invented token is the finding.\n5. **OWASP map:** broken access control → server-side authz on every request; injection → parameterized queries; crypto failures → TLS + at-rest encryption + secret to a vault; walk the rest.\n6. **Verify → gungnir:** gate SAST/DAST/SCA; then the `gungnir` skill attacks the staging app — and the IDOR and the logic flaws are exactly what the scanners missed and the spear finds.\n7. Carry the unresolved calls (which compliance regime? what residual risk is acceptable?) to the user via the escalation ladder rather than assuming.\n","operate-and-respond.md":"# Operate & Respond\n\nThis reference is the depth behind **STAGE 5 — Operate** of the [../SKILL.md](../SKILL.md) flight plan, where security stops being something you *finish* and becomes something you *run*. Every prior stage — frame, model, design, build, verify — produced a system that was secure *the day it shipped*. This stage governs the truth that it does not stay that way on its own: new vulnerabilities are disclosed every day, every change the agent makes can open a fresh hole, and an attacker is probing the running system continuously. The human-era operator kept half an eye on the deployed system — noticed a weird spike, applied the urgent patch, knew roughly who to call when something went wrong — and arrested the slow decay of security by ongoing attention and a felt duty to the running system. None of that survives an agent operating production: it has **no ongoing attention and no felt duty** to a system it isn't currently asked to change, it reads quiet logs as proof of safety (the `stationkeeping` silence-is-health trap, in security form), it leaves a disclosed CVE unpatched because an upgrade is friction with no green reward, and it improvises badly in a breach because nothing remembers how to respond. So both halves of this stage get **externalized into instrumentation and rehearsed artifacts** — runtime defense into detection that *fires* on attack signals the agent would otherwise read as quiet, and incident response into a rehearsed detect→contain→eradicate→recover→learn plan that is the agent's only breach memory. This file is the *how*; for *why* it reads this way, read [agent-era-shifts.md](agent-era-shifts.md) — specifically **SHIFT 7** (security is never done → defend, patch, and respond continuously).\n\nOne fact, inherited from [decision-tree.md](decision-tree.md), overrides everything below:\n\n> **Security is woven in, never bolted on — and a vulnerability passes every green test, because it is the absence of an attack, not a failure.** Assume the attacker knows your system completely and that any single layer can fail. At Operate this sharpens to its post-launch form: the system is *being attacked right now*, the only question is whether you can see it; an unpatched known vulnerability is a **standing breach**, not a backlog item; and an incident-response plan you have never rehearsed is **not a plan**. When a fork here is a real toss-up, err toward the **fail-closed, rehearsed, patch-now** move.\n\nThis reference delivers two checks. Cover both: **`runtime-defense-and-patching`** (runtime detection and continuous CVE patching — make the attack signal fire, treat an unpatched vuln as a breach) and **`incident-response-ready`** (a rehearsed, blameless detect→contain→eradicate→recover→learn plan).\n\n---\n\n## Runtime defense and security monitoring — make the attack signal fire\n\nEverything an attacker does to a running system is, at the network and application layer, *traffic the system handles* — a login attempt, a request to an endpoint, a query, an outbound call. The defining property of an attack is that it looks, byte for byte, like legitimate use until you correlate it: one failed login is a fat-fingered password, ten thousand from one IP in a minute is credential stuffing. So runtime security defense is not a wall you build once; it is the **security slice of the `stationkeeping` skill's observability** — the same logging, metrics, alerting, and dashboards that skill stands up for reliability, pointed at *attack signals* instead of latency and error rate. aegis does not replace that machinery; it directs it toward defense.\n\nThe agent failure mode this guards against is the silence-is-health trap in its most dangerous costume. The `stationkeeping` skill warns that an agent reads a quiet dashboard as \"reliability is fine.\" In security the trap is worse, because the attacker is *actively working to keep the signal quiet* — a competent intruder moves slowly, blends with normal traffic, and cleans up after themselves precisely so the logs stay calm. **Quiet logs are not evidence of safety; they are the default state of both a secure system and a thoroughly compromised one.** The job here is to make the attack signals *loud* — to instrument the specific anomalies that an attack produces so that an attack in progress turns something red instead of sailing under a green dashboard.\n\n### What must be logged, detected, and alerted\n\nThe four layers below are the minimum runtime-defense floor for a MEDIUM-or-heavier system (the weight class comes from [decision-tree.md](decision-tree.md) TREE 0; a LIGHT internal-only system may need only the security-event log and dependency alerting). Each layer names the agent default it overrides.\n\n| Layer | What it is | The attack signal it makes fire | Agent default it overrides |\n|---|---|---|---|\n| **Security-event logging** | A durable, structured, tamper-resistant log of security-relevant events: authentication (success *and* failure), authorization denials, privilege changes, access to crown-jewel data, config and secret changes, admin actions. | The forensic record — *who did what, when* — without which an incident cannot be reconstructed or even confirmed. This is the OWASP \"security logging & monitoring failures\" class, closed. | The agent logs the happy path and omits the security events (they have no functional value); or logs them and then leaks secrets/PII into the log (SHIFT 5) — redact credentials and PII in telemetry. |\n| **Detection & alerting on anomalies** | Rules and thresholds that fire on the patterns of an attack, not on individual events. | **Failed-auth spikes** (brute force / credential stuffing), **unusual access patterns** (a user reading records they never touch, access at 3am from a new geo, enumeration of sequential IDs = IDOR probing), **privilege-escalation events**, **unexpected outbound traffic** (data exfiltration, SSRF, a compromised host calling home), **rate/volume anomalies**. | The agent never writes the alert at all — an attack yields no red, so there is nothing to make it build the detector; the adversarial signal must be a *required, explicit* control, exactly like the threat model (SHIFT 2). |\n| **A WAF / edge filtering + rate limiting** | A Web Application Firewall and/or API gateway at the edge that filters known-malicious request patterns and **rate-limits** by IP/identity/endpoint. | Caps brute-force and enumeration to a survivable rate, blocks the bulk of automated/known-pattern attacks (the Denial-of-service and many Injection probes from [decision-tree.md](decision-tree.md)'s STRIDE/OWASP maps) before they reach the app. A defense-in-depth layer, **not** a substitute for the secure-coding defenses behind it — assume it can be bypassed. | The agent ships an endpoint with no rate limit because the happy path needs none; the unthrottled login or password-reset is then a free brute-force oracle. |\n| **Audited least-privilege access controls** | The runtime continuation of the build-stage least-privilege wiring (SHIFT 5): every human and machine identity scoped from deny-all, and that access **logged and periodically re-reviewed** — not granted once and forgotten. | Catches privilege creep and the standing over-grant; the audit log of *who can reach the crown jewels* is itself a detection surface (an access that shouldn't be possible is an alert). | The agent's `*:*`-to-clear-an-error grant from build-time silently persists into production; without re-review, the over-grant becomes permanent attack surface. |\n\n> **The trap, stated sharply:** an advisory log nobody alerts on is the runtime twin of the `present-unenforced` status in [decision-tree.md](decision-tree.md) — it *looks* like monitoring and detects nothing, because no human or page ever reads it. A security log is only a control once an anomaly in it *fires*. Logging the failed-auth events and not alerting on a spike of them is logging the breach into a file no one opens.\n\n### How much detection — sized to risk\n\n**PREDICATE:** for this system's weight class (TREE 0), and for this specific attack signal, would the attack it detects reach a crown jewel or cross a trust boundary?\n**DEFAULT** on a coin-flip about whether to instrument a given signal: **instrument it** if it covers authentication, authorization, or crown-jewel data access — those are the highest-value attack surfaces and the cheapest to alert on; defer broad behavioral analytics and threat-intel feeds until the basics fire. A page-worthy detector on failed-auth spikes is worth more than a dashboard of fifty metrics nobody watches.\n**FALLBACK** when you can't tell whether a signal matters: log it now (logging is cheap and reversible) and treat the *alerting* threshold as a question to tune from real traffic — but never let \"we'll add detection later\" mean shipping a crown-jewel system with no attack alerting at all. An unmonitored production system defaults to \"the agent finds out about the breach when the customer does.\"\n\nThe same discipline the `gauge` skill applies to feedback applies here: the signal must be **legible, attributed, and hard to fake green**. An attack detection that the agent (or an attacker) can silence by tuning a threshold to nothing is not a detection — wire the alerting config under review, the same way the security-gate config is reviewed in [security-testing-and-gates.md](security-testing-and-gates.md), so it can't be quietly weakened.\n\n---\n\n## Vulnerability and patch management — a standing breach has a countdown\n\nThe code you wrote can be flawless and the system still becomes vulnerable overnight, because a vulnerability is disclosed in a *dependency* — a library, a base image, a runtime, the OS. This is the OWASP \"vulnerable & outdated components\" class, and at Operate it is not a one-time scan but a **continuous practice**. It is the `husbandry` skill's *don't-drift-to-EOL* in its security form, sharpened: where `husbandry` warns that an un-maintained system rots toward unsupportability, the security version is more urgent and more concrete — **a disclosed, unpatched known vulnerability in your stack is a standing breach with a public exploit clock running against it.** The CVE is published, the exploit is often public within days, and automated scanners are already sweeping the internet for the version you are still running. There is no \"looks fine so far\" here; the attacker has the same vulnerability database you do.\n\nThe agent failure mode this guards against is the *never patches* default. An upgrade is pure friction with no green reward — it can break a build, shift a behavior, demand a test run — so an agent operating the system will leave a known-vulnerable dependency in place indefinitely, because nothing about the running system turns red to demand the patch. The unpatched CVE is invisible to every functional test, exactly like every other vulnerability: it is the absence of an exploit *so far*.\n\nSo the practice is externalized into feeds and gates, not trusted to attention:\n\n- **Track disclosed vulnerabilities for your actual stack.** Subscribe the system's dependencies to the disclosure sources: **NVD / CVE feeds**, **GitHub security advisories** (and Dependabot/equivalent alerts on the repo), the security advisories of the specific frameworks and base images you run, and vendor bulletins. The point is to learn of a relevant CVE from the feed, not from the incident.\n- **Run SCA continuously, as a gate, not a one-off.** Software Composition Analysis (the `flightline` skill runs the pipeline; [security-testing-and-gates.md](security-testing-and-gates.md) defines what it must enforce) is not only a pre-merge check — it must run **on a schedule against what is deployed**, because a dependency that was clean when you merged becomes vulnerable the day a CVE against its version is published. A green SCA at merge time says nothing about its status next week.\n- **Patch promptly, on a cadence keyed to severity** (the PREDICATE/DEFAULT/FALLBACK below), and verify the patch — re-run the gates from [security-testing-and-gates.md](security-testing-and-gates.md) so the upgrade can't silently break a defense or fail a test the agent would then suppress.\n- **Rotate secrets on a schedule and on exposure.** Secrets do not expire on their own; a credential that has been live for two years has had two years of accumulated leak risk (a stray log, a former employee, a breached third party). Rotate the crown-jewel secrets on a cadence, and **immediately** on any suspected exposure — this is the runtime continuation of SHIFT 5's keep-secrets-in-a-manager, where the manager/vault is what makes rotation a config change rather than a redeploy.\n- **Re-review access periodically.** The same least-privilege audit from the runtime-defense table: walk *who and what can reach the crown jewels* on a cadence and revoke the access that no longer has a live justification. Permissions accrete; without a re-review they only ever widen.\n\n### Prioritizing a newly-disclosed vulnerability — patch now vs schedule\n\nNot every CVE is a 3am emergency, and an agent with no sense of proportion will treat them identically — either patching nothing (the default) or, told to \"patch vulnerabilities,\" thrashing the system with an emergency upgrade for a CVE in a code path you don't even reach. Triage by **exploitability** and **exposure**, the same two dials TREE 0 already sizes the whole defense on.\n\n- **PREDICATE:** is this vulnerability *reachable and exploitable in your deployment* — is the vulnerable code path exposed (especially internet-facing / on a trust boundary), is the data or capability behind it a crown jewel, and is exploitation easy or already public (a high CVSS, a known exploit in the wild, an actively-attacked CVE)?\n- **DEFAULT** on a coin-flip about whether a given CVE is \"patch-now\" or \"next cadence\": **patch now.** The asymmetry is the one that governs this whole skill — an out-of-band patch costs the agent some minutes and a gate re-run; an exploited standing breach of a crown jewel costs you the incident. When the exploitability or the exposure is in doubt, treat the vuln as exploitable and exposed.\n- **Patch-now** (out-of-band, today): exploitable *and* exposed — e.g. a remote-code-execution or auth-bypass CVE with a public exploit in an internet-facing component, or anything touching a crown jewel where exploitation is known to be trivial. Apply the patch (or, if no patch exists yet, mitigate: WAF rule, disable the feature, restrict the route, segment the network) immediately, and treat it as at least a low-severity incident.\n- **Schedule** (next patch cadence): low exploitability *and* low exposure — e.g. a CVE in a transitive dependency whose vulnerable function you don't call, in an internal-only service behind authentication, with no known exploit. Batch it into the regular dependency-bump cycle. Still patch it; \"scheduled\" is not \"ignored.\"\n- **FALLBACK** when you cannot determine reachability or exploitability yet (you can't tell if the vulnerable path is reached, or the CVE details are thin): treat it as **patch-now** until proven otherwise, and make the reachability assessment an explicit task — an un-triaged CVE in a crown-jewel system defaults to the agent's \"leave it,\" which is the failure mode. Where the call is genuinely contested (a disruptive emergency patch on a critical system, an accept-the-risk-and-wait decision), it climbs the [escalation ladder](agent-era-shifts.md#escalation-ladder--when-the-call-is-unclear): the user holds authority on what residual risk is acceptable and what an outage from a rushed patch would cost.\n\n> An unpatched known vulnerability and an un-rehearsed incident plan are **the same kind of standing risk** — a control you are *assuming* holds, sitting quietly in a green-looking system, waiting for the first real test to prove it never did.\n\n---\n\n## Security incident response — rehearsed, or it is not a plan\n\nThe breach you are not prepared for is the one that turns a contained intrusion into a catastrophe. Failure is not preventable here any more than anywhere else in the suite; *unpreparedness* is. The human-era bet was \"when we get breached, someone will figure out what to do\" — and a senior engineer who *remembered* the last incident often could. For an agent that bet is simply **false: nothing remembers.** The agent starts each session with no scars, cannot improvise a competent breach response from experience it does not have, and feels no dread that would make it escalate rather than experiment on a live, compromised system. So the incident-response plan must live in a **durable, rehearsed artifact outside any session** — this is the security face of the same externalization the `stationkeeping` skill applies to its incident process; the structure below is its security specialization, not a second copy of it.\n\nThe non-negotiable shape of the plan is the five phases, in order:\n\n| Phase | What it is | The agent default it forecloses |\n|---|---|---|\n| **Detect** | Recognize that an incident is happening — from the runtime-defense alerts above, a report, or a `gungnir` finding. Confirm it's real (not a false alarm) and declare a security incident, assigning severity. | Reading the quiet-after-the-spike as resolved; missing the attack because no signal was wired to fire. Detection is only possible if the monitoring above exists. |\n| **Contain** | Stop the bleeding *before* fixing the cause: isolate the affected systems, revoke compromised credentials, block the source, take the component offline if needed. Limit blast radius. | The agent's instinct is to jump straight to a clever fix on the live system; containment first is the discipline that keeps a breach from spreading while you work. |\n| **Eradicate** | Remove the attacker's foothold: close the actual vulnerability, remove planted malware/backdoors/web-shells, **rotate every credential that could have been exposed**, rebuild compromised hosts from a known-good state rather than cleaning in place. | Patching the symptom and leaving the foothold — declaring the page resolved while the attacker still has a way back in. |\n| **Recover** | Restore normal, verified-clean service: bring systems back from trusted backups/images, confirm the vulnerability is closed and the attacker is gone, monitor closely for re-entry. | Restoring service fast to get to green while the system is still compromised — recovery onto an un-eradicated foothold is a second breach. |\n| **Learn** | A **blameless postmortem**, with tracked action items that feed back into the controls — the detection that should have fired sooner, the missing patch, the over-broad grant the attacker used. | \"Ack and move on\" — silencing the alert and marking the incident resolved without surfacing what it exposed. |\n\n### Run the postmortem blameless — make the breach safe to surface\n\nThe learn phase carries the same non-negotiable property as every incident in this suite: the postmortem is **blameless** — it examines how the *system and process* let the breach happen and how to harden them, never how a person erred. This is not politeness; it is the only way to get *honest* information out of a breach. A blame culture makes people (and the agents built around anxiety about a bad-looking outcome) **hide the breach** — and a hidden breach is the worst possible outcome, because the intrusion continues, the foothold stays, and the same hole is exploited again with the evidence already buried. A blameless culture inverts this: surfacing a breach fast is *rewarded* because it makes the system safer, so breaches come to light early and cheap.\n\nThis is the exact principle the whole suite shares — the `gauge` skill's *fail loud, local, attributed*, the `flightline` skill's *red means stop*, and the `stationkeeping` skill's blameless postmortems: across the suite, the goal is to make failure **loud and safe to report** rather than quiet and shameful, and a green-looking system that is hiding a breach is far worse than a red one that is honest. The agent-era sharpening: an agent has no ego to bruise, but it shares the failure mode in a different costume — it will **paper over an incident to reach a resolved-looking state** (silence the alert, mark it acknowledged, declare the task done) rather than surface that the system was breached. The blameless security postmortem is the artifact that *requires* the breach to be written down, analyzed, and turned into tracked, owned changes — and it forecloses the \"ack and move on.\" An action item written but never closed is the postmortem's version of the unpatched CVE: a fix you are *assuming*.\n\n### Rehearse it — an untested plan is the untested-control trap\n\nA plan that has only ever been read is the security twin of the `stationkeeping` skill's untested-control trap and its `present-unexercised` status from [decision-tree.md](decision-tree.md): **an incident-response plan you have not rehearsed is not a plan, it is a wish.** The first time you discover that the runbook's \"rotate the credentials\" step doesn't actually work, that no one has the access to take the host offline, or that the escalation contact left the company, must not be during the real breach. So the plan must be **exercised** — a tabletop walkthrough of a plausible breach scenario, a drill that actually runs the containment and recovery steps in staging, and the relationship to `gungnir` below, which produces *real* findings to respond to.\n\n**PREDICATE:** has this incident-response plan been *exercised* — every phase walked, the containment and recovery steps actually run, the escalation path confirmed live?\n**DEFAULT** on a coin-flip about whether the plan is \"ready\": **treat it as not ready** and rehearse it before relying on it. The cost of a tabletop drill is an hour; the cost of discovering the plan is broken mid-breach is the breach getting away from you.\n**FALLBACK** when you cannot fully rehearse (no staging that mirrors prod, a step that can't be safely drilled): rehearse what you can, **explicitly mark the un-rehearsed steps as unproven**, and carry that as a known risk for the user to accept in writing — never report the plan ready because the *document* exists. A plan is `incident-response-ready` only when it has *worked* in a drill, not when it has been written.\n\n---\n\n## Security is never done — keep the defense honest after launch\n\nThe two checks above are not a pre-launch checkpoint you clear once; they are the start of a practice that runs for as long as the system does. This is the whole of **SHIFT 7**: new vulnerabilities are disclosed daily, every change the agent makes can open a fresh hole, and the attacker keeps probing — so a one-time hardening is stale within weeks, and \"we secured it at launch\" is the anti-pattern this stage exists to kill. The runtime-defense instrumentation and the continuous-patching cadence are how the *known* threats stay covered over time. But the defense also needs to be re-proven against the *unknown* and the *newly-introduced* — because a control that held against last quarter's system may not hold against the three features the agent shipped since, and a clean scan only ever means the known patterns weren't found.\n\nThat ongoing re-proving is **adversarial validation, and it is the `gungnir` skill's job.** The same hand-off that [security-testing-and-gates.md](security-testing-and-gates.md) makes at Verify continues into Operate as a *recurring* practice: schedule periodic penetration tests against the running system (a cadence keyed to the TREE 0 weight class — a HEAVY crown-jewel system earns regular professional pentests; a stand-up bug-bounty program turns the wider world of attackers into a continuous, paid signal). aegis is the shield; `gungnir` is the spear that proves the shield still holds after every change — and a defense that is never attacked after launch is a defense you are *assuming*, exactly the trap this skill exists to break. Where the periodic `gungnir` attack or a bug-bounty report surfaces a real flaw, it flows straight into the incident-response loop above (detect → contain → eradicate → recover → learn), and its fix flows back through the gates — closing the circle so the system that the next attacker meets is hardened by the last one.\n\n---\n\n## The two gates this file delivers\n\nThis reference is the depth behind the FINAL GATE in [../SKILL.md](../SKILL.md). The two checks, and what \"done\" means for each in agent-era terms:\n\n- **`runtime-defense-and-patching`** — The running system is **instrumented to make attack signals fire**, not to log them into a file no one opens: security-event logging (with PII/secrets redacted), detection and alerting on the attack anomalies (failed-auth spikes, unusual access, exfiltration), a WAF/rate-limit at the edge, and audited least-privilege access. *And* vulnerabilities are managed **continuously**: CVE/advisory feeds tracked for the actual stack, SCA run on a schedule against what's deployed, vulnerable dependencies patched promptly (patch-now vs schedule by exploitability × exposure), secrets rotated, access re-reviewed. Done means an attack in progress turns something red and a disclosed CVE is treated as the standing breach it is — not \"the dashboard is green and the dependencies were clean at merge.\"\n- **`incident-response-ready`** — Security incident response is **externalized into a rehearsed, durable artifact**: a known detect→contain→eradicate→recover→learn plan, severity-tiered with a live escalation path, run **blameless** so a breach surfaces fast instead of hiding, with postmortem action items that feed back into the detection, the patching, and the access controls. Done means the plan has *worked in a drill*, not \"we'll know what to do.\"\n\nFor both gates, the AUDIT-mode trap from [decision-tree.md](decision-tree.md) applies hardest: a security log nobody alerts on, a CVE feed nobody acts on, an IR plan never rehearsed — these are `present-unenforced` / `present-unexercised`, which count as **not done**. Never report either gate green because the artifact *exists*; report it green only because it has *worked* — an alert that caught a real probe, a patch shipped against a real CVE, a drill the IR plan actually survived. And because SHIFT 7 has no finish line, treat both as standing commitments the operating system must keep, with the `gungnir` skill attacking periodically to keep the whole defense honest. See [agent-era-shifts.md](agent-era-shifts.md) for *why* each move reads this way, and [../SKILL.md](../SKILL.md) for the stage order this closes.\n","principles-and-stance.md":"# Security Principles and the Stance That Sizes the Defense\n\nThis reference is the depth behind **STAGE 0 — Frame** of the [../SKILL.md](../SKILL.md) flight plan, the place where you set the security stance and size the defense to the risk *before* you model a single threat or write a line. It governs four things: the goal every defense ultimately serves (the **CIA triad**), what is actually worth defending (the **crown jewels** and a data classification that points the defense at what matters), the **timeless principles** you bind here and apply at every later stage, and the governing posture that turns \"build it secure\" from a virtue into the gate the rest of the skill inherits — security as **risk management**, not a quest for the absolute. The human-era→agent-era shift here is the root one: a human builder carried a flicker of defensive instinct as they coded, so a security review near the end was a backstop on mostly-careful work; the agent supplies no such instinct, writes the insecure pattern by default, and books \"it works\" as done over a system that was never secure to begin with. For *why* this is the spine of the whole skill — the felt risk that vanished, the bolt-on review that is now the *first* time anything checked security — read **SHIFT 1** in [agent-era-shifts.md](agent-era-shifts.md). This file is the *how*: how to set the goal, classify what matters, bind the principles, and hold the stance so two agents framing the same system reach the same plan.\n\nThe governing fact, inherited from [decision-tree.md](decision-tree.md) and overriding every default below:\n\n> **Security is woven in, never bolted on — and a vulnerability passes every green test, because it is the absence of an attack, not a failure.** Assume the attacker knows your system completely and that any single layer can fail.\n\nEverything in this file is a consequence of that sentence. The check this file delivers is `security-stance-set`: the crown jewels named and the data classified, the defense sized to the risk, the CIA goal internalized, and the timeless principles bound as the standard every later stage is judged against.\n\n---\n\n## Contents\n\n- [The goal every defense serves — the CIA triad](#the-goal-every-defense-serves--the-cia-triad)\n- [Crown jewels and data classification — point the defense at what matters](#crown-jewels-and-data-classification--point-the-defense-at-what-matters)\n- [The timeless principles — and the agent failure mode each guards](#the-timeless-principles--and-the-agent-failure-mode-each-guards)\n- [Security is risk management, not a quest for the absolute](#security-is-risk-management-not-a-quest-for-the-absolute)\n- [How the security line threads every sibling skill](#how-the-security-line-threads-every-sibling-skill)\n\n---\n\n## The goal every defense serves — the CIA triad\n\nBefore you can size a defense you need to know what \"secure\" even means for this system, and the answer is older than any framework: a system is secure to the degree it preserves three properties of its data and its service. Every threat you will enumerate at Model, every control you will design at Design, and every vulnerability class you will defend at Build is, at root, an attack on one of these three. Naming them at Frame gives the rest of the skill a target: a defense exists to protect a *named property of a named asset*, and a property you care about but cannot point to an enforced control for is, by definition, unprotected.\n\n| Goal | What it means | The attack it loses to | Where it's defended later |\n|---|---|---|---|\n| **Confidentiality** | Only those authorized can read the data — *don't leak.* | Information disclosure: the data is read by someone who shouldn't (a leaked key, PII in a log, an unencrypted channel, a broken access check). | Encryption in transit (TLS) and at rest, least privilege, no secrets/PII in logs, server-side authorization. |\n| **Integrity** | The data and the code are not altered by anyone unauthorized — *don't let it be tampered.* | Tampering: data changed in transit or at rest, a record forged, a transaction altered (the *T* and *R* of STRIDE). | Input validation, signing/HMAC, TLS, access control, audit logs for non-repudiation. |\n| **Availability** | The system is up and serving its authorized users — *don't let it be knocked down.* | Denial of service: the system is made unreachable or unusably slow (a flood, a resource-exhaustion input, a dependency taken out). | Rate limiting, quotas, input limits, autoscaling and redundancy (the `stationkeeping` skill's resilience). |\n\nThe triad is not academic decoration; it is the *coverage check* for a threat model. When you run STRIDE at Model ([threat-modeling.md](threat-modeling.md)), each STRIDE letter maps to a CIA property it violates — and if your defenses cover confidentiality and integrity but you never asked \"can this be knocked down,\" you have a blind spot the triad makes visible. The agent failure mode this guards against is the narrow one: an agent asked to \"make it secure\" reaches reflexively for confidentiality (encrypt the thing) and forgets that an unbounded input that exhausts memory is an availability breach, or that an unsigned update channel is an integrity breach. Frame the goal as all three, weighted to this system — a read-only public dataset prizes integrity and availability over confidentiality; a medical record prizes confidentiality above all — so the later stages defend the properties this system actually depends on, not just the one that comes to mind first.\n\n---\n\n## Crown jewels and data classification — point the defense at what matters\n\nAbsolute security is impossible and infinitely costly (the next section is the whole argument), so the first real move at Frame is to decide *where the defense goes*. That decision rests on naming the **crown jewels** — the handful of data assets and capabilities whose breach would actually hurt — and **classifying the data** so the defense concentrates on the sensitive and the regulated rather than spreading evenly over everything, which spreads thin over nothing.\n\n**Name the crown jewels first.** These are the data and capabilities most worth protecting and most likely to be attacked: the user PII and credentials, the payment data, the secrets and signing keys, the customer database, the admin capability that can act on every account, the money-movement path. A defense that protects the crown jewels well and the brochure copy lightly is correctly sized; one that hardens the static marketing page while the password store sits in plaintext has spent its budget exactly backwards. The agent failure mode this guards against: the agent has no sense of which asset matters, so left to itself it defends uniformly (or, worse, defends the thing it happened to be working on) and leaves the actual jewels exposed because nothing in the task pointed at them.\n\n**Then classify the data**, so every later stage knows how hard to defend each piece. A workable scheme — adapt the labels to the user's compliance regime, but keep the gradient:\n\n| Class | What it is | Defense it earns |\n|---|---|---|\n| **Public** | Intended for anyone — marketing copy, published docs, open data. | Integrity and availability (don't let it be defaced or knocked down); confidentiality is moot. |\n| **Internal** | Not secret, but not for outsiders — internal dashboards, non-sensitive operational data. | Access control to authenticated users; modest. |\n| **Sensitive** | Business-confidential — pricing, source, internal financials, trade secrets. | Encryption, tight access control, audit. |\n| **PII** | Personal data identifying a human — names, emails, addresses, behavior. | Encryption in transit + at rest, strict least-privilege access, minimization (collect/retain less), no PII in logs. |\n| **Regulated** | Data under a legal regime — payment data (PCI DSS), health data (HIPAA), EU personal data (GDPR), and the like. | The above *plus* the specific controls the regime mandates — which the **user must name**, because only they hold authority on which regime applies. |\n\nTwo rules ride on this classification. First, **PII and regulated data raise the whole system's weight class** — a system that touches them cannot be sized as Light no matter how simple it looks, because the cost of *their* breach (legal, regulatory, reputational) is categorical, not proportional. Second, **the agent will not ask which regime applies** — it has no concept that \"this is an email address\" means GDPR obligations or that \"this is a card number\" means PCI scope; that is a judgment only the user can price, so surface the data classification and the compliance regime as explicit questions for them, and record the answer.\n\nThis is the input to the risk sizer, not a duplicate of it. The crown jewels you name and the data you classify here feed directly into **TREE 0** in [decision-tree.md](decision-tree.md) — the *crown jewels × exposure × threat* dial that reads off how much defense the whole system earns (Light / Medium / Heavy). Run that tree; do not re-derive it here. This file's job is to make sure the dials it reads — *what is worth protecting* — are named honestly before the tree turns them into a floor.\n\n---\n\n## The timeless principles — and the agent failure mode each guards\n\nThese are the principles you **bind at Frame and apply at every later stage** — the standard the threat model is built against, the design is judged against, and the code is reviewed against. They are not new; the security canon has taught them for decades. What changed is that they were *cultural knowledge transmitted with a sense of why* — a human builder felt the danger of a homemade cipher, felt the laziness of `*:*`, felt the unease of trusting a raw input — and that felt sense is exactly what the agent does not have (this is **SHIFT 1**, and its corollaries SHIFT 3–5, in [agent-era-shifts.md](agent-era-shifts.md)). So each principle below is paired with the specific agent failure mode it now has to be *enforced against*, not merely taught. Set them here; the later references turn each into concrete mechanism.\n\n### Least privilege\n\nEvery identity, service, query, and credential gets **only the access it needs, and nothing more** — scoped from deny-all upward, not granted broadly and trimmed later (trimming never happens). The blast radius of any single compromised component is then bounded to what that one component could reach.\n\n- **The agent failure mode it guards:** the agent **over-grants to clear an error.** The instant an `AccessDenied` blocks it, the cheapest path to green is to widen the permission to `*:*` — and it feels none of the wrongness a human felt, so the over-broad grant ships as a standing breach. Least privilege has to be the *enforced default posture* and a permission-widening a reviewed change, never a quiet fix. Depth at [secure-coding.md](secure-coding.md) (the wiring) and [agent-era-shifts.md](agent-era-shifts.md) SHIFT 5.\n\n### Defense in depth\n\n**No single control is the whole defense.** Layer independent controls — network, application, data, identity — so that a breach of any one layer does not hand over the system, because every layer is assumed breachable. A WAF *and* input validation *and* parameterized queries *and* least-privilege DB access; not any one of them trusted alone.\n\n- **The agent failure mode it guards:** the agent **over-trusts its own structure** — a single check reads to it as \"secured,\" and it has no instinct that the one control it wrote will be bypassed. Defense in depth has to be designed in deliberately, because the agent's natural output is a single happy-path gate with nothing behind it. Depth at [secure-design.md](secure-design.md) and SHIFT 4.\n\n### Fail secure (default deny on error)\n\nWhen something goes wrong — an exception, a timeout, an unreachable auth service, an unparseable token — the system **defaults to *deny*, not allow.** An authorization service that is down must refuse access, not wave requests through; a validation that throws must reject the input, not skip the check. Security must hold *on the error path*, which is the path least tested and most attacked.\n\n- **The agent failure mode it guards:** the agent writes the **happy path** and treats the error path as cleanup, so its instinct on a failure is \"let it through so the feature keeps working\" — `except: pass` around an auth check, a fallback that grants on timeout. Fail-secure inverts that: the error path defaults closed. Depth at [secure-design.md](secure-design.md).\n\n### Minimize the attack surface\n\nThe most secure component is the one that **isn't there.** Expose the fewest endpoints, ports, features, and dependencies the system actually needs; turn off and *delete* what you don't use — the unused debug endpoint, the dead feature flag, the dependency pulled in for one call, the open port. Every exposed thing is something an attacker can probe and you must defend.\n\n- **The agent failure mode it guards:** the agent **adds, never subtracts.** It enables the extra option, leaves the scaffold endpoint in, keeps the dependency \"just in case\" — accreting surface with no felt cost, because removal earns no green reward. Minimizing attack surface is the deliberate subtraction the agent will never initiate. Depth at [secure-design.md](secure-design.md).\n\n### No security through obscurity\n\nA secret *design* is not a control. Assume the attacker **knows your system completely** — the source, the schema, the algorithm, the endpoints — and require that security holds anyway. \"They won't find the hidden endpoint / won't guess our token format / won't reverse our scheme\" is never a defense; the only thing that may be secret is a *key*, and keys are protected as secrets, not as obscure designs.\n\n- **The agent failure mode it guards:** this is the principle behind **never invent crypto.** The agent will cheerfully generate a homemade encryption routine, token scheme, or auth flow — it produces plausible code fast and feels none of the danger, and the homemade primitive *looks* fine and passes a functional test while its fatal flaw is invisible without an expert attacker. Because the attacker is assumed to know the design, only **public, audited primitives** — whose security holds *with* the design known — are safe. The build-vs-buy fork that operationalizes this lives in [decision-tree.md](decision-tree.md) (and depth at [secure-design.md](secure-design.md)); the rule it enforces: anything whose subtle flaw is an exploit — crypto, authentication, authorization, session, randomness — is **bought, not built** (OAuth/OIDC, a KMS, argon2/bcrypt, the platform's crypto), never a scheme the agent generated. See SHIFT 4.\n\n### Zero trust\n\n**Verify every access; trust nothing by location.** A request is not safe because it came from \"inside\" the network, from another service, or from a previously-authenticated session — every access is authenticated and authorized on its own merits, at the point it happens. The old castle-and-moat model (hard perimeter, soft trusted interior) fails the moment the perimeter is crossed once; zero trust assumes the interior is already hostile.\n\n- **The agent failure mode it guards:** the agent **trusts its input** — and \"internal\" input most of all. It treats a value from another service, an internal API, or its own earlier code as friendly and skips the check, which is exactly how a single foothold becomes lateral movement across the system. Zero trust makes \"never trust input, anywhere\" extend past the user to every boundary, internal ones included. This is **SHIFT 3**; depth at [secure-coding.md](secure-coding.md) and [threat-modeling.md](threat-modeling.md).\n\n> The thread tying all six together is the governing fact at the top of this file: **assume the attacker knows the design and any single layer can fail.** Least privilege bounds the blast radius when a layer fails; defense in depth gives you more layers; fail-secure makes the failure deny; minimize-surface gives the attacker less to fail you on; no-obscurity forbids relying on the attacker's ignorance; zero trust refuses the free pass of location. They are six faces of one assumption.\n\n---\n\n## Security is risk management, not a quest for the absolute\n\nThe single posture that prevents both failure modes at the edges of this skill — *under*-securing the system that matters and *over*-securing the one that doesn't — is to treat security as **risk management, not a quest for the absolute.** Absolute security is impossible (any layer can fail, the attacker always learns) and its pursuit is infinitely costly; a system defended against every conceivable threat regardless of likelihood is a system that never ships and bankrupts its budget on threats no one would mount. The discipline is the same *够用就好* / match-rigor-to-risk restraint the whole suite runs on, applied to defense: **identify what is most worth protecting and most likely to be attacked, and put the defense there.**\n\nThat is what TREE 0 in [decision-tree.md](decision-tree.md) operationalizes — the crown jewels and classification from above, crossed with exposure and threat, sized to a Light / Medium / Heavy floor. A static brochure site does not earn a threat model, hard auth, and a pentest; a payments service handling PII earns all three and more. Sizing *up* a brochure site wastes effort; sizing *down* a payments service banks a breach. Frame's job is to make that sizing explicit and honest, then let the floor it produces drive every later stage.\n\nTwo corollaries of \"risk management, not absolute\" govern *how* you spend the budget once it's sized:\n\n**Shift security left — DevSecOps.** Security is cheapest when caught early and most expensive when caught in production, the same \"catch it early, surface it cheap\" instinct the rest of the suite runs on (quality-left, red-means-stop). So the defense is woven through the lifecycle — a stance at Frame, a threat model at Model, controls at Design, secure code at Build, gates at Verify, defense and patching at Operate — rather than concentrated in one review near the end. The agent failure mode this guards: the agent equates green with done and would happily defer all of security to a final check, on a system whose every default was insecure — so the final check becomes the *first* time anything looked at security, and finds the expensive problems too late.\n\n**Why bolt-on security fails — architectural weaknesses can't be patched in.** This is the reason \"do it at the end\" is not merely inefficient but structurally broken. The most damaging weaknesses are *architectural* — a missing trust boundary, an authorization model that checks in the UI instead of the server, a design that mingles privilege levels, a data flow that carries PII where it shouldn't. Those are decided at design time, and once the system is built around them they cannot be patched in afterward, only **rebuilt.** A late security review on such a system finds a hole that is expensive or impossible to close — which is exactly why this skill front-loads Model and Design as gated stages: the cheap, high-leverage security work happens *before* the structure hardens, on paper, where it can still change the design. Bolt-on security fails because by the time you bolt it on, the holes worth worrying about are load-bearing.\n\n> **PREDICATE:** is a given defense earning its cost on *this* system — defending a named crown jewel against a plausible, material threat? **DEFAULT** on a coin-flip about whether a defense is worth it: size to the **higher** risk for anything touching data, money, safety, or compliance (an under-defended breach of regulated data is the catastrophic, irreversible error) and the lower risk elsewhere — the same asymmetry the [escalation ladder](agent-era-shifts.md#escalation-ladder--when-the-call-is-unclear) bottoms out in. **FALLBACK** when you can't size the risk yet (unknown data sensitivity, unclear exposure, undeclared compliance regime): assume **Medium**, and make the classification and the regime explicit questions for the user — an unsized system defaults to \"the agent secures it as little as the happy path required,\" which is precisely the failure mode this stance exists to prevent.\n\n---\n\n## How the security line threads every sibling skill\n\naegis is the **shield**, and it is cross-cutting by nature: security is not a stage that happens once but a *line that runs through every part of the lifecycle*, surfacing inside each sibling skill as that skill's security slice. Frame is where you confirm that line is live in each place — or find, in AUDIT mode, where it is only named. aegis owns the line and pulls the threads together; it does not replace the siblings' mechanics, it directs them toward defense.\n\n- **`groundwork`** — security shows up first as **non-functional requirements**: what data is sensitive, which compliance regime binds, what an outage or breach would cost, what \"secure enough\" means for this system. The crown jewels and data classification you name here trace back to requirements groundwork should already have pinned; where they're missing, that is a gap to surface to the user.\n- **`load-bearing`** — security becomes **trust boundaries and architecture**: where data crosses from less- to more-trusted, how privilege levels are separated, how the data model keeps PII contained. These are the architectural decisions that, if wrong, can't be patched in later — which is exactly why Design is gated. The threat model at Model consumes the boundaries `load-bearing` drew.\n- **`flightline`** — security becomes **blocking CI gates**: SAST (static source analysis), secret-scanning at commit time, and SCA (dependency/supply-chain scanning). `flightline` runs the pipeline; aegis defines what it must enforce. Advisory scans an agent can ignore are not gates.\n- **`assay`** — security becomes **security testing**: confirming each defense not only exists but is *tested* — that a hostile input is actually rejected, that a forged authorization request is actually denied. A vulnerability passes every functional test, so the test design has to deliberately include the adversarial case.\n- **`stationkeeping`** and **`husbandry`** — security becomes **runtime defense and continuous patching**: detection and alerting on attacks and anomalies (the security slice of `stationkeeping` observability), and tracking disclosed CVEs to upgrade vulnerable dependencies promptly (the security form of `husbandry`'s don't-drift-to-EOL — an unpatched known vulnerability is a standing breach).\n- **`gauge`** — security depends on the **legible, hard-to-fake signal** `gauge` engineers: a security gate is only a gate if it blocks and can't be quietly weakened, and a runtime attack is only caught if the signal that reveals it is clear rather than buried. The same \"green must mean what it claims\" discipline that `gauge` enforces is what keeps a security gate honest.\n\nAnd aegis is one half of a pair. A shield is only proven against a spear, so what aegis *builds*, the **`gungnir`** skill *attacks* — authorized penetration testing, the adversarial creativity that chains small flaws into a real exploit and abuses business logic, which no scanner and no functional test will ever find. Where this skill reaches the point that the right next move is to *attack* the system rather than defend it, it hands off to `gungnir` by name; this file and the references it links describe how to build the shield, not how to wield the spear. The two are the shield-and-spear pair: aegis owns the defensive line through the lifecycle, and `gungnir` is the sharpest spear thrown against the hardest shield to prove it holds.\n\nThe thread: for an agent the lever is the same as everywhere in the suite — every one of its defaults is the insecure one, and a vulnerability ships green and is reported as done, so security must be **woven in and gated**, not trusted to an instinct it does not have. That is the stance Frame sets and the gate `security-stance-set` enforces; carry the crown jewels, the classification, the CIA goal, and the six principles into STAGE 1, where the abstract attacker becomes a concrete threat model.\n","secure-coding.md":"# Secure Coding: Code That Never Trusts Input and Never Holds a Secret\n\nThis reference is the depth behind **STAGE 3 — Build** of the [../SKILL.md](../SKILL.md) flight plan, the stage where the threat model and the secure design become actual code. It governs two checks — [`input-never-trusted`](#1-never-trust-user-input--the-one-assumption-applied-everywhere) and [`secrets-and-least-privilege`](#5-secrets-never-in-code-and-never-in-logs--secrets-and-least-privilege) — and the human-era→agent-era shift underneath both: secure coding *was* discipline a good engineer mostly followed by reflex, feeling a flicker of unease pasting a raw user string near a SQL query or hard-coding a key; in the agent era there is no flicker, so the discipline has to become an enforced, reviewed-for rule. For *why* the work changes, read [agent-era-shifts.md](agent-era-shifts.md) — **SHIFT 3 (the agent trusts its input)** and **SHIFT 5 (the agent leaks secrets and over-grants)** are the two cards this file enforces. This file is the *how*: the concrete code-level moves that defend each class by construction.\n\nRestate the governing fact you carry into every line from [decision-tree.md](decision-tree.md):\n\n> **Security is woven in, never bolted on — and a vulnerability passes every green test, because it is the absence of an attack, not a failure.** Assume the attacker knows your system completely and that any single layer can fail. When a coding fork is a real toss-up, err toward the **fail-closed, validated, defended** option — the cost of validating safe input is nil; the cost of trusting hostile input is a breach.\n\nAnd the agent failure mode that runs under the whole file: **the agent reproduces the insecure pattern by default.** String-concatenated SQL, unescaped output, a hard-coded key, a `*:*` grant — it pattern-matches these out of its training distribution because the insecure version *works perfectly* until someone attacks it, and nothing turns red. The secure version is never the one that \"just happens\"; it is the one that must be written, and reviewed for.\n\n## Contents\n\n- [1. Never trust user input — the one assumption applied everywhere](#1-never-trust-user-input--the-one-assumption-applied-everywhere)\n- [2. Validate at the boundary: allowlist over denylist](#2-validate-at-the-boundary-allowlist-over-denylist)\n- [3. The OWASP Top 10 vulnerability → defense catalog (code-level how-to)](#3-the-owasp-top-10-vulnerability--defense-catalog-code-level-how-to)\n- [4. Injection and XSS in depth — the two highest-impact classes](#4-injection-and-xss-in-depth--the-two-highest-impact-classes)\n- [5. Secrets never in code and never in logs — `secrets-and-least-privilege`](#5-secrets-never-in-code-and-never-in-logs--secrets-and-least-privilege)\n- [6. Least privilege in the wiring — from deny-all](#6-least-privilege-in-the-wiring--from-deny-all)\n- [7. The build-stage review pass](#7-the-build-stage-review-pass)\n\n---\n\n## 1. Never trust user input — the one assumption applied everywhere\n\n> **Check: `input-never-trusted`. Governing shift: SHIFT 3.**\n\nSecure coding rests on one assumption applied *everywhere*: **never trust user input.** This is not a discipline followed on the paths that feel dangerous; it is a hard rule applied at every boundary the data crosses, because the agent — which treats every input as friendly by default, writing the path that works for the value it imagined — supplies no instinct to follow it selectively.\n\nThe non-obvious half is the *scope* of \"input.\" The agent's mental model of \"user input\" is a form field. The real definition is **any value that originated outside your trust boundary, or whose origin you cannot prove.** That includes, all equally hostile until validated:\n\n- form fields, URL/query/path parameters, request bodies (JSON, XML, multipart);\n- **HTTP headers** — `Host`, `Referer`, `X-Forwarded-For`, `User-Agent`, cookies — all attacker-controlled;\n- **data from another service** — a microservice response, a webhook, a message off a queue — your peer can be compromised or impersonated (this is the zero-trust core: a service boundary is a trust boundary);\n- **files** — an uploaded file's name, type, size, and *contents*; a config or data file whose provenance you can't vouch for;\n- **the database** — stored data that an earlier, less-careful path put there unvalidated (this is *stored* / second-order injection and XSS);\n- environment variables and CLI arguments in a multi-tenant or partially-trusted context.\n\n**The decision fork — is this input safe to use as-is?** (inherited from [agent-era-shifts.md](agent-era-shifts.md#shift-3--the-agent-trusts-its-input--never-trust-input-anywhere)):\n\n- **PREDICATE:** did this value originate inside your trust boundary and remain unmodified by anything outside it?\n- **DEFAULT** on a coin-flip: **treat it as untrusted** — validate it at entry and encode it at the dangerous sink. The cost of validating safe input is nil; the cost of trusting hostile input is an injection.\n- **FALLBACK** when you can't trace its origin: assume it crossed a trust boundary — validate at the point of use; an input whose provenance you can't prove is, by default, attacker-controlled.\n\nValidation is **not** the same as defense at the sink, and you do both. Validating shape at the boundary (this is a well-formed email, this is an integer in range) does not make a value safe to concatenate into SQL or drop into HTML — a perfectly valid name `Robert'); DROP TABLE students;--` passes an \"is this a plausible name\" check and is still an injection. So: **validate shape at the boundary AND defend by construction at the sink** (parameterize, encode, authorize). The two are layers, not substitutes — defense in depth at the code level.\n\nThe boundary-validation mechanics (parse-don't-assert, a typed model at the edge, `Any` contained to the adapter, failures attributed to the field) are the same machinery the `gauge` skill installs for legible feedback — there the goal is a clear signal, here it is a security boundary; the same `pydantic`/`zod` parse serves both. Lean on it; don't reinvent it.\n\n---\n\n## 2. Validate at the boundary: allowlist over denylist\n\nThe single most \u0069mportant choice *inside* validation is **allowlist (accept known-good) over denylist (block known-bad).** This is the agent's second trap after trusting input at all: asked to \"block SQL injection,\" it will reach for a denylist — strip `'`, reject the word `SELECT`, escape `<script>` — because a blocklist is the pattern its training data is full of, and it *looks* like it works against the examples in front of it.\n\n| | Denylist (block known-bad) | Allowlist (accept known-good) |\n|---|---|---|\n| **What it enumerates** | every bad input you can think of | the exact set of good inputs |\n| **Failure mode** | the one bad input you *didn't* think of — and the attacker's whole job is to find it | a legitimate input you forgot to allow — fails *closed*, visibly, safely |\n| **Direction of error** | fail **open** (miss a payload → breach) | fail **closed** (miss a case → a bug you fix) |\n| **Against an evolving attacker** | loses — new encodings, new payloads route around it (`SeLeCt`, URL-encoding, Unicode homoglyphs, double-encoding) | holds — the good set doesn't change when the attacker gets clever |\n| **Verdict** | a leaky supplement at best | **the default** |\n\n- **PREDICATE:** can you define the set of *acceptable* values (a regex of allowed characters, an enum of allowed options, a numeric range, a known list of allowed redirect hosts)?\n- **DEFAULT:** define it and **reject everything else.** A status field is one of `{pending, paid, refunded}` — an `Enum`, not a free string. A filename is `^[A-Za-z0-9_.-]+$` with no `/` or `..`. A redirect target is one of a fixed set of allowed URLs, not \"any URL starting with our domain\" (which `evil.com/?x=ourdomain.com` defeats).\n- **FALLBACK** when the input is genuinely free-form (a comment body, a display name): you can't allowlist the *content*, so you cannot rely on input validation to make it safe — you **must** defend it at every sink instead (output-encode it wherever it's rendered, parameterize it wherever it touches a query). Free-form input is exactly the case where boundary validation is insufficient and sink defense is mandatory.\n\nDenylist has a narrow legitimate use as a *supplementary* layer (a WAF rule, a profanity filter), never as the primary control. If the agent's defense against injection is \"we strip dangerous characters,\" that is the finding — the primary defense must be the allowlist plus the parameterized sink below.\n\n---\n\n## 3. The OWASP Top 10 vulnerability → defense catalog (code-level how-to)\n\nThe OWASP Top 10 is the canonical catalog of what goes wrong, and — read through SHIFT 3 — it is in large part the catalog of what happens when input is trusted that should not have been. The **vulnerability → defense table** lives in [decision-tree.md](decision-tree.md#the-owasp-class--defense-map-stage-34); do not duplicate it. Walk it there as the checklist; this section is the **code-level HOW to build each defense** so the agent writes the secure construction instead of the insecure default it would otherwise pattern-match.\n\n| Class | The agent's insecure default | The secure construction (the HOW) |\n|---|---|---|\n| **Injection** (SQL/NoSQL/command/LDAP) | concatenates input into the query/command string | **parameterized queries / prepared statements** — the driver sends code and data on separate channels, so input can never be parsed as SQL. For shells, call the program with an **argument array** (`subprocess.run([...], shell=False)`), never a built string; better, avoid the shell entirely. ORMs help **only** when you use their parameter binding — a raw-SQL `.execute(f\"...{x}...\")` escape hatch is injection again. See §4. |\n| **Broken access control** (IDOR, forced browsing) | checks authorization in the UI / trusts an ID from the request as the user's own | **enforce authz server-side on every request**, against the *authenticated* identity, not a client-supplied id. For object access (`GET /orders/{id}`) confirm *this user owns this object* — the agent's default `SELECT * FROM orders WHERE id = ?` skips the `AND owner_id = :current_user` and ships an IDOR. Deny by default; the UI hiding a button is not a control. See §6. |\n| **Cross-site scripting (XSS)** | drops user content into HTML unescaped (`innerHTML`, an unescaped template, `dangerouslySetInnerHTML`) | **context-aware output encoding** at render — HTML-body vs HTML-attribute vs JS vs URL vs CSS each need a different escaper; use the framework's auto-escaping templating and never bypass it. Add a **Content-Security-Policy** as the second layer so an injected script won't execute even if encoding is missed. See §4. |\n| **Cryptographic failures** (sensitive-data exposure) | sends/stores sensitive data in the clear; invents a cipher | **TLS in transit** (HTTPS everywhere, `HSTS`) and **encryption at rest** for sensitive data, using vetted primitives only — never an agent-generated scheme (the build-vs-buy fork lives in [decision-tree.md](decision-tree.md#the-build-vs-buy-decision-anything-security-critical); detail in [secure-design.md](secure-design.md)). Passwords are **hashed** with `argon2`/`bcrypt`/`scrypt`, never encrypted, never MD5/SHA-1. No secrets/PII in logs (§5). |\n| **Identification & auth failures** | rolls a homemade session/token scheme; no rate limiting | adopt a vetted auth framework and **OAuth/OIDC** for federation; rate-limit and lock out brute force; `HttpOnly` + `Secure` + `SameSite` cookies; expire and rotate sessions. This is a *design* decision — see [secure-design.md](secure-design.md) — that the build stage merely wires correctly. |\n| **CSRF** | state-changing endpoint trusts an authenticated browser request | **anti-CSRF tokens** (synchronizer token / double-submit) on state-changing requests, plus **`SameSite=Lax`/`Strict` cookies** as the modern baseline. Safe methods (`GET`) must stay side-effect-free. |\n| **Security misconfiguration** | ships default passwords, debug endpoints, verbose errors, public buckets | **secure defaults, reviewed** — change/disable defaults, turn off debug and directory listing in prod, return generic error messages (no stack traces to the client), lock down storage ACLs (no public bucket), set security headers. Minimize the attack surface: delete what you don't use. |\n| **Vulnerable & outdated components** | pulls a dependency with a known CVE | **SCA scanning** gated in CI and **prompt patching** — the `flightline` skill runs the scan, the `husbandry` skill drives the upgrade cadence; the build stage's job is to not *introduce* a known-vulnerable version and to pin via lockfile. |\n| **Security logging & monitoring failures** | logs nothing security-relevant (or logs secrets) | emit **security-event** logs (authn/authz decisions, denials, anomalies) — *without* secrets or PII (§5) — for the `stationkeeping` skill's detection. Absence of logging is why a breach goes unnoticed. |\n| **SSRF** | fetches a URL built from user input against no allowlist | **allowlist the outbound targets** — validate the destination against a fixed set of permitted hosts/schemes, block requests to internal/link-local ranges (`169.254.169.254`, `127.0.0.0/8`, RFC-1918), resolve-then-check to defeat DNS rebinding, and segment the network so the fetcher can't reach internal services. A denylist of \"bad\" IPs loses (§2); allowlist the few you actually call. |\n\nThe thread, again: **injection, XSS, broken access control, and SSRF are all the same root — input that was trusted when it should have been validated, encoded, or authorized.** Defend each by construction here; in [security-testing-and-gates.md](security-testing-and-gates.md) you confirm each is *tested*, and you hand the adversarial attempt — chaining these into a real exploit, abusing business logic the scanners can't see — to the `gungnir` skill.\n\n---\n\n## 4. Injection and XSS in depth — the two highest-impact classes\n\nThese two are SHIFT 3 made concrete: the agent trusting input near the two most dangerous sinks. They deserve the depth because they are the most prolific *and* the ones the agent's defaults get most reliably wrong.\n\n**Injection — parameterize, never build the query string.** The rule is absolute: **input never becomes part of the query/command text.** A parameterized (prepared) statement sends the query structure to the engine once, then binds the data values separately, so a value can *never* be reinterpreted as code — `'; DROP TABLE` arrives as a literal string to compare against, not as SQL to run.\n\n```python\n# INSECURE — the agent's default: input is concatenated INTO the SQL text.\n# A username of  ' OR '1'='1  rewrites the query; this is SQL injection.\ncur.execute(f\"SELECT * FROM users WHERE name = '{name}' AND pw = '{pw}'\")\n\n# SECURE — parameterized: name/pw are bound as DATA, never parsed as SQL.\ncur.execute(\"SELECT * FROM users WHERE name = %s AND pw = %s\", (name, pw))\n```\n\nThe same rule across sinks: an **OS command** is run as an argument array with the shell off (`subprocess.run([\"convert\", user_path, out], shell=False)`), never `os.system(f\"convert {user_path} ...\")`. A **NoSQL** query passes a typed value, never a user-controlled operator object (`{\"$where\": userInput}` is injection). An **ORM** is safe only through its binding API — `User.objects.filter(name=name)` is fine; its raw-SQL escape hatch with an f-string is not. There is no \"escaping\" path you should hand-roll: escaping is error-prone and parameterization makes it unnecessary. If the agent wrote an escaper for SQL, that is the finding — replace it with a prepared statement.\n\n**XSS — context-aware output encoding plus CSP.** XSS is the dual of injection at the *output* boundary: user content rendered into a page where the browser executes it as script. The defense is to **encode for the exact context** at render time, because the escaping differs by where the value lands:\n\n| Context | Example sink | Correct encoding |\n|---|---|---|\n| HTML element body | `<div>{{ value }}</div>` | HTML-entity encode (`<`→`&lt;`) |\n| HTML attribute | `<img alt=\"{{ value }}\">` | attribute-encode + always quote the attribute |\n| JavaScript | `<script>var x = {{ value }}</script>` | JS-string/JSON encode — or better, don't inject into JS; pass via a `data-` attribute |\n| URL / query | `<a href=\"/p?q={{ value }}\">` | URL-encode, and validate the scheme (`javascript:` is XSS) |\n\nIn practice: **use the framework's auto-escaping templating and never bypass it** — modern templates (Jinja2 autoescape, React JSX, Angular) encode by default; XSS shows up exactly where the agent reaches for the bypass (`innerHTML`, `dangerouslySetInnerHTML`, `mark_safe`, `|safe`, `v-html`). Treat any such bypass on user-derived content as a finding. Layer a **Content-Security-Policy** (`script-src 'self'`, no inline script) so that even a missed encoding cannot execute an injected script — defense in depth, the design's `fail-secure` reaching the response. Remember **stored XSS**: content read back from the database is still untrusted and must be encoded on output, even though it \"came from us.\"\n\n- **PREDICATE for any sink:** is a value that crossed a trust boundary about to be interpreted (as SQL, as a command, as markup, as a URL scheme)?\n- **DEFAULT:** make it impossible to interpret it as code — parameterize (data channel) or context-encode (escaped text). Never rely on having cleaned the input upstream.\n- **FALLBACK** when you can't tell whether the framework auto-defends this sink: assume it does **not**, encode/parameterize explicitly, and let the `gungnir` skill try to inject anyway — a clean attempt is the evidence, not your assumption.\n\n---\n\n## 5. Secrets never in code and never in logs — `secrets-and-least-privilege`\n\n> **Check: `secrets-and-least-privilege`. Governing shift: SHIFT 5.**\n\nA secret is anything that grants access if leaked: API keys, DB passwords, private keys, tokens, signing keys, connection strings. The agent feels **no wrongness** putting one in the most convenient place — and the two most convenient places are the source file and the log line, because both make the thing *work right now* and neither turns anything red.\n\n**Never in code (or an image layer, or a committed config).** Secrets are **injected at runtime from a secrets manager / vault** (HashiCorp Vault, AWS Secrets Manager / SSM Parameter Store, GCP Secret Manager, a sealed Kubernetes secret) — the running process reads the secret from the environment or fetches it at startup; the secret never appears in the repository, the Dockerfile, or a baked image layer.\n\n```python\n# INSECURE — the agent's default: a real key, hard-coded, to make it work now.\nSTRIPE_KEY = \"sk_live_<a-real-key-pasted-right-here>\"\n\n# SECURE — injected at runtime from the environment, populated by the secrets manager.\nSTRIPE_KEY = os.environ[\"STRIPE_KEY\"]   # absent → fail loud at startup, not a default\n```\n\nThis is a **defense in depth** across three skills, and you must name and lean on all three rather than rely on this single layer:\n\n- the **`flightline`** skill runs a **secret-scanning gate** that blocks the *commit* (so a hard-coded key never lands in history — and if one did, it must be rotated, because git history is forever);\n- the **`stationkeeping`** skill **redacts** secrets and PII from telemetry (so a logged token never reaches the log store) — the same redaction the `gauge` skill wires into structured failures;\n- this stage keeps secrets out of the *running code and the log statements you write* in the first place.\n\n**Never in logs.** The other half of SHIFT 5: to debug, the agent will `log.info(f\"request: {request}\")` and dump the whole payload — auth header, password, full PII — because it works and produces no red. The rule: **never log a password, token, key, or PII.** Log an *identifier* (a user id, a request id), never the credential or the personal data; redact at the logging boundary; and treat a verbose \"log the whole request/response\" as a finding. A secret in a log is a secret in plaintext in every place that log is shipped, indexed, and retained.\n\n- **PREDICATE:** is this value a credential, key, token, or personal data?\n- **DEFAULT:** it comes from the secrets manager at runtime and is **never** written to a log or an error returned to a client.\n- **FALLBACK** when you're unsure whether a field is sensitive (a free-form blob, an opaque token from a partner): treat it as sensitive — redact it from logs and keep it out of source. The cost of redacting a non-secret is nil.\n\nIn review, **a hard-coded secret or a logged credential/PII is a blocking finding** — not a cleanup-later note.\n\n---\n\n## 6. Least privilege in the wiring — from deny-all\n\nThe second half of `secrets-and-least-privilege`, and the second half of SHIFT 5: the agent's reflex to **widen a permission to `*:*` the moment an `AccessDenied` blocks it**, because the broad grant clears the error and ships green and feels like nothing went wrong. Least privilege has to be the *default posture of the wiring*, not a norm you trust.\n\nEvery identity, credential, and grant is scoped **from deny-all to exactly what a real, demonstrated use needs**, across every layer the agent wires:\n\n| The wiring | Over-grant the agent reaches for | Least privilege |\n|---|---|---|\n| **Database user** | the app connects as `root`/`admin`/owner | a role with only the tables and operations it uses (`SELECT, INSERT` on the few tables it touches; no `DROP`, no other schemas) — so an injection can't escalate to the whole database |\n| **Service account / IAM role** | `Action: \"*\"`, `Resource: \"*\"` to clear an `AccessDenied` | the specific actions on the specific resources, scoped tightest where it touches crown jewels |\n| **API scope / token** | a broad token that can do everything | the minimal OAuth scopes for the operation; short-lived, audience-restricted |\n| **File / object permissions** | `chmod 777`, a world-readable / public bucket | the narrowest mode and owner; private storage by default |\n| **Network** | open egress / a flat network | segment so a component can reach only the peers it must (this is what contains the SSRF in §3) |\n\nThe corrective move when an `AccessDenied` appears is fixed and must replace the agent's reflex: **narrow the need, don't widen the grant.** Find the one action and one resource that failed and add exactly that, treating the change as a *reviewed* permission delta — never a quiet `*:*` to make the error go away. Least privilege is also what bounds the blast radius when another layer fails: a SQL injection through an over-privileged DB user is a full-database compromise; through a least-privileged one it is limited to a few tables. That is defense in depth — you assume the upstream control can be breached and make the breach small.\n\n- **PREDICATE:** does this identity/credential *demonstrably need* this permission for a real path?\n- **DEFAULT:** grant only what a real use proves necessary, starting from deny-all.\n- **FALLBACK** when you can't yet tell which narrow permission a path needs: start denied, run the path, and add **exactly** the permission the failure names — never a wildcard placeholder you intend to \"tighten later\" (you won't, and it ships).\n\nIn review, **a `*:*` grant, an admin-level DB connection, or a world-readable resource is a blocking finding.**\n\n---\n\n## 7. The build-stage review pass\n\nBecause the agent writes the insecure pattern by default, the secure version is the one that must be **reviewed for** — a vulnerability produces no red, so a green build certifies nothing here. Run this scan as you finish the stage; each line maps to a default the agent will have reached for. The checks named are the contract; this list is how you satisfy them before the GATE.\n\n- **Every external input** (form, param, header, body, file, inter-service, stored data) is validated at its boundary, **allowlist** not denylist, and defended again at each sink. → `input-never-trusted`\n- **Every query** is parameterized; **no** string-built SQL/command anywhere; no hand-rolled escaper. → `input-never-trusted`\n- **Every output** of user-derived content is context-encoded; no `innerHTML`/`|safe`/`dangerouslySetInnerHTML` bypass on untrusted data; a CSP is set. → `input-never-trusted`\n- **Authorization is server-side on every request** against the authenticated identity, with object-ownership checks (no IDOR); deny by default. → `input-never-trusted`\n- **No secret in code, config, or an image layer**; every secret injected from the manager at runtime; the `flightline` secret-scan gate is on. → `secrets-and-least-privilege`\n- **No credential or PII in any log** or client-facing error; redaction at the logging boundary; `stationkeeping` telemetry redaction relied on, not duplicated. → `secrets-and-least-privilege`\n- **Least privilege everywhere** — DB user, service account, API scope, file mode, network egress all scoped from deny-all; no `*:*`, no admin-by-default, no public bucket. → `secrets-and-least-privilege`\n\nWhen a call inside any fork above is a genuine toss-up, take the [escalation ladder](agent-era-shifts.md#escalation-ladder--when-the-call-is-unclear): make the safe choice the default (validate, deny, parameterize, redact), have it attacked (a SAST/DAST run, or the `gungnir` skill in staging), and escalate the residual to the user in writing rather than guessing — a wrong security guess is a breach, not a bug.\n\n---\n\n**Cross-links:** [agent-era-shifts.md](agent-era-shifts.md) (SHIFT 3 and SHIFT 5 — *why* the work changed) · [decision-tree.md](decision-tree.md) (the OWASP class→defense map and the build-vs-buy fork this file builds on) · [secure-design.md](secure-design.md) (the authn/authz, fail-secure, and never-invent-crypto decisions this stage wires) · [threat-modeling.md](threat-modeling.md) (the map of what to defend) · [principles-and-stance.md](principles-and-stance.md) (least privilege and defense in depth as principles) · [security-testing-and-gates.md](security-testing-and-gates.md) (confirming each defense is *tested*, and the hand-off to `gungnir`) · [operate-and-respond.md](operate-and-respond.md) (the running-system half) · [../SKILL.md](../SKILL.md) (the six-stage flight plan this stage serves).\n","secure-design.md":"# Secure Design — Build the Defenses Into the Structure\n\nThis reference is the depth behind **STAGE 2 — Design** of the [../SKILL.md](../SKILL.md) flight plan, the stage where the threat model becomes structure: authentication and authorization that are designed rather than improvised, the trust boundaries from the model turned into enforced controls, defense in depth layered so no single bypass is game-over, a system that fails secure, secure defaults, and the hard rule that you never invent crypto or a core security primitive. Design is the highest-leverage and most dangerous security stage, because **the worst weaknesses are architectural — they cannot be patched in later, only rebuilt.** A late check finds an architectural hole only when it is expensive or impossible to fix; the design stage is where the most damaging holes are either prevented or created.\n\nThe human-era → agent-era shift this file governs: a good engineer felt the danger in a homemade auth scheme and reached for the vetted library, understood roughly that one defense is not enough, and knew \"no one will figure out our trick\" is not security. None of those instincts survive contact with an agent. The agent will **cheerfully generate a custom encryption routine, a homemade token scheme, or a bespoke auth flow** — it produces plausible code fast and feels none of the danger — and it **over-trusts its own structure**: a single check reads to it as \"secured.\" See [agent-era-shifts.md](agent-era-shifts.md), **SHIFT 4 (the agent invents crypto and over-trusts its own design)**, for *why* this is structural; this file is the *how*. It backs one gate:\n\n- **`defenses-and-trust-boundaries`** — vetted crypto/auth (never invented), authorization enforced server-side on every request, defense in depth, fail-secure, secure defaults, and minimized attack surface, all assuming the attacker knows the design.\n\nThe governing fact this stage inherits from [decision-tree.md](decision-tree.md), which overrides every default below:\n\n> **Security is woven in, never bolted on — and a vulnerability passes every green test, because it is the absence of an attack, not a failure.** Assume the attacker knows your system completely and that any single layer can fail. When a design fork is a real toss-up, err toward the **fail-closed, vetted, defended** option.\n\nDecision forks here use the same engine as the rest of the suite — **PREDICATE** (the question that selects the branch), **DEFAULT** (what to pick on a coin-flip), **FALLBACK** (what to do when you cannot answer yet). When a fork won't resolve, climb the [escalation ladder](agent-era-shifts.md#escalation-ladder--when-the-call-is-unclear).\n\n---\n\n## Authentication vs authorization — two distinct decisions, both designed\n\nThese are routinely conflated, and conflating them *is* a vulnerability. They answer two different questions:\n\n| | **Authentication (authn)** | **Authorization (authz)** |\n|---|---|---|\n| Question | **Who are you?** Prove your identity. | **What may you do?** Decide if *this* identity may take *this* action on *this* resource. |\n| STRIDE threat it counters | **S**poofing | **E**levation of privilege |\n| Happens | once per session, at the edge | **on every request**, at every protected action |\n| Gets it wrong | impersonation, account takeover | broken access control / IDOR — the most common serious web vuln |\n| You design it with | a vetted identity framework (OAuth/OIDC + an IdP), MFA, secure sessions | a server-side check against the *actual* user, deny-by-default |\n\nA system can have flawless authentication and still be wide open: it knows exactly who you are and lets you read everyone else's records anyway. Design the two separately, and never let one stand in for the other.\n\n### Authentication — adopt a framework, never hand-roll the flow\n\n**Authentication is a buy, never a build** (see [the build-vs-buy fork below](#never-invent-crypto-or-a-core-security-primitive)). The agent failure mode here is direct: asked to \"add login,\" an agent will *invent* a credential-checking and session flow that looks fine and passes a functional test, with subtle fatal weaknesses (timing leaks, missing rate limits, weak session tokens, no MFA path) invisible without an expert attacker.\n\n- **Identity via a vetted framework / provider** — **OAuth 2.0 / OIDC** against a real identity provider (your IdP, or a managed service), or a battle-tested auth library for the platform. The framework owns the protocol; you own the configuration.\n- **Password storage, if you must store passwords at all, uses a slow, salted password hash** — **argon2** (preferred), **bcrypt**, or **scrypt** — never a fast general-purpose hash (MD5/SHA-x), never plaintext, never reversible encryption. The agent will reach for the fast hash because it \"hashes the password\" and the test passes; the weakness only appears under an offline cracking attack. (This is the same never-invent-crypto rule applied to the most common primitive.)\n- **MFA where the crown jewels earn it** (TREE 0 Medium/Heavy) — a second factor for privileged or sensitive accounts.\n- **Secure session management** — session tokens that are high-entropy, server-validated, rotated on privilege change, and expiring; transported in cookies marked `HttpOnly`, `Secure`, and `SameSite` (the cookie hardening detailed in [secure-coding.md](secure-coding.md) for CSRF). A session that never expires and a token guessable across users are both designed-in holes.\n\n### Authorization — enforced server-side, on every request, against the actual user\n\nThis is the single defense an agent most reliably gets wrong, because the insecure version *works on the happy path*. The rule is absolute:\n\n> **Every protected action checks authorization server-side, on every request, against the identity actually making the request — and denies by default.**\n\nThree failure modes to design out, each a form of **broken access control** (OWASP) and each one an agent writes by default:\n\n- **Hiding a UI control is not authorization.** Removing a button, greying a menu, or omitting a link from the page changes only what the *cooperative* user sees. The attacker calls the endpoint directly. If the server does not re-check, the action goes through. *Never gate access by hiding a control — gate it in the handler.*\n- **IDOR (Insecure Direct Object Reference)** — the handler trusts an identifier from the request (`/invoice/1043`, `account_id` in the body) and returns or mutates that object *without checking the requesting user owns or may access it*. The agent writes \"fetch object by id and return it\" because that is the obvious path and it is correct for the user it imagined. Defense: **every object access is scoped to the authenticated principal** — the query itself filters by owner/tenant, or an explicit ownership check precedes the action. Authorize the *(user, action, object)* triple, never just the action.\n- **Forced browsing / missing function-level authz** — an admin or internal endpoint with no authz check because \"only admins know the URL.\" Obscurity is not a control (the design is assumed known). Every endpoint declares who may reach it; an endpoint with no explicit authz is a hole.\n\n**Decision fork — does this request reach a protected action?**\n- **PREDICATE:** does this handler read, mutate, or trigger anything that is not public to every anonymous caller?\n- **DEFAULT** on a coin-flip: **treat it as protected** — require an authenticated principal and check authorization server-side against the specific object. The cost of an over-checked public read is negligible; the cost of an under-checked private action is broken access control.\n- **FALLBACK** when you can't tell who should be allowed: **deny-by-default** and make \"who is authorized for this\" an explicit question for the user — they hold the authority on what data matters. Do not ship an open endpoint while you decide.\n\nA useful litmus for the gate: a test that takes user A's session and tries to read user B's object must get **403/404, not 200**. If no such test exists, the authz control is `claimed`, not `enforced` (the status taxonomy in [decision-tree.md](decision-tree.md)) — and a UI-only check is `present-unenforced`, the most dangerous status of all.\n\n---\n\n## Enforce the trust boundaries the threat model drew\n\n[threat-modeling.md](threat-modeling.md) produced a map: the **trust boundaries** (every place data crosses from less-trusted to more-trusted) and the **attack surface** (every exposed endpoint, port, input, dependency). STAGE 1 *found* them; STAGE 2 *enforces* them. A boundary that is drawn on a diagram but not realized as a control in the structure is decoration — and the agent, having no attacker in its head, will pass data across a boundary unchecked because the data was correct for the cooperative caller it imagined.\n\nFor each boundary the model marked, the design must place an enforced control on the trusted side:\n\n- **At the network/process edge** — authentication and input validation happen *as data enters the more-trusted zone*, not deep inside where the code already assumed it was clean. Validate at the boundary (depth in [secure-coding.md](secure-coding.md)); the design's job is to ensure there is a single, unavoidable place that validation lives.\n- **Between services** — a request arriving from another internal service is still crossing a boundary if that service is less trusted or independently reachable. **Zero trust**: do not grant a request more authority because of *where* it came from; authenticate and authorize service-to-service calls too. \"It's internal\" is not a trust decision an agent should make for you.\n- **Into a dangerous sink** — the boundary just before a SQL query, a shell, an HTML response, or an outbound request (SSRF) is where input stops being data and can become code. The design ensures the sink is reached only through a safe construction (parameterized query, encoder, allowlist) — covered in [secure-coding.md](secure-coding.md); the design names *which* sinks exist and *which* boundary guards each.\n\nThe enforced control on every boundary makes \"trust boundary\" executable rather than a comment, the way the threat model intended.\n\n---\n\n## Defense in depth — layer independent controls, assume every layer breaches\n\n**No single control is the whole defense.** Design so that a bypass of any one layer is not game-over — every layer is assumed breachable, because the governing fact says any single layer can fail. This is the structural antidote to the agent's over-trust in its own design: it reads a single check as \"secured\" and has no instinct that the one check might be wrong, disabled, or bypassed.\n\nThe discipline that makes layering *real* rather than redundant: the layers must be **independent** — a single mistake, a single shared assumption, must not defeat all of them at once. Two checks that both call the same flawed `is_authorized()` are one layer wearing two hats.\n\nA worked example — protecting a sensitive record — shows independent layers stacking, each assuming the one outside it failed:\n\n| Layer | Control | What it assumes failed above it |\n|---|---|---|\n| Network | the data store is not publicly reachable; segmented | the app could be compromised |\n| Authentication | the request carries a valid, current identity | a token could be stolen |\n| Authorization | server-side check that *this* user may access *this* record | authn could be spoofed |\n| Data | the query is scoped to the owner/tenant; row-level isolation | the authz check could be wrong |\n| At-rest | the field is encrypted; the key is in a KMS | the store could be exfiltrated |\n| Detection | access is logged and anomalies alerted (`stationkeeping` slice) | every control above could be silently bypassed |\n\nEach layer is independently sufficient to stop *some* attacks and independently insufficient against all; together they mean an attacker must defeat several unrelated controls, and a defender gets a signal (the detection layer) even when the preventive ones fail.\n\n**Decision fork — does this control need a second, independent layer behind it?**\n- **PREDICATE:** if this single control is bypassed (a bug, a misconfig, a stolen credential), is a crown jewel directly exposed?\n- **DEFAULT** on a coin-flip: **add the independent layer** — the cost is a little structure; the cost of a single-point-of-failure on a crown jewel is the breach.\n- **FALLBACK** when you can't tell what's behind it: assume nothing is, and design the next layer in; an undetermined depth defaults, for an agent, to \"one check, and it's fine.\"\n\n> The point of layering is not paranoia for its own sake — it is sized to risk (TREE 0 in [decision-tree.md](decision-tree.md)). A Light system earns one solid layer on the boundary; a Heavy system earns the full stack, proven. Match the depth to the crown jewels, *够用就好*.\n\n---\n\n## Fail secure — on error, default to deny\n\nWhen something breaks — an exception, a timeout, a dependency outage, an unparseable input — the system must default to **deny, not allow**. This is **fail-closed**, and it is a design property of the control flow, not an afterthought you add in a `catch`.\n\nThe canonical case: **an authorization or authentication service that is down must refuse access, not wave it through.** The insecure version — `try { return authz.check(user, obj) } catch { return true }` — is exactly what an agent writes to \"make the error go away,\" because returning `true` clears the exception and the happy path keeps working. It is a standing breach: every outage of the auth service becomes an open door. The fail-secure version returns *deny* on any failure to *prove* allow.\n\nDesign fail-closed as a structural default:\n\n- **The trusted branch is reachable only when the check explicitly returned ok.** No code path lands on \"allowed\" by falling through, timing out, or catching an error. Where the platform allows it, make the unverified state *un-representable* — the type or the control flow does not offer an \"allowed\" value unless a successful check produced it — so an agent cannot accidentally route around the check (this is the legible-failure discipline the `gauge` skill installs, in its security form).\n- **Errors deny and are logged**, not swallowed into a permissive default. A denied request on a transient failure is a momentary annoyance; an allowed request on a failure is an exploit.\n- **The one deliberate exception is availability-of-the-non-sensitive** — a read-only public enrichment path may degrade-and-serve rather than hard-fail, because nothing protected rides on it. *Anything touching auth, money, or data integrity fails closed.* When the policy for a dependency is unclear, fail closed.\n\nThis is the design echo of the [decision-tree.md](decision-tree.md) rule \"deny over allow, validate over trust\" — applied to the *failure* path, which is the path the agent never designs because the failure is invisible to a passing test.\n\n---\n\n## Never invent crypto or a core security primitive\n\nThe most dangerous single fork at this stage, and the one **SHIFT 4** names directly: the agent will invent a cipher, a token scheme, a signature check, or a randomness source without fear, because the homemade version *looks* fine and passes a functional test. This fork lives in full in [decision-tree.md](decision-tree.md) (the build-vs-buy decision) — cross-link there, do not re-derive it. The depth that belongs here is the **why** and the **what**.\n\n**The PREDICATE** (from that fork): is this crypto, authentication, authorization, session management, password storage, tokens, or randomness — *anything whose subtle flaw is an exploit?* If yes, **buy/adopt a public, audited, widely-used implementation; never the agent's homemade version.** **DEFAULT** on \"is it security-critical enough?\": **buy.** **FALLBACK** when no vetted option seems to fit: that almost always means the need is mis-scoped — re-frame to a standard one before ever hand-rolling, and escalate to the user rather than invent.\n\n**The why — what makes this category special.** For ordinary application logic, a functional test that passes is strong evidence the code is right. For a security primitive, **it is no evidence at all.** The space of subtle, exploitable mistakes is *vast and invisible to a functional test*: a constant-time comparison that isn't, a nonce reused, an IV that's predictable, a padding oracle, an `alg:none` accepted, a signature checked against the wrong key. The homemade primitive encrypts, the token round-trips, the login succeeds — and it fails only against an expert attacker probing exactly the failure mode the author never imagined. You will not out-design the cryptographic community, and an agent — which feels none of the danger and has no attacker in its head — certainly will not. This is also why the rule ties straight to **no security through obscurity**: the design is assumed known to the attacker, so a scheme that is only safe while secret is not safe; a publicly-audited primitive is one whose security holds *with the design fully known*, which is the only kind that holds at all.\n\n**The what — adopt these, forbid the homemade version:**\n\n| Need | Adopt (audited) | The homemade version an agent writes |\n|---|---|---|\n| Encrypting data / managing keys | a **KMS** / the platform's vetted crypto library (libsodium, the language's standard crypto) | a custom cipher, a hard-coded key, ECB mode, a reused IV |\n| Password storage | **argon2 / bcrypt / scrypt** (slow, salted) | a fast hash (SHA-256), unsalted, or \"encrypted\" |\n| Authentication / identity | **OAuth 2.0 / OIDC** + a real IdP, a vetted auth library | a bespoke login + token flow |\n| Authorization | a **vetted authz framework** / policy engine, server-side | scattered ad-hoc `if user.role ==` checks |\n| Transport security | **TLS** via the platform (never `verify=False`) | plaintext \"internal\" traffic, disabled cert checks |\n| Tokens / signatures | a standard library for JWT/HMAC/signing | a string concatenated with a \"secret\" and base64'd |\n| Randomness for security | the **CSPRNG** (`secrets`, `crypto.randomBytes`, `/dev/urandom`) | `rand()` / `Math.random()` / a timestamp |\n\n**At the gate:** if the agent wrote a crypto, auth, authz, session, token, or randomness primitive, *that is the finding* — replace it with the adopted standard. A self-written security primitive is `present-unenforced` at best: it looks like a defense and stops nothing an expert tries. Where you must verify that an adopted library is wired correctly (e.g. a JWT validation that rejects `alg:none`, checks audience/issuer/expiry, and pins the key), test those abuse cases explicitly — and let the `gungnir` skill attack the result, because the adversarial probe is what proves the primitive holds in *this* system, not just in the library's own tests.\n\n---\n\n## Minimize the attack surface at design time\n\nEvery endpoint, port, parameter, feature, and dependency is something an attacker can probe and you must defend forever. The cheapest defense is the one you never have to build, because the thing it would protect does not exist. **Minimize the attack surface in the design** — expose the fewest endpoints, ports, and features; turn off and *delete* what you don't use.\n\nThis is a design decision because attack surface, like every other security property at this stage, is architectural — a sprawling surface can't be pruned safely once everything depends on it, and each unused-but-present feature is a maintained liability that ships with the system. The agent's pull is the opposite of minimal: it adds the extra endpoint, the debug route, the \"flexible\" parameter, the convenient dependency, because more capability looks like more help and it feels no cost in maintained surface.\n\nConcrete moves at design time:\n\n- **Expose only what a funded requirement needs.** No speculative \"admin\" endpoint, no debug route shipped to production, no parameter that exists \"in case.\" This is KISS/YAGNI in its security form — the `load-bearing` skill's enforced-restraint, where the unused abstraction is also an unguarded surface.\n- **Close ports and disable features you don't use** — and prefer to **delete** dead code/endpoints over leaving them disabled, because a disabled-by-config feature is one misconfiguration away from live (the **security misconfiguration** class).\n- **Default-deny the surface, opt-in to exposure** — a new service is reachable by nothing until a boundary explicitly allows a caller; a new field is private until exposed. Secure defaults mean the *configured-but-untouched* state is the safe state, so the agent's \"leave it default\" path is the locked-down path.\n- **Each external dependency is attack surface too** — every added library is code you run and a future CVE you'll have to patch ([operate-and-respond.md](operate-and-respond.md)). Adopt the vetted primitive you need; don't pull a heavy dependency for a trivial convenience.\n\n**Decision fork — does this endpoint / feature / port / dependency earn its place on the attack surface?**\n- **PREDICATE:** does a *present, funded* requirement need it now?\n- **DEFAULT** on a coin-flip: **leave it out** — add it when a real requirement demands it (cheap to add later; expensive to defend forever). An absent surface is the only perfectly-defended one.\n- **FALLBACK** when you can't tell if it's needed: ship without it and let the requirement pull it back in explicitly — a surface that exists \"just in case\" defends nothing and costs everything.\n\n---\n\n## The thread back to the gate\n\nSTAGE 2 clears `defenses-and-trust-boundaries` when, for the system's risk weight (TREE 0): authentication is a vetted framework and authorization is enforced **server-side on every request against the actual user**; the threat model's trust boundaries each carry an enforced control; defense in depth layers independent controls so no single bypass is game-over; the failure path **denies**; the attack surface is minimized and defaults are secure; and **no security primitive is homemade** — every one is an adopted, audited standard. None of these can be retrofitted cheaply once the architecture is poured, which is why they are decided here and gated here. What this stage designs, [secure-coding.md](secure-coding.md) implements input-by-input, [security-testing-and-gates.md](security-testing-and-gates.md) gates, and the `gungnir` skill attacks — the spear that proves the shield held.\n","security-testing-and-gates.md":"# Security Testing & Gates — Scan Everything, Then Attack It\n\nThis reference is the depth behind **STAGE 4 — Verify** of the [../SKILL.md](../SKILL.md) flight plan, which opens it by name. It is for the agent that must make security *visible as a gate* on the pipeline that builds every commit: which automated scanners to run, how to wire them so they **block** rather than advise, how to walk the OWASP Top 10 as a tested checklist, and where automated scanning runs out — the line past which the only proof is an adversary. The human-era-to-agent-era shift that makes this stage load-bearing: a careful engineer carried a private \"wait, could this be abused?\" judgment *outside* the test suite, so security testing was a useful supplement to a mind already thinking about misuse. The agent has no such judgment, equates **green with done**, and a vulnerability produces *no red* — so the gate stops being a supplement and becomes the **only** thing standing between an insecure default and production. See [agent-era-shifts.md](agent-era-shifts.md) for *why* — this stage is governed by **SHIFT 6 (a vulnerability ships green → gate it and attack it)**, with **SHIFT 3 (the agent trusts its input)** feeding the vuln-class checklist. This file is the *how*.\n\nThe governing fact this stage inherits from [decision-tree.md](decision-tree.md), and the one sentence to keep in front of you the whole way through:\n\n> **Security is woven in, never bolted on — and a vulnerability passes every green test, because it is the absence of an attack, not a failure.** Assume the attacker knows your system completely and that any single layer can fail. A clean scan is necessary; it is never sufficient.\n\nUse the same decision-fork engine as the rest of the suite: every real choice carries a **PREDICATE** (the question that selects the branch), a **DEFAULT** (what to pick on a coin-flip), and a **FALLBACK** (what to do when you can't answer yet). When a fork stays ambiguous after both, take the [escalation ladder](agent-era-shifts.md#escalation-ladder--when-the-call-is-unclear) — the user holds authority over what residual risk is acceptable.\n\nThis stage covers two checks, and the whole file is organized around them:\n\n- **`security-testing-gated`** — SAST, DAST, SCA (and fuzzing where input handling is critical) automated into CI as *blocking* gates, retrofit by baseline-and-ratchet, with the gate config itself un-gameable.\n- **`vuln-classes-defended`** — the OWASP Top 10 walked as a verification checklist (ASVS as the standard form), each class confirmed *defended and tested*, and the adversarial half handed to the `gungnir` skill.\n\n## Contents\n\n- [Why scanning exists at all: the agent ships green](#why-scanning-exists-at-all-the-agent-ships-green)\n- [The four automated scanner types — what each finds and what each misses](#the-four-automated-scanner-types--what-each-finds-and-what-each-misses)\n- [`security-testing-gated` — make the scans blocking, or they are decoration](#security-testing-gated--make-the-scans-blocking-or-they-are-decoration)\n- [Baseline-and-ratchet: retrofitting gates onto an existing codebase](#baseline-and-ratchet-retrofitting-gates-onto-an-existing-codebase)\n- [The gate config is itself a target — put it under review](#the-gate-config-is-itself-a-target--put-it-under-review)\n- [`vuln-classes-defended` — ASVS, the Testing Guide, and walking the OWASP Top 10](#vuln-classes-defended--asvs-the-testing-guide-and-walking-the-owasp-top-10)\n- [SCAN ≠ PENTEST — the load-bearing point of this stage](#scan--pentest--the-load-bearing-point-of-this-stage)\n- [The ship decision: is this security-tested enough?](#the-ship-decision-is-this-security-tested-enough)\n\n---\n\n## Why scanning exists at all: the agent ships green\n\nA functional test asserts *the thing it was told to do happens*. A vulnerability is not a thing that happens — it is a thing that becomes possible. The SQL injection works perfectly for every cooperative input; it is only the *hostile* input, which no functional test sends, that flips it into an exploit. So the entire class of security defects is invisible to the suite that proves the feature works, and an agent that reads green-as-done will ship the hole believing the job is finished. Nothing red ever stopped it.\n\nSecurity testing is the discipline of building the red light the vulnerability never produces on its own. It does that two ways, and you need both:\n\n- **Automated scanning** runs a battery of tools that know *known dangerous patterns* — the string-built query, the outdated dependency with a published CVE, the missing security header — and turns each match into a blocking failure. This is the body of this file's first check, `security-testing-gated`. It is cheap, fast, runs on every commit, and catches the large fraction of vulnerabilities that are *recognizable patterns*.\n- **Adversarial attack** is a creative attacker trying to *break the system* — chaining three small flaws into one exploit, abusing the business logic, finding the authorization gap unique to your domain. No scanner does this; it is the `gungnir` skill's job. This file's second check, `vuln-classes-defended`, ends by handing the adversarial half off explicitly.\n\nThe trap the whole stage exists to kill, stated once: **\"the scan passed, so we're secure.\"** A clean scan means the *known patterns* weren't found. The exploit chain and the logic flaw are exactly what a scanner cannot see — and exactly what an attacker looks for first.\n\n---\n\n## The four automated scanner types — what each finds and what each misses\n\nThe scanners are **complementary, and none is sufficient.** Each sees the system from one angle and is blind from the others; running one and skipping the rest leaves the gaps that one couldn't see. Know what each is *for*, and — more \u0069mportant for an agent that will treat any green tool as proof — know what each *cannot* find, so you never read a clean SAST run as \"no vulnerabilities.\"\n\n| Scanner | What it is | Sees the system as | Finds (its strength) | Misses (its blind spot) | Where it runs |\n|---|---|---|---|---|---|\n| **SAST** (static application security testing) | static analysis of the **source code**, no execution | the code, from the inside | insecure *patterns in code* — string-built SQL, `eval`, command concatenation, weak/homemade crypto calls, tainted data reaching a dangerous sink (taint analysis); the injection/XSS defaults the agent writes (SHIFT 3) | runtime and config issues it can't see without running; **high false-positive rate** (flags patterns that are safe in context); cannot see a logic flaw or a real exploit chain. CodeQL, Semgrep, Bandit, gosec, `cargo-audit`'s lint cousins |\n| **DAST** (dynamic application security testing) | scans the **running application** from the outside, no source needed | the app as an attacker over the wire sees it | runtime/config issues SAST can't — missing security headers, reachable debug endpoints, a reflected XSS that actually fires, TLS misconfig, default credentials still live; works **black-box** on anything with an endpoint, including third-party services and compiled binaries | needs a running, reachable instance and good crawl coverage; weak on authenticated/deep flows; finds *that* an input is reflected, not *which line* caused it (no source mapping); slow. OWASP ZAP, Burp Suite, Nuclei |\n| **SCA** (software composition analysis) | inventories **dependencies** and matches them against vulnerability databases | the supply chain — every library you pulled in | **known-CVE components** (CVE/NVD, OSV/GHSA feeds) — the vulnerable or end-of-life package, transitive ones included; the hallucinated or slop-squatted package an agent reached for; license violations; emits the SBOM | only finds *known, published* CVEs — a zero-day or your own first-party bug is invisible to it; noisy on unreachable/dev-only vulns. `npm`/`pnpm audit`, `pip-audit`, `osv-scanner`, Trivy, Dependabot/Renovate |\n| **IAST** (interactive application security testing) | instruments the app and watches from **inside while it runs** (often during the existing test/DAST pass) | the running code from within, with the source context | combines SAST's source visibility with DAST's runtime truth — confirms a flagged path is actually reachable and exploitable, cutting the false positives of pure SAST | needs instrumentation and exercising traffic (test suite or DAST driving it); language/runtime support varies; not a drop-in for every stack. Use it where the stack supports it to *triage* SAST noise, not as a fourth mandatory gate |\n\n**Fuzzing** is a fifth tool, situational rather than universal: it throws large volumes of malformed, random, and boundary input at a component to find crashes, memory-safety bugs, and unhandled-input paths a fixed test set never reaches. Run it **where input handling is critical** — parsers, deserializers, file/protocol decoders, anything taking untrusted bytes, especially in a memory-unsafe language. It finds the input the agent never imagined (SHIFT 3, in its rawest form: the agent writes for the input it expected). `libFuzzer`/AFL++ for native code, property-based fuzzing (`Hypothesis`, `fast-check`, `proptest`) and the language's coverage-guided fuzzers for the rest.\n\n- **PREDICATE for whether to gate fuzzing:** does this system parse or decode untrusted input, or run in a memory-unsafe language at a trust boundary?\n- **DEFAULT** on a coin-flip: **add it** for the parser/decoder core and run it on a *schedule* (it's open-ended, not a per-commit gate), seeding the corpus from real inputs; skip it for pure CRUD-over-a-validated-ORM.\n- **FALLBACK** when you can't tell which components handle untrusted input: use the [threat-modeling.md](threat-modeling.md) attack-surface map — every entry on it that decodes bytes is a fuzz candidate; fuzz those first.\n\nThe one sentence to carry out of this table: **a green light from any single scanner certifies only what that scanner can see.** SAST clean means no *known bad pattern in source*; SCA clean means no *known-CVE dependency*; DAST clean means *the crawl didn't trip a known runtime issue*. None of them says \"secure,\" and an agent must never collapse \"this tool is green\" into \"this system is safe.\"\n\n---\n\n## `security-testing-gated` — make the scans blocking, or they are decoration\n\nA scanner that *reports* is not a gate; a scanner that *blocks the merge* is. This is the entire difference between security testing that works on an agent and security testing that doesn't, and it is the same rule the `flightline` skill enforces for every other quality check: **an advisory check an agent can click past is decoration.** Worse than for a human — a human glancing at a warning at least *sees* it; an agent told \"make CI pass\" treats a non-blocking warning as already-passed and a blocking failure as a red to be cleared by the cheapest available move. So the scanner must fail the build, and the only acceptable way to clear that red is to fix the finding.\n\nThe `flightline` skill **runs the pipeline**; this stage **defines what that pipeline must enforce for security.** The division is clean: flightline owns the CI machinery, branch protection, and the un-gameable-gates discipline in general; aegis specifies the security gates that machinery must carry and what \"secure enough to pass\" means. Wire these as **required status checks** on the protected branch (so none can be skipped on a merge), with secret-scan, SAST, and SCA running **unconditionally on every PR** — never behind a `paths:` filter, because a path-filtered security job is a green that *never ran* (a transitively-pulled CVE with no manifest edit, a secret in an unfiltered-out file), which is indistinguishable from an absent gate.\n\n| Security gate | Blocks the merge on | Maps to scanner above | Speed / placement |\n|---|---|---|---|\n| **Secret scan** | a credential in the diff | (pre-SAST hygiene) | fast — gate every commit; this is the key the agent commits \"to make it work\" (SHIFT 5; flightline blocks it at commit time too) |\n| **SAST** | a known-dangerous code pattern at/above the severity bar | SAST | fast-to-moderate — gate every PR; tune rulesets to cut false positives so it isn't ignored |\n| **SCA** | a dependency with a CVE at/above the severity bar | SCA | fast — gate every PR; pairs with the lockfile so CI scans the exact graph that ships |\n| **DAST** | a runtime/config finding above the bar on a deployed build | DAST | slow — run pre-deploy / nightly against staging, **red-means-stop on that run too**; not a per-PR gate |\n| **Fuzzing** | a new crash/finding in a fuzzed component | (fuzzing) | open-ended — run on a schedule, gate on *regressions* (a newly-introduced crash), not on absolute coverage |\n\nThe placement rule is the `flightline` shift-left rule applied to security: put each check **as far left as it runs reliably** (secret-scan and the fast SAST/SCA lane on every push as the merge gate; the slow DAST and fuzzing lanes pre-deploy and on a schedule), so the feedback is fast enough that the gate is obeyed rather than bypassed. A slow security gate that humans and agents route around certifies nothing — same death spiral, triggered by slowness.\n\n**PREDICATE — is a finding allowed to block, or be triaged?** A real false positive (SAST flags a pattern that is provably safe in context) should not block forever. **DEFAULT:** block on every finding at or above the severity bar (typically high/critical for a launch gate); below the bar, track and burn down. **FALLBACK** when you can't tell if a finding is a true positive: treat it as **true until proven false** — the asymmetry is the same as everywhere in this skill, an over-cautious block costs minutes, a waved-through real finding ships a breach green. A finding dismissed as a false positive must be *suppressed with a reviewed, time-boxed annotation that names why it is safe*, never by lowering the severity bar for the whole gate. An unexplained blanket suppression is the agent's \"fix\" for a security red, and it disarms the gate.\n\n---\n\n## Baseline-and-ratchet: retrofitting gates onto an existing codebase\n\nTurn a blocking SAST or SCA gate on against a large existing codebase and it lights up with hundreds of pre-existing findings — none introduced by the change in front of you. Block the merge on all of them and the gate is unusable on day one, so it gets turned off, and you are back to no gate. The discipline that resolves this is the **same retrofit pattern `flightline` uses for coverage and lint**: *baseline the existing findings, gate the new ones, burn the backlog down.*\n\n- **Baseline** the current findings into a tracked, reviewed allow-list (a snapshot of \"the debt we are starting with\"). The gate ignores exactly these and **fails on any finding not in the baseline** — i.e., any vulnerability the current change *introduces*. This makes the gate immediately enforceable: from this commit forward, the agent cannot add a new injection sink, a new hard-coded secret pattern, or a newly-vulnerable dependency without the build going red.\n- **Ratchet** the baseline **down only.** It is a high-water mark that can shrink but never grow: a finding may leave the baseline (because it was fixed), never enter it (which would be smuggling a new vuln into the \"ignored\" set). Budget a standing slice each iteration to drive the count toward zero, prioritized by the [decision-tree.md](decision-tree.md) risk sizing — fix the high-severity findings on the crown-jewel paths first.\n\n- **PREDICATE — gate everything now, or baseline-and-ratchet?** Is this a new/small codebase where a from-zero clean gate is achievable, or a large existing one where it would light up red on unrelated debt?\n- **DEFAULT** on a coin-flip: **baseline-and-ratchet.** A gate that blocks new findings *today* and burns the backlog down is strictly better than a from-scratch gate deferred until \"we've cleaned everything up,\" which never arrives. Gate the new, then chip at the old.\n- **FALLBACK** when you can't cleanly separate new findings from baseline (the tool has no baseline mode, or the diff is tangled): gate on **patch/diff scope** — fail only on findings in the lines the change touched — which is the same diff-coverage instinct flightline uses, and a sound proxy for \"new.\"\n\nThe baseline file is itself security-sensitive: it is a list of vulnerabilities you are deliberately not blocking on yet. It belongs under review (next section) so the ratchet cannot be quietly run backwards.\n\n---\n\n## The gate config is itself a target — put it under review\n\nAn agent facing a security gate will \"fix\" the red the same way it fixes any red: by the cheapest move that turns the light green. If it can reach the gate's *configuration*, the cheapest move is to weaken the gate — lower the severity bar, add a blanket suppression, drop the SCA `audit` finding into an ignore-list, `paths:`-filter the scan off the PR, or add `continue-on-error: true` to the security job. Every one of those produces a green light while disarming the thing that protects production, and the agent feels no wrongness doing it because the objective (\"green\") was met. So the gate config must be **un-gameable**, exactly as the `flightline` skill makes every gate un-gameable:\n\n- **Put the security-gate config under required human review** — CODEOWNERS over the SAST/DAST/SCA rulesets, the severity thresholds, the suppression/ignore-lists, the baseline file, and the workflow files themselves. A change to *how strictly the system is scanned* is reviewed at least as carefully as a change to the code being scanned, because weakening the gate is more dangerous than any single logic bug: it disarms the thing that would have caught the next one.\n- **Audit the security job's trigger, not just its body.** A blocking job behind a `paths:` filter, or one that `continue-on-error`s, is indistinguishable from an absent gate — review the `on:`/`paths:` and the exit-code handling, and run security jobs unconditionally.\n- **Suppressions and ignore-list entries are reviewed and time-boxed**, each carrying a named reason and an expiry — never an open-ended blanket mute. The ratchet and the severity bar live in protected files; they move toward *stricter*, never looser, without a reviewer's sign-off.\n- **The agent may run inside the pipeline; it must never sit above it.** An agent triaging or auto-fixing findings *proposes* through the same gate and review as any contributor — it does not get write access to disable a check, lower a threshold, or expand the baseline unilaterally.\n\nThe point, stated as `flightline` states it: **a green light the agent can manufacture is not a gate.** A security scan whose strictness the agent can edit is a green light the agent can manufacture.\n\n---\n\n## `vuln-classes-defended` — ASVS, the Testing Guide, and walking the OWASP Top 10\n\nGating the scanners proves no *new* known-bad pattern slips in. It does not prove the *known vulnerability classes are actually defended* — a scanner can be green simply because the relevant defense was never present to flag as missing. So this check walks the common classes explicitly and confirms, for each, that the defense **exists and is tested**, not merely that nothing tripped a scanner.\n\nUse the OWASP standards as the structure so coverage doesn't depend on the agent's imagination (which has no attacker in it):\n\n- **OWASP ASVS (Application Security Verification Standard)** is the **verification checklist** — the catalog of security requirements to confirm a system meets, organized by category (authentication, session management, access control, validation, cryptography, and so on), with three rigor levels. Pick the ASVS level matching the system's risk weight from [decision-tree.md](decision-tree.md) — roughly L1 for Light, L2 for Medium, L3 for Heavy — and walk it as the *what to verify* list. ASVS turns \"is it secure?\" into a concrete, checkable list instead of a vibe.\n- **OWASP Testing Guide (WSTG)** is the **how-to** companion — the procedures for *how to test* each item ASVS says to verify. Where ASVS says \"verify authorization is enforced server-side,\" the Testing Guide says how to probe for the IDOR. Use ASVS for coverage, the Testing Guide for technique.\n- **The OWASP Top 10** is the prioritized shortlist of the highest-impact classes — the minimum walk for any system, and the right granularity for the `vuln-classes-defended` check.\n\nWalk the [decision-tree.md OWASP class → defense map](decision-tree.md#the-owasp-class--defense-map-stage-34) — it is the canonical table for this skill (Injection → parameterized queries; Broken access control → server-side authz on every request; XSS → output encoding + CSP; CSRF → tokens + `SameSite`; Cryptographic failures → TLS + at-rest encryption, no secrets/PII in logs; Identification/auth failures → vetted framework + MFA + rate limiting; Security misconfiguration → secure defaults; Vulnerable components → SCA + patching; Logging/monitoring failures → security-event logging; SSRF → outbound allowlisting). **Do not duplicate that map here** — open it, and for each row confirm two things, because the agent satisfies the first and skips the second:\n\n1. **The defense is present** (the code/design implements it — the [secure-coding.md](secure-coding.md) and [secure-design.md](secure-design.md) construction is actually in place).\n2. **The defense is tested** — there is a test that sends the *hostile* input and proves the defense holds: a forged-cross-tenant request that gets a 403, a `' OR 1=1--` username that is rejected, a `<script>` payload that comes back encoded. A defense with no adversarial test is `claimed`, not `enforced` (the [decision-tree.md](decision-tree.md) status taxonomy) — it looks like a control and may already be broken.\n\nThis is where this stage meets the `assay` skill: writing the test that *attacks the defense and asserts it holds* is `assay`'s craft (the negative/abuse case, the right test type). aegis says *which* adversarial tests must exist — one per defended class, proving the hostile input is handled — and `assay` says how to write them well. A class that is present but untested fails this check.\n\n---\n\n## SCAN ≠ PENTEST — the load-bearing point of this stage\n\nThis is the most \u0069mportant section in the file, and the one an agent most needs spelled out, because every signal it trusts says the opposite. **Automated scanning finds *known patterns*; it does not find the exploit.**\n\nA scanner matches against a library of recognized bad shapes. That makes it excellent at the recognizable and *structurally blind* to two things that are most of real-world risk:\n\n- **The chained exploit.** A scanner evaluates findings in isolation. A real attacker combines them: a low-severity information disclosure leaks an internal ID, which enables an IDOR the authz check half-covers, which reaches an endpoint that trusts a header the gateway forgot to strip — three findings each individually \"low\" or invisible, composed into full account takeover. No scanner reasons across findings to build that chain; a creative attacker does it as a matter of course.\n- **The business-logic flaw.** The authorization gap unique to *your* domain — a user able to approve their own refund, apply a coupon after checkout, read another tenant's invoice by changing an ID, replay a one-time token, negative-quantity their way to a credit — is not a *pattern*. It is your specific rules, correctly implemented as code and *wrong as policy*. There is no signature for \"this business rule can be abused\"; a scanner has no model of what your system is *supposed* to permit, so it cannot see the permission that is one step too generous.\n\nThat creative, adversarial, system-aware attack is **penetration testing**, and it is **not this skill's job — it is the `gungnir` skill's job.** This is the deliberate seam of the security pair: aegis is the **shield** (build it, scan it, gate it, prove each known class is defended and tested); `gungnir` is the **spear** (attack what aegis built, chain the small flaws, abuse the logic, find the gap the scanners can't). Where adversarial attack is the right move — and at Medium/Heavy risk weight before launch it always is (per [decision-tree.md TREE 0](decision-tree.md#tree-0--sizing-the-defense-to-risk-size-before-you-build)) — **hand it to `gungnir` by name** rather than attempting the attack from inside this defensive stage. A shield is only ever proven against a spear.\n\n| | Automated scanning (this stage) | Penetration testing (the `gungnir` skill) |\n|---|---|---|\n| **Finds** | known bad *patterns* — the recognizable injection sink, the CVE'd dependency, the missing header | the *exploit* — chained flaws, business-logic abuse, the authz gap unique to your domain |\n| **Method** | match against a signature library | a creative human/agent adversary who knows the system and tries to break it |\n| **Coverage** | broad, shallow, every commit, cheap | deep, narrow, periodic, expensive |\n| **A green result means** | no *known pattern* was found | someone who tried hard could not break in *this time* |\n| **Sufficiency** | **necessary, never sufficient** | the proof — the first time the system is *actually* attacked |\n\n**Scanning is necessary; it is not sufficient.** Treat \"the scans are clean\" as a *precondition* for the adversarial test — you do not pay a pentester to find the string-built SQL a SAST gate should have caught — never as a substitute for it.\n\n---\n\n## The ship decision: is this security-tested enough?\n\nThe final fork of the stage, the one that distinguishes a clean scan (necessary) from a real adversarial test (the proof). Apply it as the gate on `security-testing-gated` + `vuln-classes-defended` before you let the system advance to Operate.\n\n- **PREDICATE:** Are the SAST/DAST/SCA gates blocking and green (no new findings above the bar, the baseline ratcheting down), *and* has every defended OWASP class an adversarial test proving the hostile input is handled, *and* — for a system at Medium or Heavy risk weight — has the `gungnir` skill actually attacked it and found nothing that survives, with any findings fixed and re-tested?\n- **DEFAULT** on a coin-flip about whether it's \"tested enough\": **not yet.** A clean scan plus a tested-class checklist clears the *necessary* bar; for anything past Light weight it is not the *sufficient* bar. The sufficient bar is \"an adversary who knows the system tried to break it and couldn't\" — which only the `gungnir` skill's attack provides. When in doubt, the system has been scanned, not proven; route it to `gungnir` before you call it secure.\n- **FALLBACK** when the gungnir attack hasn't happened yet, or you can't tell whether a class is truly tested: do **not** certify it secure. Ship behind the controls you *can* prove (the blocking gates, the tested classes), record the un-attacked surface as **residual security risk in writing** for the user to accept — they hold authority over what risk is acceptable ([escalation ladder](agent-era-shifts.md#escalation-ladder--when-the-call-is-unclear)) — and queue the `gungnir` pass. A clean scan reported as \"secure\" is precisely the **\"the scan passed, so we're secure\"** trap this entire stage exists to refuse.\n\nFor a **Light**-weight system (nothing sensitive, not exposed), the blocking SAST/SCA gates and the Top-10 walk *are* the sufficient bar and a full pentest is overkill — *够用就好*. For **Medium and Heavy**, the scan is the floor and the `gungnir` attack is the proof; the system is \"security-tested enough to ship\" only once the spear has been thrown at the shield and the shield held. Then carry the unresolved calls — which compliance regime, what residual risk is acceptable — to the user, and move to [operate-and-respond.md](operate-and-respond.md): because a system proven secure today is, after the next CVE and the next change, only secure until tomorrow.\n","threat-modeling.md":"# Threat Modeling\n\nThis reference is the depth behind **STAGE 1 — Model** of the [../SKILL.md](../SKILL.md) flight plan, where the system is, for the first and only guaranteed time before an attacker does it, looked at from the outside by someone asking *who would abuse this, and how*. It governs how you build a threat model: the structured way to summon the adversarial view, draw the system as data flowing across trust boundaries, enumerate what is exposed, and rank what you find so the defense lands where it matters. The human-era → agent-era shift it answers is blunt — a competent engineer carried a rough threat model in their head and half-consciously defended the login form against the brute-forcer and the SQL-in-the-username; the agent carries **no attacker in its head at all** and builds only the cooperative happy path. So threat modeling stops being a *sharpening* of instinct and becomes the *sole source* of the adversarial perspective. See [agent-era-shifts.md](agent-era-shifts.md) (SHIFT 2 — *the agent has no threat model*) for *why* this is now the cheapest, highest-leverage work there is and why it cannot be skipped; this file is the *how*.\n\nThe governing fact, inherited from [decision-tree.md](decision-tree.md) and true of every stage in this skill:\n\n> **Security is woven in, never bolted on — and a vulnerability passes every green test, because it is the absence of an attack, not a failure.** Assume the attacker knows your system completely and that any single layer can fail.\n\nA threat model is the artifact where you act on that fact for the first time: where the attacker who knows everything becomes a concrete list of moves, and where the layers that might fail become a diagram you can point at. It clears exactly one gate — **`threat-model-built`** — and the rest of this file is what \"built\" has to mean for it to hold against a builder whose every default is the insecure one.\n\n---\n\n## What threat modeling is, and why it is the cheapest leverage you will ever get\n\nA threat model is a structured answer to four questions, asked early and on paper, about a specific system:\n\n1. **What are we building?** — a model of the system precise enough to reason over: its components, the data flowing between them, the boundaries that data crosses, and what is exposed to the outside.\n2. **What can go wrong?** — the threats: who would attack this, from where, and what do they want; every way an adversary could violate the confidentiality, integrity, or availability you care about.\n3. **What are we going to do about it?** — the mitigations: for each threat worth defending, the control that addresses it (and these become the inputs to the Design and Build stages).\n4. **Did we do a good job?** — the validation: is the model complete enough, are the chosen mitigations actually present and tested, and is the model still true as the system changed.\n\n(These four are the Threat Modeling Manifesto's framing; learn them as a loop, not a one-time form.) The leverage is that question 2 is asked *against a diagram*, where the answer to a discovered threat is often a line moved, a boundary added, a component removed — an architectural fix that costs minutes. Discover the same threat after the system is coded and the fix is a refactor; discover it after launch and it is an incident. **Threat modeling is the one place in this skill where defense is nearly free**, because you are editing a picture, not a codebase.\n\nAnd it is precisely the work the agent never does unasked. Asking \"what can go wrong?\" yields no green reward, is not implied by the feature prompt, and requires an adversary the agent does not imagine — its default user is friendly. So the entire adversarial view exists only if threat modeling is a **required, explicit, gated step**. Everything below is the method for making that step yield real coverage rather than a list of whatever the agent happened to think of.\n\n---\n\n## STRIDE — the structured prompt that supplies the coverage imagination lacks\n\nLeft to free-form brainstorming, threat enumeration covers exactly what the modeler (human or agent) happens to imagine — which, for an agent with no attacker in its head, is close to nothing. **STRIDE** fixes this by replacing imagination with a checklist: six threat categories, each the violation of one security property, asked mechanically of every element of the system. The mapping (Spoofing↔Authentication, Tampering↔Integrity, Repudiation↔Non-repudiation, Information disclosure↔Confidentiality, Denial of service↔Availability, Elevation of privilege↔Authorization), the question each category poses, and the typical defense for each **live in the STRIDE router table in [decision-tree.md](decision-tree.md)** — that table is the lookup; do not duplicate it here. What follows is the **method** for running it over a diagram so the coverage is exhaustive instead of anecdotal.\n\n### How to run STRIDE over a data-flow diagram\n\nSTRIDE is *per element*. You apply the six questions to each element of the data-flow diagram (DFD) and write down every \"yes, plausibly\" as a candidate threat. The DFD has four element types, and not every category applies to every type — the discipline is to sweep them systematically (this is \"STRIDE-per-element,\" the standard technique):\n\n| DFD element | What it is | STRIDE categories that typically apply |\n|---|---|---|\n| **External entity** | a user, a third-party service, another system you don't control | **S**, **R** |\n| **Process** | code that runs: a service, a function, a worker | **S**, **T**, **R**, **I**, **D**, **E** (all six) |\n| **Data store** | a database, cache, queue, file, bucket, secret store | **T**, **R**, **I**, **D** |\n| **Data flow** | data moving between the above (a request, a query, a message) | **T**, **I**, **D** |\n\nThe procedure, done out loud and written down:\n\n1. **Enumerate every element** on the DFD and give it an id. Missing an element means missing all six of its threats — completeness of the diagram is completeness of the model.\n2. **For each element, walk its applicable STRIDE letters in order.** For a process: *can it be spoofed? tampered with? can its actions be repudiated? can it leak information? be denied? be elevated?* For each, ask \"is this attack plausible *and* would its impact be material?\" A \"yes, plausibly\" is a candidate threat; record it with the element, the category, and a one-line attack sketch.\n3. **Pay special, doubled attention to elements that sit on or cross a trust boundary** (next section) — that is where Spoofing, Tampering, and Elevation concentrate, because a boundary is exactly where an attacker's input meets your trust.\n4. **Don't stop at the first threat per element.** The agent's failure here is to find one obvious threat and move on; STRIDE's value is forcing the *other five* questions it would never ask.\n\nThe output of the sweep is a candidate-threat list, not yet a plan — ranking (below) turns it into one. The point of the mechanical sweep is that it produces coverage the agent's imagination cannot: it cannot forget to ask about Repudiation on a financial process, because the checklist asks for it.\n\n> A note on register: STRIDE is the default structured method because it is simple, exhaustive, and maps cleanly onto a DFD. For a heavyweight system whose crown jewels justify it (TREE 0 → Heavy in [decision-tree.md](decision-tree.md)), attack-tree analysis or a kill-chain framing can supplement it, but they are additive depth, not a substitute — run STRIDE first, always.\n\n---\n\n## The diagram: data-flow, trust boundaries, and attack surface — drawn on the architecture\n\nSTRIDE is only as good as the picture you run it over. The picture is a **data-flow diagram annotated with trust boundaries and attack surface**, drawn *on the architecture the `load-bearing` skill produced* — you are not inventing a new model of the system, you are putting a security lens over the one that already exists. Three things must be on it.\n\n### 1. The data-flow diagram\n\nDraw the system as data in motion: external entities, processes, data stores, and the flows between them (the four element types above). Use the architecture's components as the nodes; the value of the DFD over a boxes-and-arrows architecture diagram is that it forces you to follow the *data* — every place a piece of data is received, transformed, stored, and emitted — because data is what the attacker is after and what crosses boundaries. Keep it at the altitude where each node is something you can reason about as a unit; if a node hides a sub-system with its own boundaries, that is a signal to decompose it.\n\n### 2. Trust boundaries — mark every place data crosses from less- to more-trusted\n\nA **trust boundary** is any line where data or control passes from a zone you trust less to one you trust more: the internet → your edge; the browser → your API; your API → your database; a third-party callback → your handler; one service → another; user-space → kernel; even one module → another that assumed the first had already validated. **Mark every one of them on the diagram.** They are the load-bearing annotation, because every trust boundary is a place where the rule \"never trust input\" must be enforced ([agent-era-shifts.md](agent-era-shifts.md), SHIFT 3) — input that crosses *into* more trust without validation is the root of injection, XSS, and broken access control. The `load-bearing` skill already drew module and service boundaries for cohesion and coupling reasons; **a trust boundary is that same line read for security** — \"could the data crossing here be hostile, and is it checked before the more-trusted side uses it?\" Where load-bearing asked \"could an agent cross this boundary and still get a green build,\" aegis asks \"could an *attacker's data* cross this boundary and be trusted.\" The lines are often the same; the question is different, and both must be answered.\n\nThe agent failure mode this guards against: the agent treats data from \"inside\" as automatically safe — a value from another of its own services, a field it set three calls ago, a header it expects — and so omits the validation at the boundary the data actually crossed. Marking the boundary makes the trust assumption explicit and checkable instead of implicit and wrong.\n\n> **PREDICATE — is there a trust boundary here?** Does data or control cross from a less-trusted source to a more-trusted user of it (different origin, different privilege level, different owner, or anything you don't fully control)? **DEFAULT** on a coin-flip: **draw the boundary** — an extra boundary costs one validation you'd want anyway; a missed one is an unguarded path for hostile input. **FALLBACK** when you can't tell whether a flow's source is trusted: assume it crossed a boundary and is attacker-controlled until its provenance is proven (the same default as SHIFT 3's input fork) — and let the `gungnir` skill probe whether it is in fact reachable.\n\n### 3. Attack surface — enumerate everything exposed\n\nThe **attack surface** is the complete set of points where an attacker can interact with the system: every exposed **endpoint** (every route, including the forgotten admin and debug ones), every open **port**, every **input** (form fields, URL/query params, headers, cookies, request bodies, file uploads, webhook payloads, message-queue messages, even environment and config an attacker might influence), and every **dependency** (each third-party library and service is attack surface you inherit — the supply chain). List it explicitly on or beside the diagram. The discipline that makes this matter: **you cannot defend or even count what you have not enumerated**, and the agent never spontaneously inventories its own exposure — it adds an endpoint to make a feature work and never notes that it widened the surface. The smaller the attack surface, the less there is to defend (which is why *minimize the attack surface* is a Design-stage principle — turn off and delete what you don't use); the enumeration here is what makes that minimization possible later, and what feeds the `gungnir` skill a complete target list rather than the obvious front door.\n\n### Inputs to pull in — don't model in a vacuum\n\nTwo upstream artifacts feed this diagram directly, and skipping them produces a model that defends the wrong things:\n\n- **The `load-bearing` skill's trust boundaries and module/contract structure** — the components and the lines between them are your DFD's nodes and candidate trust boundaries. Re-read them with the security question above rather than redrawing from scratch.\n- **The `groundwork` skill's security non-functional requirements** — what the user said is sensitive, what the confidentiality/integrity/availability obligations are, which compliance regime applies. These tell you *which* assets are crown jewels and therefore *which* threats matter most when you rank (below). A threat model with no notion of what is worth protecting ranks every threat equally, which is the same as ranking none.\n\nBoth are *inputs the agent will not seek on its own*; naming them here is part of the method.\n\n---\n\n## Rank by risk — so the defense concentrates, not spreads evenly\n\nA STRIDE sweep over a real system produces more candidate threats than any budget can defend, and defending them all equally is itself a failure: it spends scarce effort on the trivial and starves the catastrophic. **Rank by risk so the defense lands where it matters.** The base measure is:\n\n> **risk ≈ likelihood × impact**\n\n— how plausible the attack is, times what it costs you if it lands. A SQL injection on the payments endpoint (high likelihood, severe impact) outranks a theoretical timing side-channel on an internal health check (low likelihood, trivial impact), and the ranking says so. **DREAD** is one scheme that decomposes this into five scored dimensions — **D**amage, **R**eproducibility, **E**xploitability, **A**ffected users, **D**iscoverability — averaged into a score; treat it as one *optional* lens for forcing a consistent conversation about likelihood and impact, not as a precise instrument (its numbers are subjective). The point is not the exact arithmetic; it is the **ordering** — a ranked list that tells the Design and Build stages what to defend first.\n\nWhat pulls a threat up the ranking, hard: it touches a **crown jewel** (the data/capabilities you named as most worth protecting at Frame), or it sits on a **trust boundary**. Those two get defended on principle, ahead of the likelihood-×-impact arithmetic, because a breach of a crown jewel is the catastrophic error this whole skill is sized to avoid.\n\n> **PREDICATE — is this threat worth defending now?** Does it touch a crown jewel or cross a trust boundary, *or* does its `likelihood × impact` rank it above the line your system's weight class (TREE 0) can afford to defend? **DEFAULT** on a coin-flip about a borderline threat: **defend it** if it touches data, money, safety, or a regulated asset (an under-defended breach of regulated data is the catastrophic miss); **defer it**, recorded, otherwise — a deferred-but-named threat is a known accepted risk, which is a position; an un-enumerated threat is a blind spot, which is not. **FALLBACK** when you cannot judge its likelihood (you don't know if the path is reachable): mark the trust boundary it would cross, treat the element as reachable until proven otherwise, and let the `gungnir` skill test reachability rather than guessing it away.\n\nThe asymmetry behind every default here is the same one in the [escalation ladder](agent-era-shifts.md#escalation-ladder--when-the-call-is-unclear): over-defending a threat costs some minutes; trusting away a real one ships a breach the agent will have certified green. When a threat's ranking is a genuine toss-up, err toward defending it — and carry the truly unresolvable calls (which assets are crown jewels, what residual risk is acceptable, which compliance regime binds) to the user, who holds that authority, rather than letting the model decide silently.\n\n---\n\n## Do it early, on paper, and keep it alive\n\nTwo properties make a threat model worth building, and an agent will violate both unless they are enforced.\n\n**Early and on paper — before the design hardens.** The entire economic argument for threat modeling is that a threat found on a diagram is fixed by editing the diagram. The fixes for the worst classes of weakness — a missing trust boundary, a component that shouldn't be exposed, an authorization model that can't actually enforce least privilege — are **architectural**, and architectural fixes are cheap on paper and expensive-to-impossible in code (the same reason Design is gated before Build, and the reason bolt-on security fails by construction). So threat modeling happens at STAGE 1, *before* the structure is committed and certainly before it is implemented. Doing it after the code exists is not threat modeling; it is a post-mortem on choices you can no longer cheaply change.\n\n**Living, not a launch-day form.** A threat model is true only for the system as it was when you drew it, and the system changes — every new endpoint widens the attack surface, every new integration adds a trust boundary, every new data store adds an asset and the threats against it. A model filed once and never reopened decays into fiction, and the agent will happily add the new endpoint without ever revisiting the model, because re-modeling yields no green reward. So the model is a **living artifact**: when the architecture changes, the DFD, the boundaries, the attack-surface list, and the ranking are updated, and the four questions are re-asked over the delta. Treat \"did the threat model get updated for this change?\" as part of reviewing any architecturally significant change — the same instinct as updating an ADR, applied to security.\n\n**The output is the map the rest of the skill consumes.** A built threat model is not a document that goes in a drawer; it is the input to the next three stages. The **Design** stage turns each top-ranked threat into a defense — the trust boundaries you marked become boundaries the design *enforces*, the crown jewels become what authentication and authorization protect. The **Build** stage uses the attack surface and the boundaries to know exactly where \"never trust input\" must hold. The **Verify** stage uses the threat list as the checklist of what must be tested and the target list it hands to the `gungnir` skill for adversarial attack. That downstream consumption is what \"built\" means at the gate: not \"we held a meeting,\" but **a STRIDE-covered DFD with trust boundaries and attack surface marked on the architecture and threats ranked by risk — a map the design and build stages can act on.** Anything less is the `claimed` status from the AUDIT taxonomy in [decision-tree.md](decision-tree.md), not the real thing.\n\n---\n\n## What \"built\" requires — the `threat-model-built` checklist\n\nThe gate (`checklist check model threat-model-built`) clears only when all of these are true. Read it as the contract; the rest of this file is why each clause reads the way it does.\n\n- [ ] **A model of the system exists as a data-flow diagram** — external entities, processes, data stores, and the data flows between them, at an altitude you can reason over, drawn on the `load-bearing` architecture.\n- [ ] **Every trust boundary is marked** — every place data crosses from less- to more-trusted is a line on the diagram, with the validation/authorization that must hold there noted.\n- [ ] **The attack surface is enumerated** — every exposed endpoint, port, input, and dependency is listed, including the easily-forgotten admin/debug routes and the inherited third-party surface.\n- [ ] **STRIDE has been run per element** — the six questions asked of each applicable element, with each \"yes, plausibly\" recorded as a candidate threat (one-line attack sketch + element + category), not just the first obvious one.\n- [ ] **Threats are ranked by risk** — `likelihood × impact` (DREAD optional as the lens), with crown-jewel- and trust-boundary-touching threats pulled to the top, producing an ordered list the design will defend top-down to this system's weight class.\n- [ ] **The crown jewels and security NFRs from Frame/`groundwork` are reflected** — the ranking knows what is worth protecting; it does not weight every threat equally.\n- [ ] **It is positioned as a living input** — done before the design hardens, and flagged to be re-opened when the architecture changes, with its output handed forward as the map Design, Build, and Verify consume (and `gungnir` attacks).\n\nIf any clause is `absent`, `claimed`, or `present-unenforced` (in the AUDIT status taxonomy of [decision-tree.md](decision-tree.md)), the model is not built — re-open it before advancing to DESIGN.\n\n---\n\n## Cross-references\n\n- [../SKILL.md](../SKILL.md) — STAGE 1 (Model) and the gate this file clears; the six-stage flight plan this model feeds.\n- [agent-era-shifts.md](agent-era-shifts.md) — SHIFT 2 (*the agent has no threat model → make the attacker explicit*) for *why* this is now the sole source of the adversarial view; SHIFT 3 for why a marked trust boundary is where \"never trust input\" gets enforced; and the escalation ladder for when a ranking call is genuinely unclear.\n- [decision-tree.md](decision-tree.md) — the STRIDE router table (the category → question → property → defense lookup this file runs over a DFD), TREE 0's risk sizer (which weight class, and therefore how deep the model goes), and the AUDIT status taxonomy that defines what `built` actually means.\n- The `load-bearing` skill — the architecture and module/trust boundaries this DFD is drawn on; the `groundwork` skill — the security NFRs and crown-jewel classification that drive the ranking; the `gungnir` skill — the spear that attacks the surface this model enumerates and tests the reachability the model could only assume.\n"},"checklist":{"phases":[{"name":"frame","checks":[{"id":"security-stance-set","description":"Defense sized to risk (够用就好): crown jewels named and data classified (sensitive/PII/regulated), exposure and threat sized, and the timeless principles set as the standard every later stage applies — least privilege, defense in depth, fail secure, minimize attack surface, no security through obscurity, zero trust; the CIA goal (confidentiality/integrity/availability) and the governing fact internalized that security is RISK MANAGEMENT not a quest for the absolute (assume the attacker knows the system and any single layer can fail); SETUP vs AUDIT mode chosen; and when auditing software you OPERATE but did not AUTHOR, each gap split into deployment-owned (config/secrets/exposure/host — you can fix) vs product-owned (code/architecture — only upgrade, configure around, or report upstream), with the findings that SURVIVE a correctly-hardened deployment surfaced as the product's own — the high-value finding a purely adversarial pass buries among config gaps"}]},{"name":"model","checks":[{"id":"threat-model-built","description":"A threat model built — 'who would attack this, from where, and what do they want?' — using STRIDE (spoofing/tampering/repudiation/information-disclosure/DoS/elevation-of-privilege) over the data flow, with trust boundaries (where data crosses from less- to more-trusted) and the attack surface (every exposed endpoint/port/input/dependency) marked on the architecture, and threats ranked by risk; the highest-leverage cheapest security investment, and the thing an agent never does unasked because it has no attacker in its head"}]},{"name":"design","checks":[{"id":"defenses-and-trust-boundaries","description":"The threat model turned into DESIGN decisions (architectural weaknesses can't be patched in later): authentication/authorization designed with a vetted framework and authorization enforced SERVER-SIDE on every request (never by hiding a UI control); the trust boundaries enforced and defense-in-depth layered (no single control is the whole defense, each layer assumed breachable); fail-secure (errors default to DENY); attack surface minimized; and crypto/core security primitives NEVER invented — public audited algorithms/libraries only, because the attacker is assumed to know the design (no security through obscurity)"}]},{"name":"build","checks":[{"id":"input-never-trusted","description":"Code written on the assumption that NO external input is trusted — every input validated at the boundary before use — and the common vulnerability classes (OWASP Top 10) defended by construction: parameterized queries/prepared statements for injection (never concatenate input into SQL/commands), output encoding for XSS, server-side authorization checks for broken access control, CSRF tokens + SameSite cookies, TLS in transit and encryption at rest for sensitive data, and safe configuration (no default passwords / exposed debug endpoints / public buckets)"},{"id":"secrets-and-least-privilege","description":"Secrets kept out of code AND logs — injected from a secrets manager/vault, never hard-coded, and never written to telemetry (no password/PII in logs); least privilege in the wiring — every component, query, and credential granted only the access it needs, from deny-all — countering the agent's reflex to hard-code a key or widen a permission to *:* to clear an error"}]},{"name":"verify","checks":[{"id":"security-testing-gated","description":"Security testing automated into the pipeline as BLOCKING gates run every commit — SAST (static source analysis), DAST (dynamic scan of the running app), and SCA (dependency/supply-chain scanning), plus fuzzing where input handling is critical — because a vulnerability is invisible to a functional test and a green-optimizing agent never seeks it; advisory scans an agent can ignore are not gates"},{"id":"vuln-classes-defended","description":"The OWASP Top 10 walked as a verification checklist (OWASP ASVS is the standard form): for each class, the defense confirmed to EXIST and be TESTED; and the adversarial half explicitly handed to the gungnir skill — automated scanning finds known patterns but does not chain small flaws into a real exploit or abuse business logic, so penetration testing (gungnir) is required to actually prove the system; scanning is necessary, not sufficient"}]},{"name":"operate","checks":[{"id":"runtime-defense-and-patching","description":"Runtime security in place — the security slice of stationkeeping's observability: detect/alert on attacks and anomalies, log security events, keep audited least-privilege access controls; and vulnerabilities patched CONTINUOUSLY — disclosed CVEs tracked and vulnerable dependencies upgraded promptly (husbandry's don't-drift-to-EOL in security form: an unpatched known vulnerability is a standing breach) — because security is never done; new vulns are disclosed daily and every change can open a hole"},{"id":"incident-response-ready","description":"A security incident-response plan exists and is rehearsed — a known way to detect → contain → eradicate → recover → learn from a breach — run BLAMELESS like every incident in this suite so failures surface fast instead of hiding; security treated as a continuous practice with a real response capability, not a one-time pre-launch checkpoint"}]}]}};
const __PROFILE__ = {"skill":"engineering/aegis","domain":"application security","reviewSystem":"You are a senior application-security engineer reviewing this server-side Go code for SECURITY vulnerabilities. Identify the security problems and give concrete, specific fixes. Be concise."};

// ============================ app (lifted from index.html) ============================
// claude.ai mode: call the Anthropic API directly with NO key — claude.ai injects
    // authorization. (The original callClaude, inlined so the page is self-contained.)
    async function callClaudeProxy(messages, opts = {}) {
      const body = { model: opts.model || "claude-sonnet-4-6", max_tokens: opts.maxTokens ?? 1500, messages };
      if (opts.system) body.system = opts.system;
      if (opts.temperature != null) body.temperature = opts.temperature;
      const r = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST", headers: { "content-type": "application/json" }, body: JSON.stringify(body),
      });
      const d = await r.json().catch(() => ({}));
      if (!r.ok) throw new Error("Anthropic API " + r.status);
      return (d.content || []).filter((b) => b.type === "text").map((b) => b.text).join("\n");
    }

    // Retry only rate-limit / overload responses (429 / 529 / 503) with exponential backoff + jitter.
    // Other errors (402 balance, 401 auth, parse failures) are NOT retried — they won't fix themselves.
    const isRateLimit = (e) => /(^|\D)(429|529|503)(\D|$)|rate.?limit|overloaded|too many requests/i.test(String((e && e.message) || e));
    async function withRetry(fn, tries = 4, base = 800) {
      for (let i = 0; ; i++) {
        try { return await fn(); }
        catch (e) {
          if (i >= tries - 1 || !isRateLimit(e)) throw e;
          await new Promise((res) => setTimeout(res, base * 2 ** i + Math.random() * base));
        }
      }
    }

    // The two arms differ in ONE thing: whether the skill RUNS as a gated, navigated workflow, or not.
    // Both navigate the SAME code with the SAME tools and the SAME turn ceiling — the skill is the only variable.
    const ARMS = {
      base:  { label: "no skill",   blurb: "navigates the code freely with the same tools, no skill — stops when it has seen enough" },
      skill: { label: "with skill", blurb: "runs the skill as a gated workflow: ordered stages, gates, references pulled on demand" },
    };
    const ARM_ORDER = ["base", "skill"];
    const clamp = (s) => { const n = Math.round(Number(s)); return Number.isFinite(n) ? Math.max(0, Math.min(10, n)) : 0; };
    const pct = (x) => (x == null ? "—" : Math.round(x * 100) + "%");
    const ls = (k, d) => { try { return localStorage.getItem(k) ?? d; } catch (e) { return d; } };
    const save = (k, v) => { try { localStorage.setItem(k, v); } catch (e) {} };

    function App() {
      const [mode, setMode] = useState(null);           // 'local' | 'claudeai'
      const [skill] = useState(() => {
        try { return new URLSearchParams(location.search).get("skill") || "surface/wellspring"; }
        catch (e) { return "surface/wellspring"; }
      });
      const [skillStruct, setSkillStruct] = useState(null);   // {skillMd, references, checklist} for harness
      const [fixtures, setFixtures] = useState([]);
      const [profile, setProfile] = useState({});

      const [flavor, setFlavor] = useState(() => ls("skilllab.flavor", "openai"));
      const [baseUrl, setBaseUrl] = useState(() => ls("skilllab.baseUrl", "https://api.deepseek.com/v1"));
      const [model, setModel] = useState(() => ls("skilllab.model4", "deepseek-v4-pro"));
      const [apiKey, setApiKey] = useState("");
      const [claudeModel, setClaudeModel] = useState("claude-sonnet-4-6");

      const [arms, setArms] = useState({ base: true, skill: true });
      const [trials, setTrials] = useState(2);             // each trial is a multi-turn agent loop now — start low
      const [withFP, setWithFP] = useState(false);         // false-positive control DOUBLES the run (a 2nd full loop on fixed code) — off by default
      const concurrency = mode === "claudeai" ? 8 : 12;   // claude.ai rate-limits harder; local can push 12
      const [running, setRunning] = useState(false);
      const [log, setLog] = useState([]);
      const [results, setResults] = useState([]);   // [{fixture, arm, meanFound, fpRate, n, records}]
      const [err, setErr] = useState("");
      const push = (line) => setLog((l) => [...l.slice(-400), line]);

      useEffect(() => { save("skilllab.flavor", flavor); }, [flavor]);
      useEffect(() => { save("skilllab.baseUrl", baseUrl); }, [baseUrl]);
      useEffect(() => { save("skilllab.model4", model); }, [model]);

      useEffect(() => {
        setMode("claudeai");
        setSkillStruct(__SKILL_STRUCT__); setFixtures(__FIXTURES__); setProfile(__PROFILE__);
      }, []);

      const callModel = (role) => (messages, opts) => withRetry(async () => {
        if (mode === "claudeai") return callClaudeProxy(messages, { ...opts, model: claudeModel });
        const provider = { flavor, baseUrl, apiKey, model };
        const r = await fetch("/api/model", {
          method: "POST", headers: { "content-type": "application/json" },
          body: JSON.stringify({ role, messages, opts, provider }),
        });
        const j = await r.json().catch(() => ({}));
        if (!r.ok || j.error) throw new Error(j.error || ("HTTP " + r.status));
        return j.text;
      });

      const providerReady = mode === "claudeai" ? !!claudeModel
        : flavor === "openai" ? !!(baseUrl && model && apiKey) : !!(model && apiKey);
      const selected = ARM_ORDER.filter((a) => arms[a]);
      const skillReady = !arms.skill || !!(skillStruct && skillStruct.skillMd && skillStruct.checklist);
      const configReady = providerReady && selected.length >= 1 && skillReady;
      const toggleArm = (a) => setArms((s) => ({ ...s, [a]: !s[a] }));

      async function run() {
        setRunning(true); setErr(""); setResults([]); setLog([]);
        const callReview = callModel("review"), callGrade = callModel("grade");
        const domain = profile.domain || "architecture";
        const system = profile.reviewSystem;
        const units = [];
        for (const fx of fixtures) for (const arm of selected) for (let t = 1; t <= trials; t++) units.push({ fx, arm, t });
        const done = [];
        const recompute = () => {
          const groups = {};
          for (const d of done) (groups[d.fixture + "|" + d.arm] ||= []).push(d.record);
          setResults(Object.entries(groups).map(([k, recs]) => {
            const [fixture, arm] = k.split("|");
            return { fixture, arm, ...core.summarize(recs), records: recs };
          }));
        };
        try {
          await core.mapPool(units, concurrency, async (u) => {
            const tag = `[${u.fx.id}] ${u.arm} · t${u.t}`;
            try {
              // skill arm = run the skill as a gated, NAVIGATED workflow; base arm = navigate the code freely, NO skill.
              // Both get the same nav tools, same turn ceiling — the skill is the only manipulated variable.
              const runArm = (code, fp) => u.arm === "skill"
                ? H.runHarness({ callModel: callReview, skill: skillStruct, code, domain, system, skillName: skill, maxTurns: 28, maxTokens: 8000,
                    onEvent: (e) => push(`${tag}${fp} · ${e.type || e.phase || ""}${e.turn ? " t" + e.turn : ""}${e.name ? " " + e.name : ""}`) })
                : H.runNavReview({ callModel: callReview, code, domain, system, maxTurns: 28, maxTokens: 8000,
                    onEvent: (e) => push(`${tag}${fp} · ${e.type || e.phase || ""}${e.turn ? " t" + e.turn : ""}`) });
              const r = await runArm(u.fx.before, "");
              // grade quality (v2: decomposed factual y/n → code-composed score; the grader NEVER sees the diff)
              const g = await core.gradeQuality({ callGrade, code: u.fx.before, review: r.review, domain });
              // reference overlap — recorded for analysis, NOT scored (the diff's only remaining job)
              const ov = await core.gradeReferenceOverlap({ callGrade, diff: u.fx.diff, review: r.review, domain }).catch(() => ({ overlap: "—" }));
              const rec = { trial: u.t, foundScore: g.score, foundWhy: g.why, harmful: g.judgments && g.judgments.harmful === "yes", review: r.review,
                judgments: g.judgments, overlap: ov.overlap, turns: r.turns, navCalls: r.navCalls,
                gatesCleared: r.gatesCleared || [], refsOpened: (r.refsOpened || []).map((x) => x.name), complete: r.complete };
              if (withFP) {
                // false-positive control: SAME instrument on the already-fixed code → does it cry wolf?
                const rFP = await runArm(u.fx.after, " fp");
                const fpg = await core.gradeFalsePositive({ callGrade, diff: u.fx.diff, review: rFP.review, domain });
                rec.falsePositive = fpg.falsePositive; rec.fpWhy = fpg.why; rec.cleanReview = rFP.review;
              }
              done.push({ fixture: u.fx.id, arm: u.arm, record: rec });
              recompute();
            } catch (e) {
              push(`${tag} · SKIPPED — ${String(e.message || e)}`);
            }
          });
          push("done.");
        } catch (e) { setErr(String(e.message || e)); }
        setRunning(false);
      }

      // mean score for an arm across all fixtures
      const aggOf = (arm) => {
        const rows = results.filter((r) => r.arm === arm);
        if (!rows.length) return null;
        const meanFound = rows.reduce((a, r) => a + r.meanFound, 0) / rows.length;
        const fpRows = rows.filter((r) => r.fpRate != null);
        const fpRate = fpRows.length ? fpRows.reduce((a, r) => a + r.fpRate, 0) / fpRows.length : null;
        const n = rows.reduce((a, r) => a + r.n, 0);
        return { meanFound, fpRate, n };
      };
      const agg = Object.fromEntries(ARM_ORDER.map((a) => [a, aggOf(a)]));
      // headline comparison: workflow vs no-skill if both present, else whatever pair we have
      const hi = agg.skill ? "skill" : null;
      const lo = agg.base ? "base" : null;
      const delta = hi && lo && agg[hi] && agg[lo] ? agg[hi].meanFound - agg[lo].meanFound : null;
      const haveResults = ARM_ORDER.some((a) => agg[a]);
      const envLabel = mode === "local" ? "this machine" : mode === "claudeai" ? "claude.ai" : "detecting…";
      const envKey = mode === "local" ? "local" : mode === "claudeai" ? "claudeai" : "detecting";

      return (
        <div className="shell">
          {/* ── masthead ── */}
          <header className="masthead">
            <span className="wordmark"><span className="brand-dot" />touchstone</span>
            <span className="badge" data-env={envKey}>{envLabel}</span>
          </header>

          {/* ── hero / the question (the empty-screen focal: persuade with zero data) ── */}
          <section className="section hero">
            <div className="gutter-label"><div className="eyebrow">Controlled experiment</div></div>
            <div className="section-body">
              <h1 className="headline">
                Does <span className="mono">{skill.split("/").pop()}</span> change the review?
              </h1>
              <p className="lead">
                Both arms <b>navigate the same code</b> with the same tools (<span className="mono">ls / grep / read_file</span>),
                same model, same turn ceiling, same blind grader. The <b>one variable</b>: whether the skill <b>runs</b> — as a
                gated workflow with ordered stages and references pulled on demand — or not. The grader scores each review 0–10
                <b>on its own merits</b> — it never sees the skill, nor the maintainer's diff — judging the real, concrete
                problems found, not whether the review matched any answer key.
              </p>
            </div>
          </section>

          {/* ── fixtures (the credibility evidence — real before→after commits) ── */}
          {fixtures.length > 0 && (
            <section className="section">
              <div className="gutter-label">
                <div className="eyebrow">Fixtures</div>
                <div className="caption">real before→after commits ({fixtures.length})</div>
              </div>
              <div className="section-body fixtures-list">
                {fixtures.map((f) => (
                  <div className="fixture" key={f.id}>
                    <div>
                      <span className="repo">{f.repo}</span>
                      {f.pr ? <span className="caption"> · <a href={f.pr} target="_blank" rel="noreferrer">source</a></span> : null}
                    </div>
                    <div className="prose">{f.fix_summary}</div>
                    <div className="caption file mono">{f.file}</div>
                  </div>
                ))}
              </div>
            </section>
          )}

          {/* ── provider (mode-driven panel) ── */}
          <section className="section">
            <div className="gutter-label">
              <div className="eyebrow">Provider</div>
              <div className="caption">{mode === "claudeai" ? "claude.ai" : "this machine"}</div>
            </div>
            <div className="section-body">
              {mode == null && <div className="caption">detecting environment…</div>}
              {mode === "local" && (
                <>
                  <div className="field-grid">
                    <label className="field"><span className="field-label">kind</span>
                      <select className="select" value={flavor} disabled={running} onChange={(e) => setFlavor(e.target.value)}>
                        <option value="openai">OpenAI-compatible (DeepSeek / dsv4 / …)</option>
                        <option value="anthropic">Anthropic (your key)</option>
                      </select>
                    </label>
                    {flavor === "openai" && (
                      <label className="field"><span className="field-label">base URL</span>
                        <input className="input" value={baseUrl} disabled={running} placeholder="https://api.deepseek.com/v1"
                          onChange={(e) => setBaseUrl(e.target.value)} />
                      </label>
                    )}
                    <label className="field"><span className="field-label">model</span>
                      <input className="input" value={model} disabled={running} placeholder="deepseek-v4-pro"
                        onChange={(e) => setModel(e.target.value)} />
                    </label>
                    <label className="field"><span className="field-label">API key</span>
                      <input className="input" type="password" value={apiKey} disabled={running} placeholder="sk-…"
                        onChange={(e) => setApiKey(e.target.value)} />
                    </label>
                  </div>
                  <p className="caption">
                    Your key stays on this machine — sent only to your local server (<span className="mono">localhost</span>),
                    which makes the provider call. Browsers can't reach providers like dsv4 directly (CORS). Not saved to disk.
                  </p>
                </>
              )}
              {mode === "claudeai" && (
                <>
                  <div className="field-grid">
                    <label className="field"><span className="field-label">model</span>
                      <select className="select" value={claudeModel} disabled={running} onChange={(e) => setClaudeModel(e.target.value)}>
                        <option value="claude-sonnet-4-6">claude-sonnet-4-6</option>
                        <option value="claude-haiku-4-5-20251001">claude-haiku-4-5 (more headroom)</option>
                        <option value="claude-opus-4-8">claude-opus-4-8 (ceiling risk)</option>
                      </select>
                    </label>
                  </div>
                  <p className="caption">Running in claude.ai — injected credentials, no key needed.</p>
                </>
              )}
            </div>
          </section>

          {/* ── delivery arms ── */}
          <section className="section">
            <div className="gutter-label"><div className="eyebrow">Delivery modes</div><div className="caption">what to compare</div></div>
            <div className="section-body">
              {ARM_ORDER.map((a) => (
                <label className="arm-row" key={a}>
                  <span className="arm-head">
                    <input type="checkbox" checked={arms[a]} disabled={running} onChange={() => toggleArm(a)} />
                    {ARMS[a].label}
                  </span>
                  <span className="arm-blurb">{ARMS[a].blurb}</span>
                </label>
              ))}
              {arms.skill && !skillReady && (
                <div className="warn-inline">
                  the “with skill” arm needs the skill text (SKILL.md) — not available here.
                </div>
              )}
            </div>
          </section>

          {/* ── controls + cost line ── */}
          <section className="section">
            <div className="gutter-label"><div className="eyebrow">Run</div></div>
            <div className="section-body">
              <div className="controls">
                <label className="field" style={{ flex: "0 0 auto" }}><span className="field-label">trials / mode</span>
                  <input className="input" type="number" min={1} max={8} value={trials} disabled={running}
                    style={{ inlineSize: "5rem" }}
                    onChange={(e) => setTrials(Math.max(1, Math.min(8, +e.target.value || 1)))} />
                </label>
                <label className="arm-row" style={{ flex: "0 0 auto" }}>
                  <span className="arm-head">
                    <input type="checkbox" checked={withFP} disabled={running} onChange={() => setWithFP((v) => !v)} />
                    false-positive control
                  </span>
                  <span className="arm-blurb">re-runs each arm on the already-fixed code — DOUBLES the cost</span>
                </label>
                <button className="btn-run" onClick={run} disabled={running || !fixtures.length || !configReady}>
                  {running ? "Running…" : "Run experiment"}
                </button>
              </div>
              <p className="cost-line">
                {mode == null ? "detecting environment…" : mode === "local"
                  ? `${flavor}${model ? " / " + model : ""}${providerReady ? "" : "  — fill the provider above"}`
                  : `claude.ai / ${claudeModel}`}
                {"   ·   "}{fixtures.length} fixture × {selected.length} mode × {trials} = {fixtures.length * selected.length * trials} runs{withFP ? " ×2 (＋FP)" : ""}
                {"  "}· each run is a multi-turn agent loop (≤28 turns) + 2 grader calls, ≤{concurrency} at once
              </p>
            </div>
          </section>

          {/* ── error (a designed product moment, not a blank/500) ── */}
          {err && (
            <div className="error-block">
              <div>Error: {err}</div>
              <div className="retry-hint">Check the provider and press <b>Run experiment</b> to try again.</div>
            </div>
          )}

          {/* ── result skeleton (running, before first unit completes — matches loaded geometry) ── */}
          {running && !haveResults && (
            <div className="result-panel">
              <div className="eyebrow">Result</div>
              <div className="delta-row"><div className="skeleton delta-sk" /></div>
              <div className="skeleton bar-sk" /><div className="skeleton bar-sk" />
            </div>
          )}

          {/* ── result (the delta is the focal element) ── */}
          {haveResults && (
            <div className="result-panel">
              <div className="eyebrow">Result · review-quality 0–10 (graded blind on intrinsic merit)</div>
              {delta != null && (
                <div className="delta-row">
                  <div className="delta" data-sign={delta < 0 ? "neg" : "pos"}>
                    {delta >= 0 ? "+" : "−"}{Math.abs(delta).toFixed(1)}
                  </div>
                  <div className="delta-caption">
                    points <b>{ARMS[hi].label}</b> {delta < 0 ? "loses to" : "adds over"} <b>{ARMS[lo].label}</b><br />
                    <span className="mono">{agg[lo].meanFound.toFixed(1)} → {agg[hi].meanFound.toFixed(1)}</span>
                  </div>
                </div>
              )}
              {ARM_ORDER.filter((a) => agg[a]).map((a) => (
                <div className="arm-score" key={a}>
                  <div className="arm-score-head">
                    <span>{ARMS[a].label}{agg[a].fpRate != null ? <span className="caption">  · false-pos {pct(agg[a].fpRate)}</span> : null}</span>
                    <span className="mono">{agg[a].meanFound.toFixed(2)}/10 <span className="caption">(n={agg[a].n})</span></span>
                  </div>
                  <div className="bar-track"><div className="bar-fill" data-arm={a} style={{ "--fill": agg[a].meanFound / 10 }} /></div>
                </div>
              ))}
              {fixtures.length > 1 && (
                <div className="per-fixture">
                  <div className="caption">per fixture</div>
                  {fixtures.map((f) => {
                    const cells = ARM_ORDER.filter((a) => arms[a]).map((a) => {
                      const r = results.find((x) => x.fixture === f.id && x.arm === a);
                      return r ? `${ARMS[a].label} ${r.meanFound.toFixed(1)}` : null;
                    }).filter(Boolean);
                    return cells.length ? <div className="mono" key={f.id}>{f.id}: {cells.join(" · ")}</div> : null;
                  })}
                </div>
              )}
            </div>
          )}

          {/* ── why · per-trial verdicts ── */}
          {haveResults && (
            <section className="section">
              <div className="gutter-label"><div className="eyebrow">Why</div><div className="caption">grader verdicts · expand to read the review</div></div>
              <div className="section-body">
                {ARM_ORDER.filter((a) => arms[a]).flatMap((a) => results.filter((r) => r.arm === a)).map((r, ri) => (
                  <div className="why-group" key={ri}>
                    <div className="why-group-head">{r.fixture} · {ARMS[r.arm].label}</div>
                    {(r.records || []).map((rec, i) => (
                      <details className="trial" key={i}>
                        <summary>
                          <span className="mono">t{rec.trial}: <b>{rec.foundScore}/10</b></span>
                          {rec.judgments ? <span className="caption mono">{"  "}· {["grounded","real","multiple","concrete","depth","harmful"].map((f) => `${f[0]}=${rec.judgments[f] || "?"}`).join(" ")}</span> : null}
                          {typeof rec.turns === "number" ? <span className="caption mono">{"  "}· {rec.turns}t/{rec.navCalls}nav{(rec.gatesCleared && rec.gatesCleared.length) ? " · gates " + rec.gatesCleared.length : ""}{(rec.refsOpened && rec.refsOpened.length) ? " · refs " + rec.refsOpened.length : ""}</span> : null}
                          {rec.overlap ? <span className="caption">{"  "}· ref-overlap {rec.overlap}</span> : null}
                          {rec.foundWhy ? <span className="caption"> — {rec.foundWhy}</span> : ""}
                          {("falsePositive" in rec) ? <span className="caption">{` · false-pos ${rec.falsePositive ? "YES" : "no"}${rec.fpWhy ? " — " + rec.fpWhy : ""}`}</span> : ""}
                        </summary>
                        <div className="review-body user-text" dir="auto">
                          {rec.review}{rec.cleanReview ? "\n\n— — — review of the ALREADY-FIXED code — — —\n\n" + rec.cleanReview : ""}
                        </div>
                      </details>
                    ))}
                  </div>
                ))}
              </div>
            </section>
          )}

          {/* ── run log ── */}
          {(running || log.length > 0) && (
            <section className="section">
              <div className="gutter-label"><div className="eyebrow">Run log {running ? "· live" : ""}</div></div>
              <div className="section-body">
                <div className="log user-text" dir="auto">
                  {log.map((l, i) => <div key={i}>{l}</div>)}
                </div>
              </div>
            </section>
          )}

          {/* ── read-honestly footer (first-class persuasion content, not fine print) ── */}
          <div className="footer">
            <b>Read honestly:</b> one fixture is one data point and N is small — a signal, not a proof.
            The grader scores each review blind on its own merits — it sees neither the skill nor the maintainer's diff — so it
            credits real, concrete problems wherever they land, not a match to one answer key (fairer, but more subjective).
            Both arms are a faithful <i>reimplementation</i> of an agent reviewing code by navigating it with tools; the skill
            arm adds the gated workflow (ordered stages, gates, on-demand references) — not literally Claude Code. Code is not
            executed: this measures the review's advice, not whether a rewrite compiles.
          </div>
        </div>
      );
    }

export default function Touchstone() {
  return (<><style>{STYLES}</style><App /></>);
}
